// 400 CRCST certification exam questions
export const QUESTIONS: Question[] = [
  {id:'1',question:'Soiled instruments and other items are received in which area of the Sterile Processing department?',options:['Preparation','Packaging','Decontamination','Sterilization'],correct_answer:2,domain:'SPD Overview',difficulty:'easy',explanation:'Decontamination is the entry point for all soiled items in SPD — workflow always moves from soiled to clean.'},
  {id:'2',question:'The first step in the sterilization process is:',options:['Receiving','Sorting','Soaking','Cleaning'],correct_answer:3,domain:'Sterilization',difficulty:'easy',explanation:'Cleaning is always the first and most critical step — sterilization cannot succeed on soiled instruments.'},
  {id:'3',question:'To minimize exposure to bloodborne pathogens SP technicians must wear special attire referred to as:',options:['Personal protective equipment','Personal protection garments','Professional protective equipment','Personal safety attire'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'PPE is the correct term per OSHA Bloodborne Pathogen Standard.'},
  {id:'4',question:'Instrument sets needed for all scheduled procedures for an entire day are usually pulled:',options:['Two days before','Day or evening before','Morning of surgery','Early morning day of'],correct_answer:1,domain:'Assembly',difficulty:'easy',explanation:'Case carts are typically pulled the day or evening before to allow time for verification and assembly.'},
  {id:'5',question:'Healthcare-associated infections (HAIs) are:',options:['Most likely to occur during a surgical procedure','Caused by drug-resistant organisms','Infections without known cures','Infections that occur on or after day three of a hospitalization'],correct_answer:3,domain:'Infection Prevention',difficulty:'medium',explanation:'HAIs are defined as infections occurring on or after the third day of a hospital stay.'},
  {id:'6',question:'SP workflow should move from:',options:['Clean to soiled','Unrestricted to semi-restricted','Soiled to clean','Clean to sterile'],correct_answer:2,domain:'SPD Overview',difficulty:'easy',explanation:'SPD workflow always moves from soiled to clean to prevent cross-contamination.'},
  {id:'7',question:'While items may be dispensed to all areas of a facility the major focus of the SPD is:',options:['The Emergency Department','Labor and Delivery','Supply Chain Management','The Operating Room'],correct_answer:3,domain:'SPD Overview',difficulty:'easy',explanation:'The OR is the primary customer of SPD — most instruments processed are for surgical procedures.'},
  {id:'8',question:'Working in the decontamination area requires:',options:['Knowledge of microbiology','Knowledge of cleaning and disinfecting processes','Instrument identification','All the above'],correct_answer:3,domain:'Decontamination',difficulty:'easy',explanation:'All three are required competencies for decontamination area technicians.'},
  {id:'9',question:'The suffix -itis means:',options:['Illness','Inflammation','The study of','Pain'],correct_answer:1,domain:'Medical Terminology',difficulty:'easy',explanation:'The suffix -itis means inflammation — e.g. appendicitis, arthritis.'},
  {id:'10',question:'The suffix -ectomy means:',options:['To repair','Surgical removal','Inflammation','To cut'],correct_answer:1,domain:'Medical Terminology',difficulty:'easy',explanation:'The suffix -ectomy means surgical removal — e.g. appendectomy, tonsillectomy.'},
  {id:'11',question:'The suffix -oscopy means:',options:['Visual examination','Disease','Surgical removal','Diagnosis of a condition'],correct_answer:0,domain:'Medical Terminology',difficulty:'easy',explanation:'The suffix -oscopy means visual examination — e.g. arthroscopy, laparoscopy.'},
  {id:'12',question:'The prefix hypo- means:',options:['Quickly','Above','Below','Measured'],correct_answer:2,domain:'Medical Terminology',difficulty:'easy',explanation:'Hypo- means below or under — e.g. hypoglycemia, hypotension.'},
  {id:'13',question:'Which of the following means beside or near?',options:['Para','Peri','Parta','Pana'],correct_answer:1,domain:'Medical Terminology',difficulty:'easy',explanation:'The prefix peri- means beside or near — e.g. perioperative, periosteal.'},
  {id:'14',question:'The suffix -tome means:',options:['Surgical restoration','Surgical fixation','To suture','Cutting instrument'],correct_answer:3,domain:'Medical Terminology',difficulty:'easy',explanation:'The suffix -tome means cutting instrument — e.g. osteotome, dermatome.'},
  {id:'15',question:'Arthroscopy means:',options:['Visual examination of a joint','Surgical replacement of a joint','Inflammation of a joint','Surgical removal of a joint'],correct_answer:0,domain:'Medical Terminology',difficulty:'easy',explanation:'Arthro = joint, -oscopy = visual examination.'},
  {id:'16',question:'The word laminectomy means:',options:['Removal of a cyst in the spine','Removal of part of the vertebrae in the spine','To insert rods into the spine','The study of the spine'],correct_answer:1,domain:'Medical Terminology',difficulty:'medium',explanation:'Lamin = lamina (part of vertebra), -ectomy = removal.'},
  {id:'17',question:'Which surgical abbreviation might be used relating to a fractured bone?',options:['CABG','BSO','ORIF','TAH'],correct_answer:2,domain:'Medical Terminology',difficulty:'medium',explanation:'ORIF = Open Reduction Internal Fixation — surgical repair of a fracture.'},
  {id:'18',question:'Lithotripsy means:',options:['Aspiration of fatty tissue','Surgical removal of ovary','Crushing of a stone','Visual examination of joint'],correct_answer:2,domain:'Medical Terminology',difficulty:'medium',explanation:'Litho = stone, -tripsy = crushing — used to break up kidney stones.'},
  {id:'19',question:'The system that gives the body shape and support is the:',options:['Muscular system','Nervous system','Skeletal system','Circulatory system'],correct_answer:2,domain:'Anatomy',difficulty:'easy',explanation:'The skeletal system provides the structural framework and support for the body.'},
  {id:'20',question:'The tissue that acts as a cushion between bones is:',options:['Tendon','Muscle','Cartilage','Ligament'],correct_answer:2,domain:'Anatomy',difficulty:'easy',explanation:'Cartilage acts as a cushion between bones preventing direct bone-on-bone contact.'},
  {id:'21',question:'The largest part of the human brain is the:',options:['Brain stem','Cerebellum','Cerebrum','Pituitary gland'],correct_answer:2,domain:'Anatomy',difficulty:'easy',explanation:'The cerebrum is the largest part of the brain controlling thought, memory, and voluntary movement.'},
  {id:'22',question:'This yellowish liquid makes up more than 55% of blood:',options:['Platelets','Red blood cells','White blood cells','Plasma'],correct_answer:3,domain:'Anatomy',difficulty:'easy',explanation:'Plasma is the liquid component of blood making up over 55% of blood volume.'},
  {id:'23',question:'The hip joint is an example of a:',options:['Gliding joint','Ball-and-socket joint','Pivot joint','Hinge joint'],correct_answer:1,domain:'Anatomy',difficulty:'easy',explanation:'The hip joint is a ball-and-socket joint allowing movement in multiple directions.'},
  {id:'24',question:'This tissue covers the body\'s external surface:',options:['Epithelial tissue','Connective tissue','Muscular tissue','Nervous tissue'],correct_answer:0,domain:'Anatomy',difficulty:'easy',explanation:'Epithelial tissue covers the body\'s external surface and lines internal organs and cavities.'},
  {id:'25',question:'Cartilage is replaced by bone through a process called:',options:['Ossification','Calcification','Osmosis','Cancellous formation'],correct_answer:0,domain:'Anatomy',difficulty:'medium',explanation:'Ossification is the process by which cartilage is replaced by bone during development.'},
  {id:'26',question:'Anaerobic bacteria are able to survive without:',options:['Oxygen','Warm soil','Temperatures above 100 degrees F','Water'],correct_answer:0,domain:'Microbiology',difficulty:'easy',explanation:'Anaerobic bacteria do not require oxygen to survive — they can grow in oxygen-free environments.'},
  {id:'27',question:'A spore is:',options:['The control unit of a cell','Located in the cell nucleus','Very difficult to kill','Very easy to kill'],correct_answer:2,domain:'Microbiology',difficulty:'medium',explanation:'Spores form a thick protective wall making them extremely resistant to heat, chemicals, and desiccation.'},
  {id:'28',question:'Staphylococcus is classified as a:',options:['Gram-positive bacteria','Gram-negative bacteria','Prion','Virus'],correct_answer:0,domain:'Microbiology',difficulty:'medium',explanation:'Staphylococcus is a gram-positive bacterium — it retains the crystal violet stain in gram staining.'},
  {id:'29',question:'Microorganisms that cause disease are called:',options:['Gram positive','Gram negative','Pathogens','Potentially infectious'],correct_answer:2,domain:'Microbiology',difficulty:'easy',explanation:'Pathogens are microorganisms capable of causing disease in a host.'},
  {id:'30',question:'The virus that causes hepatitis B is transmitted by:',options:['Contact','Blood','Airborne and droplet routes','Vectors'],correct_answer:1,domain:'Infection Prevention',difficulty:'medium',explanation:'Hepatitis B is transmitted through blood and blood-contaminated body fluids.'},
  {id:'31',question:'Jewelry should not be worn in SP work areas because it:',options:['Harbors microorganisms','Is expensive','May become damaged','May be misplaced or stolen'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'Jewelry harbors microorganisms that cannot be effectively removed and poses an infection control risk.'},
  {id:'32',question:'During handwashing hands should be lathered and scrubbed for at least:',options:['10 seconds','20 seconds','1 minute','2 minutes'],correct_answer:1,domain:'Safety',difficulty:'easy',explanation:'CDC recommends lathering and scrubbing hands for at least 20 seconds.'},
  {id:'33',question:'To protect themselves from splashes SP technicians assigned to decontamination should wear:',options:['Double-cloth gowns','Blue surgical scrubs','Fluid-resistant gowns','Sterile OR gowns'],correct_answer:2,domain:'Safety',difficulty:'easy',explanation:'Fluid-resistant gowns protect against splashes and spills in the decontamination area.'},
  {id:'34',question:'The main theory of Standard Precautions is that patients:',options:['In high-risk categories may be infectious','Diagnosed with a specific disease may be infectious','Are generally healthy unless they show symptoms','Must all be treated as if their blood and bodily fluids are infectious'],correct_answer:3,domain:'Infection Prevention',difficulty:'easy',explanation:'Standard Precautions require treating all patients as potentially infectious regardless of diagnosis.'},
  {id:'35',question:'The color of biohazard containers labels and signs should be:',options:['Red/orange','Orange/yellow','Orange/blue','Green/black'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'Biohazard containers, labels, and signs must be red or orange-red per OSHA requirements.'},
  {id:'36',question:'The decontamination area of the SPD should have:',options:['Negative airflow','Positive airflow','Filtered airflow','No air exchanges'],correct_answer:0,domain:'Safety',difficulty:'medium',explanation:'Negative airflow in decontamination contains contaminants and prevents them from escaping to clean areas.'},
  {id:'37',question:'The absence of microorganisms that cause disease is called:',options:['Infection prevention','Infection control','Asepsis','HAI control'],correct_answer:2,domain:'Infection Prevention',difficulty:'easy',explanation:'Asepsis is the absence of pathogenic microorganisms — the goal of sterile processing.'},
  {id:'38',question:'Chemical indicators are classified as:',options:['FDA Class I medical devices','FDA Class II medical devices','FDA Class III medical devices','Not regulated by the FDA'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'hard',explanation:'Chemical indicators are classified as FDA Class II medical devices subject to premarket notification.'},
  {id:'39',question:'Standards and regulations help set the SPD\'s levels of:',options:['Quality','Safety','Efficiency','Both quality and safety'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'easy',explanation:'Standards and regulations establish both quality and safety levels for SPD operations.'},
  {id:'40',question:'Medical device reporting is regulated by the:',options:['NFPA','EPA','WHO','FDA'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The FDA regulates medical device reporting through the MedWatch program and MDR regulations.'},
  {id:'41',question:'Formal training should occur:',options:['For new employees','At least monthly','For employees moving to a new position','For new employees and those moving to new positions'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'easy',explanation:'Formal training is required both for new hires and for any employee transitioning to a new role.'},
  {id:'42',question:'Monitoring records must be:',options:['Accurate','Legible','Complete','All the above'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'easy',explanation:'Monitoring records must be accurate, legible, and complete to be valid for regulatory purposes.'},
  {id:'43',question:'Sterilizer load records should contain:',options:['Items and quantities sterilized','Types of packaging used in each load','Preventive maintenance dates','All the above'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'Sterilizer load records must document items sterilized, packaging types, and PM dates for full traceability.'},
  {id:'44',question:'External indicators show the item was exposed to a sterilization process but do NOT prove sterility was achieved:',options:['True','False','Only for steam processes','Only for EO processes'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'External CIs show the item was exposed to sterilization conditions — they do not prove sterility was achieved.'},
  {id:'45',question:'Temperature and humidity levels in the SPD need to be monitored and recorded:',options:['Weekly preferably daily','For each shift','At least daily','At least monthly'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Temperature and humidity in the SPD must be monitored and recorded at least daily per AAMI standards.'},
  {id:'46',question:'A Class II chemical indicator cleared by the FDA and run daily in dynamic air removal sterilizers is called a/an:',options:['Process challenge device','External CI','Biological indicator','Bowie-Dick test'],correct_answer:3,domain:'Sterilization',difficulty:'hard',explanation:'The Bowie-Dick test is a Class II chemical indicator run daily in dynamic air removal sterilizers to check air removal.'},
  {id:'47',question:'A positive biological indicator (BI) means:',options:['The incubation process is complete','There is no growth in the ampule after incubation','There is growth in the ampule after incubation','None of the above'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'A positive BI shows growth in the ampule after incubation — meaning sterilization failed.'},
  {id:'48',question:'Failure mode and effects analysis (FMEA) tries to predict:',options:['The amount of wasted effort in a day','The cause of a sentinel event','A product failure before it occurs','All the above'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'hard',explanation:'FMEA is a proactive tool that identifies potential failures before they occur.'},
  {id:'49',question:'Root cause analysis (RCA):',options:['Is proactive','Is a method of identifying problems before they occur','Focuses on properly educating staff about quality measures','Looks at a poor outcome to prevent its reoccurrence'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'RCA is reactive — it examines a poor outcome after it occurs to identify root causes and prevent recurrence.'},
  {id:'50',question:'This component of a quality program moves decision making to frontline staff:',options:['Quality monitoring','Empowerment','Process management','All the above'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Empowerment is the quality program component that moves decision making authority to frontline staff.'},
  {id:'51',question:'Which system provides supplies and instruments for individual surgical procedures?',options:['Exchange cart','PAR','Case cart','Requisition'],correct_answer:2,domain:'Inventory & Distribution',difficulty:'easy',explanation:'The case cart system provides all supplies and instruments needed for individual surgical procedures.'},
  {id:'52',question:'The inventory system that stocks supplies by pre-established stock levels is called a/an:',options:['PAR system','Case cart system','Fulfillment system','Exchange system'],correct_answer:0,domain:'Inventory & Distribution',difficulty:'medium',explanation:'The PAR (Periodic Automatic Replenishment) system maintains stock at pre-established levels.'},
  {id:'53',question:'The inventory system that uses two identical carts to facilitate supply replenishment is called the:',options:['Case cart system','Exchange cart system','PAR system','Requisition system'],correct_answer:1,domain:'Inventory & Distribution',difficulty:'medium',explanation:'The exchange cart system uses two identical carts — one in use while the other is being restocked.'},
  {id:'54',question:'All patient care equipment that was dispensed for use must be considered:',options:['Sterile','Clean','Contaminated','Visibly soiled'],correct_answer:2,domain:'Equipment',difficulty:'easy',explanation:'All patient care equipment returned after use must be considered contaminated regardless of appearance.'},
  {id:'55',question:'Preventive maintenance (PM) is:',options:['Performed when a piece of equipment injures a patient','Designed to identify potential problems before they occur','Performed when a user unit notices a problem','Completed by SP before equipment is dispensed'],correct_answer:1,domain:'Equipment',difficulty:'easy',explanation:'Preventive maintenance is designed to identify and address potential problems before they occur.'},
  {id:'56',question:'Which tracking method provides real-time information?',options:['RFID tags','Laser-etched barcodes','Standard barcodes','Dot matrix applications'],correct_answer:0,domain:'Information Technology',difficulty:'medium',explanation:'RFID tags provide real-time location and status information automatically.'},
  {id:'57',question:'Safety data sheets (SDSs) are provided by:',options:['OSHA','FDA','The Risk Management department','The product manufacturer'],correct_answer:3,domain:'Safety',difficulty:'easy',explanation:'Safety Data Sheets are provided by the product manufacturer.'},
  {id:'58',question:'The process of changing work or working conditions to reduce physical stress is called:',options:['Ergonomics','An employee injury reduction plan','OSHA\'s Workers\' Rights Program','OSHA\'s Risk Management Program'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'Ergonomics is the science of changing work or working conditions to reduce physical stress.'},
  {id:'59',question:'Time-weighted average (TWA) is:',options:['A test to reduce ergonomic stress','Measure of hazardous chemicals in a department','The amount of a substance a person can be exposed to over an eight-hour period','Measure of smoke remaining after a fire'],correct_answer:2,domain:'Safety',difficulty:'hard',explanation:'TWA is the amount of a hazardous substance a person can be exposed to averaged over an 8-hour work period.'},
  {id:'60',question:'Which of the following is required for sharps safety?',options:['Disposing all single-use sharps in an appropriate container','Pointing sharp ends away from any part of one\'s body during transport','Not blindly reaching into an instrument tray','All the above'],correct_answer:3,domain:'Safety',difficulty:'easy',explanation:'All three are required sharps safety practices to prevent needlestick and sharps injuries.'},
  {id:'61',question:'Which of the following is the most important factor for effective teamwork?',options:['Attitude','Promptness','Loyalty','Cooperation'],correct_answer:3,domain:'Professional Development',difficulty:'medium',explanation:'Cooperation is the most important factor for effective teamwork.'},
  {id:'62',question:'A group of employees from different departments that works together to resolve operating problems is called a:',options:['Decision-making team','Multi-dimensional team','Cross-functional team','Management team'],correct_answer:2,domain:'Professional Development',difficulty:'easy',explanation:'A cross-functional team consists of employees from different departments working together.'},
  {id:'63',question:'Coaching is an example of:',options:['Informal communication','Discipline','Formal communication','Mentoring'],correct_answer:3,domain:'Professional Development',difficulty:'medium',explanation:'Coaching is a form of mentoring — providing guidance and support to help someone develop professionally.'},
  {id:'64',question:'Personal development:',options:['Improves employability','Expands personal potential','Is a lifelong process','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'Personal development improves employability, expands potential, and is a continuous lifelong process.'},
  {id:'65',question:'Steps toward attaining professional goals in SP include:',options:['Obtaining certification','Attending educational conferences','Participating in professional groups','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'All three are important steps — certification, conferences, and professional group participation.'},
  {id:'66',question:'This agency may intervene in a matter of worker protection even if there are no specific regulations covering the situation:',options:['OSHA','EPA','FDA','AORN'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'medium',explanation:'OSHA has broad authority to intervene in worker protection matters even without specific regulations.'},
  {id:'67',question:'This agency imposes very strict labeling requirements on manufacturers of disinfectants used by SPDs:',options:['OSHA','FDA','EPA','AAMI'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'hard',explanation:'The EPA imposes strict labeling requirements on disinfectants and sterilants used in healthcare.'},
  {id:'68',question:'Heart valves and pacemakers are examples of:',options:['FDA Class I medical devices','FDA Class II medical devices','FDA Class III medical devices','None of the above'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'hard',explanation:'High-risk implantable devices like heart valves and pacemakers are FDA Class III.'},
  {id:'69',question:'Under current regulations who is required to report suspected medical device-related deaths to the FDA?',options:['Device manufacturers','Healthcare facilities','Both of the above','None of the above'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'hard',explanation:'Both device manufacturers and healthcare facilities are required to report suspected device-related deaths.'},
  {id:'70',question:'The only way to interrupt the transmission of a causative agent is to:',options:['Sterilize the item','Wear appropriate PPE','Eliminate it','Involve OSHA'],correct_answer:2,domain:'Infection Prevention',difficulty:'medium',explanation:'Eliminating the causative agent is the only definitive way to interrupt disease transmission.'},
  {id:'71',question:'Departmental dress codes apply to:',options:['Everyone entering the SPD','Only hospital employees','Only people spending more than 10 minutes','Only visitors and maintenance personnel'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'Dress codes apply to everyone entering the SPD including visitors, vendors, and maintenance personnel.'},
  {id:'72',question:'Inanimate objects that can transmit bacteria are called:',options:['Transmission devices','Fomites','Carriers','Superspreaders'],correct_answer:1,domain:'Microbiology',difficulty:'medium',explanation:'Fomites are inanimate objects that can harbor and transmit microorganisms.'},
  {id:'73',question:'Floors in the SPD should be:',options:['Wet mopped daily','Wet mopped weekly','Swept daily and wet mopped weekly','Swept daily'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'SPD floors should be wet mopped daily — sweeping and dust mopping spread microorganisms.'},
  {id:'74',question:'Know what is dirty know what is clean know what is sterile — these are known as the:',options:['Principles of asepsis','Basics of the Bloodborne Pathogen Standard','Principles of infection prevention and control','Basics of environmental control'],correct_answer:2,domain:'Infection Prevention',difficulty:'medium',explanation:'These are the principles of infection prevention and control that guide SPD workflow.'},
  {id:'75',question:'Which traffic control requirement applies to the clean assembly area of the SPD?',options:['Biohazard','Unrestricted','Semi-restricted','Restricted'],correct_answer:2,domain:'SPD Overview',difficulty:'medium',explanation:'The clean assembly area is semi-restricted — limited access with appropriate dress code required.'},
  {id:'76',question:'Temperature and humidity parameters can best be established by reviewing which document?',options:['ANSI/AAMI ST79','OSHA 29 CFR 1910.1030','ANSI/ASHRAE/ASHE 170','ANSI/AAMI ST91'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'hard',explanation:'ANSI/ASHRAE/ASHE 170 establishes ventilation and environmental requirements for healthcare facilities.'},
  {id:'77',question:'Viruses are:',options:['Larger than bacteria','Smaller than bacteria','Gram-positive microorganisms','Gram-negative microorganisms'],correct_answer:1,domain:'Microbiology',difficulty:'easy',explanation:'Viruses are much smaller than bacteria and cannot replicate outside a living host cell.'},
  {id:'78',question:'Microorganisms reproduce by a process called:',options:['Repopulation','Binary fission','Replication','Bilateral reproduction'],correct_answer:1,domain:'Microbiology',difficulty:'easy',explanation:'Binary fission is the primary reproductive process — one cell splits into two identical daughter cells.'},
  {id:'79',question:'Which hepatitis virus is said to be the most prevalent chronic bloodborne infection today?',options:['Hepatitis A','Hepatitis B','Hepatitis C','Hepatitis D'],correct_answer:2,domain:'Infection Prevention',difficulty:'hard',explanation:'Hepatitis C is the most common chronic bloodborne infection in the United States.'},
  {id:'80',question:'Which is an example of a fungus?',options:['Pneumonia','Tuberculosis','Athlete\'s foot','Herpes simplex'],correct_answer:2,domain:'Microbiology',difficulty:'medium',explanation:'Athlete\'s foot is caused by a fungus. Pneumonia and TB are bacterial, herpes is viral.'},
  {id:'81',question:'The term septorhinoplasty means:',options:['Surgery of a muscle wound','Surgical repair of the nose','Removal of a cyst','Incision into the stomach'],correct_answer:1,domain:'Medical Terminology',difficulty:'medium',explanation:'Septo = septum, rhino = nose, -plasty = surgical repair.'},
  {id:'82',question:'Encephalopathy is a/an:',options:['Disease of the brain','Inflammation of the liver','Fluid-filled sack','Inflammation of a joint'],correct_answer:0,domain:'Medical Terminology',difficulty:'medium',explanation:'Encephalo = brain, -pathy = disease.'},
  {id:'83',question:'This organ filters the blood to remove amino acids and neutralize some harmful toxins:',options:['Kidney','Pancreas','Liver','Gallbladder'],correct_answer:2,domain:'Anatomy',difficulty:'medium',explanation:'The liver filters blood to remove amino acids and neutralize harmful toxins.'},
  {id:'84',question:'This surgical procedure removes the uterus:',options:['Hysteroscopy','Hysterectomy','Dilation and curettage','Bilateral salpingo-oophorectomy'],correct_answer:1,domain:'Medical Terminology',difficulty:'easy',explanation:'Hysterectomy = surgical removal of the uterus. Hyster = uterus, -ectomy = removal.'},
  {id:'85',question:'This gland stimulates body growth:',options:['Adrenal','Thyroid','Pancreas','Pituitary'],correct_answer:3,domain:'Anatomy',difficulty:'medium',explanation:'The pituitary gland stimulates body growth and controls other endocrine glands.'},
  {id:'86',question:'This surgical procedure removes tissue or displaced bone from the wrist to release pressure on the median nerve:',options:['Carpal tunnel repair','Ulnar nerve transposition','Arthrotomy','Fasciotomy'],correct_answer:0,domain:'Medical Terminology',difficulty:'medium',explanation:'Carpal tunnel release removes tissue or bone pressing on the median nerve in the wrist.'},
  {id:'87',question:'The end of a body part closest to the point of origin is called the:',options:['Lateral','Distal','Proximal','Medial'],correct_answer:2,domain:'Anatomy',difficulty:'medium',explanation:'Proximal means closest to the point of origin or the operator — distal is farthest away.'},
  {id:'88',question:'The throat is also called the:',options:['Esophagus','Larynx','Trachea','Pharynx'],correct_answer:3,domain:'Anatomy',difficulty:'easy',explanation:'The pharynx is the throat — it connects the nasal cavity and mouth to the larynx and esophagus.'},
  {id:'89',question:'This surgical procedure removes the gallbladder:',options:['Cholecystectomy','Colectomy','Parotidectomy','Gastrectomy'],correct_answer:0,domain:'Medical Terminology',difficulty:'easy',explanation:'Cholecystectomy = surgical removal of the gallbladder. Chole = bile/gallbladder, -ectomy = removal.'},
  {id:'90',question:'The white portion of the eye is called the:',options:['Retina','Iris','Pupil','Sclera'],correct_answer:3,domain:'Anatomy',difficulty:'easy',explanation:'The sclera is the white outer layer of the eye providing structure and protection.'},
  {id:'91',question:'Which of the following is the brain center of a cell?',options:['Cell membrane','Cytoplasm','Nucleus','Deoxyribonucleic acid'],correct_answer:2,domain:'Microbiology',difficulty:'easy',explanation:'The nucleus is the control center of the cell governing activity and heredity.'},
  {id:'92',question:'This is referred to as the voice box:',options:['Pharynx','Larynx','Mouth','Trachea'],correct_answer:1,domain:'Anatomy',difficulty:'easy',explanation:'The larynx is the voice box containing the vocal cords.'},
  {id:'93',question:'Which percentage of bacteria is not harmful to humans?',options:['75%','80%','90%','95%'],correct_answer:2,domain:'Microbiology',difficulty:'medium',explanation:'Approximately 90% of bacteria are not harmful — only a small percentage are pathogenic.'},
  {id:'94',question:'The measure of alkalinity or acidity refers to:',options:['Temperature','pH','Moisture','Humidity'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'pH measures the acidity or alkalinity of a solution on a scale of 0-14.'},
  {id:'95',question:'Which of the following is not a gram-positive bacteria?',options:['Geobacillus','Escherichia coli','Klebsiella','Pseudomonas'],correct_answer:1,domain:'Microbiology',difficulty:'hard',explanation:'Escherichia coli is gram-negative. Geobacillus is gram-positive.'},
  {id:'96',question:'Which is not a common bacterial shape?',options:['Spherical','Cylindrical','Rod','Spiral'],correct_answer:1,domain:'Microbiology',difficulty:'medium',explanation:'Cylindrical is not a standard bacterial shape. The three shapes are spherical, rod, and spiral.'},
  {id:'97',question:'The functional center of a cell is the:',options:['Cytoplasm','Nucleus','Cell membrane','Capsule'],correct_answer:1,domain:'Microbiology',difficulty:'easy',explanation:'The nucleus is the functional center governing cell activity and containing genetic material.'},
  {id:'98',question:'Quality control indicators:',options:['Include RCA and FMEA','Are used to determine how well the department is meeting its objectives','Should be monitored periodically','All the above'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Quality control indicators include all of these functions.'},
  {id:'99',question:'When quality is not emphasized:',options:['FMEA and RCA will not work','A cross-functional team should be created','Conflicts can arise','All the above'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'All three consequences occur when quality is not emphasized.'},
  {id:'100',question:'The movement of supplies throughout the healthcare facility is called:',options:['Distribution','Inventory management','Case cart system','Procurement'],correct_answer:0,domain:'Inventory & Distribution',difficulty:'easy',explanation:'Distribution is the process of moving supplies and instruments throughout the healthcare facility.'},
  {id:'101',question:'Automated supply replenishment systems are:',options:['No longer used','Used only in surgery','Difficult to manage','Computerized'],correct_answer:3,domain:'Inventory & Distribution',difficulty:'easy',explanation:'Automated supply replenishment systems are computerized and track usage to automatically reorder supplies.'},
  {id:'102',question:'Items like disposable wraps are called:',options:['Consumable supplies','Capital supplies','Patient care supplies','Non-refundable supplies'],correct_answer:0,domain:'Inventory & Distribution',difficulty:'easy',explanation:'Consumable supplies are items that are used once and discarded.'},
  {id:'103',question:'Capital equipment items are:',options:['Usually used for patient care','Items with a lower purchase price','Items with a higher purchase price','Purchased stored consumed and reordered'],correct_answer:2,domain:'Inventory & Distribution',difficulty:'easy',explanation:'Capital equipment items have a higher purchase price and are durable.'},
  {id:'104',question:'The wave/do not reuse symbol on a device means:',options:['Product lot number','Use by date','Single-use item do not reuse','Date of manufacture'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The wave symbol indicates the item is a single-use device and must not be reprocessed.'},
  {id:'105',question:'The hourglass symbol on a device means:',options:['Product lot number','Use by date','Single-use item do not reuse','Date of manufacture'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The hourglass symbol indicates the use by date — the expiration date of the item.'},
  {id:'106',question:'Technicians in this department perform safety inspections and functional tests on equipment:',options:['Supply Chain Management','Infection Prevention and Control','Biomedical/Clinical Engineering','Facilities Maintenance'],correct_answer:2,domain:'Equipment',difficulty:'easy',explanation:'Biomedical/Clinical Engineering technicians perform safety inspections and functional testing on patient care equipment.'},
  {id:'107',question:'When patient equipment enters a healthcare facility it must be safety checked by a/an before it is cleared for patient use:',options:['Biomedical technician','Infection Prevention committee member','SP technician','SP director'],correct_answer:0,domain:'Equipment',difficulty:'easy',explanation:'A biomedical technician must safety check all patient equipment before it is cleared for patient use.'},
  {id:'108',question:'Which requires that preventive maintenance standards be established for medical equipment?',options:['OSHA','The Joint Commission','AAMI','NIOSH'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The Joint Commission requires that preventive maintenance standards be established and followed.'},
  {id:'109',question:'Which of the following is not a consideration when recording patient care equipment?',options:['Equipment location','PM history','Patient diagnosis','Repair history'],correct_answer:2,domain:'Equipment',difficulty:'medium',explanation:'Patient diagnosis is not a consideration when recording and maintaining patient care equipment records.'},
  {id:'110',question:'Disposable components such as pads and tubing on patient care equipment should be:',options:['Discarded at the point of use','Reprocessed for reuse','Discarded during PM','Removed in the Biomedical Engineering department'],correct_answer:0,domain:'Equipment',difficulty:'easy',explanation:'Disposable components must be discarded at the point of use — they cannot be reused.'},
  {id:'111',question:'Equipment should be inspected for obvious hazards such as cracked or frayed electrical cords:',options:['Only by trained Biomedical Engineering technicians','Only during PM activities','Only when there are complaints from user departments','Whenever the equipment is inspected in SP'],correct_answer:3,domain:'Equipment',difficulty:'medium',explanation:'Any SP staff member who inspects equipment should check for obvious hazards at that time.'},
  {id:'112',question:'If an equipment malfunction causes patient harm it should be:',options:['Discarded immediately','Sent to the manufacturer for repairs','Sequestered for inspection by OSHA personnel','Returned immediately to the Biomedical Engineering department'],correct_answer:3,domain:'Equipment',difficulty:'medium',explanation:'Equipment causing patient harm must be sequestered and returned immediately to Biomedical Engineering.'},
  {id:'113',question:'Patient care equipment should be stored in a condition that is:',options:['Ready to dispense','Ready to clean','Ready to inspect','Ready to sterilize'],correct_answer:0,domain:'Equipment',difficulty:'easy',explanation:'Patient care equipment should be stored in a ready-to-dispense condition.'},
  {id:'114',question:'When transporting soiled medical equipment:',options:['Use an open case cart','Choose a route that minimizes contact with patients','Using PPE including gloves is optional','Perform hand hygiene only when hands are soiled'],correct_answer:1,domain:'Safety',difficulty:'easy',explanation:'Choose a transport route that minimizes contact with patients and visitors.'},
  {id:'115',question:'Which statement is correct regarding patient care equipment tracking?',options:['Patient care equipment tracking requires a computer','Equipment should only be tracked if it has a value exceeding facility specifications','Tracking patient care equipment can prevent equipment shortages','Equipment must only be tracked if its usage will be charged to patients'],correct_answer:2,domain:'Equipment',difficulty:'medium',explanation:'Tracking patient care equipment prevents shortages by knowing where equipment is located at all times.'},
  {id:'116',question:'The decision to use reusable or disposable instruments in procedure trays is determined by:',options:['Where the instruments will be used','The Infection Prevention and Control department','Several factors including physician preference storage and cost','The number of items to be used and the delivery schedule'],correct_answer:2,domain:'Equipment',difficulty:'medium',explanation:'The decision involves multiple factors — physician preference, storage considerations, and cost analysis.'},
  {id:'117',question:'In addition to financial and operational management information technology systems are used to:',options:['Support patient safety','Track changes in standards','Track patient movement','All the above'],correct_answer:3,domain:'Information Technology',difficulty:'easy',explanation:'IT systems support patient safety, track standards changes, and track patient movement.'},
  {id:'118',question:'Information technology is used to:',options:['Track clinical information','Demonstrate quality of care','Provide decision support systems','All the above'],correct_answer:3,domain:'Information Technology',difficulty:'easy',explanation:'IT is used for clinical tracking, quality demonstration, and decision support.'},
  {id:'119',question:'Which of the following is not a result of computer integration?',options:['Elimination of redundant entry of information','Increased efficiency','Automatic critical updates to industry standards','Reduction of inaccurate and conflicting information'],correct_answer:2,domain:'Information Technology',difficulty:'medium',explanation:'Computer integration does not automatically update industry standards — standards require manual review.'},
  {id:'120',question:'Patient census information used in SP is obtained from the:',options:['Electronic medical record','Admissions and registration system','Financial system','Centralized patient order entry system'],correct_answer:1,domain:'Information Technology',difficulty:'medium',explanation:'Patient census information used in SP is obtained from the admissions and registration system.'},
  {id:'121',question:'Tracking individual instruments is important:',options:['To locate missing instruments','To locate the current location of instrument sets','For keeping instruments in a specific set','All the above'],correct_answer:3,domain:'Information Technology',difficulty:'easy',explanation:'All three are important reasons for tracking individual instruments.'},
  {id:'122',question:'Point-of-use computing:',options:['Is impossible in SP because of infection control requirements','Provides no benefit to the SPD','Moves computers into SP work areas','Eliminates data entry jobs'],correct_answer:2,domain:'Information Technology',difficulty:'medium',explanation:'Point-of-use computing moves computer terminals into SP work areas allowing real-time data entry.'},
  {id:'123',question:'Which of the following is not provided by an instrument tracking system?',options:['Productivity information','Financial data','Quality assurance data','Product updates and recall information'],correct_answer:1,domain:'Information Technology',difficulty:'medium',explanation:'Instrument tracking systems do not provide financial data.'},
  {id:'124',question:'Physical safety hazards may be caused by:',options:['Solutions used in the decontamination area','The environment','Splashing chemicals','Infectious waste'],correct_answer:3,domain:'Safety',difficulty:'medium',explanation:'Infectious waste is the primary physical safety hazard category encompassing all listed sources.'},
  {id:'125',question:'Which of the following is not a component of risk management?',options:['Injury prevention','Claims management','Staff management','Risk assessment'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Staff management is an HR function — the components of risk management are injury prevention, claims management, and risk assessment.'},
  {id:'126',question:'Which is not one of the three general occupational hazards found in the SPD?',options:['Physical hazards','Ergonomic hazards','Biological hazards','Chemical hazards'],correct_answer:2,domain:'Safety',difficulty:'hard',explanation:'The three general occupational hazards in SPD are physical, ergonomic, and chemical.'},
  {id:'127',question:'Information about chemical or hazardous substances must be available to:',options:['The SP departmental supervisor','Employees working in the decontamination area','Staff assigned to low-temperature sterilization','All staff'],correct_answer:3,domain:'Safety',difficulty:'easy',explanation:'Information about chemical and hazardous substances must be available to all staff.'},
  {id:'128',question:'Healthcare facilities are required by this organization to provide adequate ventilation systems PPE and safe work operating procedures:',options:['EPA','FDA','OSHA','CMS'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'easy',explanation:'OSHA requires healthcare facilities to provide adequate ventilation systems, PPE, and safe work operating procedures.'},
  {id:'129',question:'To reduce the risk of slips and falls:',options:['Enforce the use of non-skid footwear in the SPD','Park mobile equipment in the main hallway outside the SPD','Check each cart\'s weight before moving it from an elevator','Always use transport carts'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'Enforcing the use of non-skid footwear is the primary method to reduce slip and fall risk.'},
  {id:'130',question:'When a technician cannot see what is in a sink or basin they should:',options:['Drain the sink or basin','Wear heavy duty gloves to grasp objects in the sink','Have someone help determine what is in the sink or basin','All the above'],correct_answer:0,domain:'Safety',difficulty:'medium',explanation:'When unable to see into a sink or basin drain it first — never blindly reach in even with gloves.'},
  {id:'131',question:'This is the level of exposure to a harmful substance at which an employer must take required precautions:',options:['Time-weighted average (TWA)','Short-term exposure limit (STEL)','Permissible exposure limit (PEL)','Action level (AL)'],correct_answer:2,domain:'Safety',difficulty:'hard',explanation:'The Permissible Exposure Limit (PEL) is the level at which employers must take required precautions to protect workers.'},
  {id:'132',question:'Ergonomic injuries:',options:['Are not a concern for SP employees','Are rare in today\'s work environment','Are a risk factor for people who perform repetitive activities or physical work','Occur only in the office setting'],correct_answer:2,domain:'Safety',difficulty:'easy',explanation:'Ergonomic injuries are a significant risk for SP employees who perform repetitive activities.'},
  {id:'133',question:'Secondary containers for chemicals must be labeled with:',options:['A copy of the original manufacturer\'s label or a generic label identifying the chemical hazard warnings and directions','A permanent marker and state the chemical\'s name and designated storage location','Nothing — they are not allowed in healthcare facilities','No restrictions for container labels at this time'],correct_answer:0,domain:'Safety',difficulty:'medium',explanation:'Secondary containers must be labeled with either the original manufacturer label or a generic label identifying the chemical, hazard warnings, and directions.'},
  {id:'134',question:'A molecular reaction that creates an uncontrolled release of energy is called:',options:['Combustion','Polymerization','Vapor density','Fire'],correct_answer:1,domain:'Safety',difficulty:'hard',explanation:'Polymerization is the molecular reaction that creates an uncontrolled release of energy.'},
  {id:'135',question:'Which of the following is an example of communication?',options:['Spoken word','Written word','Non-verbal expressions','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'Communication includes spoken words, written words, and non-verbal expressions.'},
  {id:'136',question:'This is an example of informal communication:',options:['Departmental bulletins and memos','Meeting discussions','Spreading rumors','Posting work schedules'],correct_answer:2,domain:'Professional Development',difficulty:'medium',explanation:'Spreading rumors is informal communication — bulletins, meeting discussions, and schedules are formal communication channels.'},
  {id:'137',question:'Behavior relating to what is right and wrong relative to the standards of professional conduct is called:',options:['Ethical behavior','Moral behavior','Legal behavior','Personal behavior'],correct_answer:0,domain:'Professional Development',difficulty:'easy',explanation:'Ethical behavior is behavior relating to what is right and wrong relative to standards of professional conduct.'},
  {id:'138',question:'When a listener asks a question during a conversation it is called:',options:['Stereotyping','Feedback','Communication looping','Halo interpretation'],correct_answer:1,domain:'Professional Development',difficulty:'easy',explanation:'When a listener asks a question it is called feedback — it confirms understanding.'},
  {id:'139',question:'This process allows a person to understand someone else\'s needs:',options:['Communication','Human relations','Feedback','Moral behavior'],correct_answer:1,domain:'Professional Development',difficulty:'medium',explanation:'Human relations is the process that allows a person to understand and respond to someone else\'s needs.'},
  {id:'140',question:'When speaking one should:',options:['Be influenced by the listener\'s emotions','Concentrate on the listener rather than oneself','Concentrate on oneself rather than the listener','Use technical jargon to address the listener'],correct_answer:1,domain:'Professional Development',difficulty:'easy',explanation:'Effective speaking requires concentrating on the listener\'s needs rather than the speaker\'s own thoughts.'},
  {id:'141',question:'Informal work groups frequently develop:',options:['An attitude that is detrimental to the organization','An informal communication system called the grapevine','A task group as an example of an informal group','A rule that employees can only be in one formal group'],correct_answer:1,domain:'Professional Development',difficulty:'medium',explanation:'Informal work groups frequently develop an informal communication system called the grapevine.'},
  {id:'142',question:'Valuing efforts to promote diversity can:',options:['Improve job satisfaction and decrease absenteeism','Create a culture of respect and promote teamwork','Increase creative thinking and problem solving','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'Valuing diversity promotes all of these outcomes.'},
  {id:'143',question:'Knowing what is expected and consistently meeting those expectations is part of:',options:['Effective communication','Ethical behavior','Job success','Professional behavior'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'Knowing expectations and consistently meeting them is the definition of professional behavior.'},
  {id:'144',question:'When SP technicians have internet access at work:',options:['It should be used for work-related purposes only','It may be used for any purpose as long as it does not interfere with work','It should only be used during break time','Employees should use their own discretion'],correct_answer:0,domain:'Professional Development',difficulty:'easy',explanation:'Internet access at work should be used for work-related purposes only.'},
  {id:'145',question:'Which of the following is an open-ended question?',options:['How long have you worked here?','Do you have experience with orthopedic instruments?','What problems do you most frequently encounter on the job?','What is the name of the SP director?'],correct_answer:2,domain:'Professional Development',difficulty:'easy',explanation:'An open-ended question requires more than a yes/no answer — it invites explanation and discussion.'},
  {id:'146',question:'When establishing personal goals set goals that are:',options:['Quickly attainable','Attainable within five years then set new goals','Attainable then build on those successes','Specific to one\'s current position and education'],correct_answer:2,domain:'Professional Development',difficulty:'medium',explanation:'Goals should be attainable and then build on successes — creating momentum for continued development.'},
  {id:'147',question:'Professional development includes:',options:['Keeping current in an existing job','Activities to advance skills','Attending on-the-job training and continuing education sessions','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'Professional development encompasses all activities that improve skills and knowledge.'},
  {id:'148',question:'Mentoring others:',options:['Is only done by management personnel','Is a requirement for promotion','Requires one to be skilled in all areas of the department','Is a positive behavior that gets noticed'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'Mentoring others is a positive behavior that gets noticed by leadership.'},
  {id:'149',question:'When developing a professional timeline one must:',options:['Recognize that some goals are easier to achieve than others','Realize that promotions do not usually happen overnight','Understand that things will not always go as planned','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'All three are important realities when developing a professional timeline.'},
  {id:'150',question:'Online resources:',options:['Have been determined as reliable','Are always the best way to obtain information','Must be checked to confirm that the information and source are valid and current','Are always approved by the device manufacturer'],correct_answer:2,domain:'Professional Development',difficulty:'easy',explanation:'Online resources must always be verified for validity and currency.'},
  {id:'151',question:'One important step in preparing for an interview is:',options:['Reviewing the certification exam questions','Developing a written response to application questions','Anticipating possible interview questions','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'medium',explanation:'All three are important interview preparation steps.'},
  {id:'152',question:'When a technician is promoted to a higher position:',options:['Their departmental relationships will change','They need to consider the broader needs of the department and facility','They should remember that things do not always go as planned','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'All three are true when promoted — relationships change, perspective must broaden, and flexibility is required.'},
  {id:'153',question:'One type of formal monitoring is:',options:['Monitoring the department\'s temperature and humidity levels','Ensuring everyone entering the department is dressed appropriately','Ensuring everyone who enters practices good hand hygiene','Ensuring traffic protocols are followed'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Monitoring and recording temperature and humidity levels is formal monitoring — the others are informal.'},
  {id:'154',question:'A physical monitor on a washer-disinfector is the:',options:['Thermostatic valve','Printout','Biological test','All the above'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'The printout is the physical monitor on a washer-disinfector showing time, temperature, and cycle data.'},
  {id:'155',question:'Cart washer floor screens should be checked:',options:['At least daily','During each shift','Weekly preferably daily','Monthly'],correct_answer:0,domain:'Equipment',difficulty:'easy',explanation:'Cart washer floor screens should be checked at least daily to prevent clogging.'},
  {id:'156',question:'Providing quality products directly impacts a patient\'s:',options:['Health','Outcome','Safety','All the above'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'easy',explanation:'Quality products directly impact patient health, outcomes, and safety.'},
  {id:'157',question:'Quality monitoring is:',options:['The process of maintaining or improving quality outputs','A quick quality fix','Finding solutions to eliminate a root cause','Collecting standard data'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'easy',explanation:'Quality monitoring is the ongoing process of maintaining and improving quality outputs.'},
  {id:'158',question:'This organization uses unannounced inspections to monitor standards:',options:['ISO','NCQA','CMS','HCAHPS'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'hard',explanation:'The Centers for Medicare and Medicaid Services (CMS) uses unannounced inspections to monitor compliance.'},
  {id:'159',question:'Quality processes in decontamination include:',options:['Measuring chemicals','Checking instruments for cleanliness and functionality','Following all pick list instructions','All the above'],correct_answer:3,domain:'Decontamination',difficulty:'easy',explanation:'All three are quality processes in decontamination.'},
  {id:'160',question:'Assuming responsibility for survey readiness is one factor in:',options:['RCA','Keeping the focus on the patient','FMEA','Quality management'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Assuming responsibility for survey readiness is a factor in overall quality management.'},
  {id:'161',question:'Supply inspection should include:',options:['Only date-related items','Only in-house sterilized items','Checking for excessive handling','Checking the product\'s manufacturer date'],correct_answer:2,domain:'Sterile Storage',difficulty:'medium',explanation:'Supply inspection should include checking for excessive handling that could compromise sterility.'},
  {id:'162',question:'This organization issues regulations to help ensure medical devices are safe:',options:['FDA','EPA','DOT','OSHA'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'easy',explanation:'The FDA issues regulations to help ensure medical devices are safe and effective.'},
  {id:'163',question:'Items that have been used for patient care should be considered:',options:['Contaminated','Disinfected','Ready to use','Decontaminated'],correct_answer:0,domain:'Decontamination',difficulty:'easy',explanation:'All items used for patient care must be considered contaminated and handled as such regardless of appearance.'},
  {id:'164',question:'Which of the following statements about IUSS is true?',options:['It is the sterilization method of choice for metal instruments','It is recommended as a primary sterilization process by AAMI and AORN','It reduces turnaround time because cleaning is not required','It should only be used when there is not enough time to process items using the wrapped method'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'IUSS should only be used when there is insufficient time for wrapped sterilization.'},
  {id:'165',question:'Following liquid chemical sterilization items intended to be used as critical devices may be stored for:',options:['No storage — they should be used immediately','60 minutes','Four hours','One day'],correct_answer:0,domain:'Sterile Storage',difficulty:'hard',explanation:'Items processed by LCS have no sterile barrier and must be used immediately.'},
  {id:'166',question:'Which of the following can be used to close sterile packages?',options:['Sterilization indicator tape','Staples','Binder clips','Painter\'s tape'],correct_answer:0,domain:'Packaging',difficulty:'easy',explanation:'Sterilization indicator tape is the only acceptable closure for sterile packages.'},
  {id:'167',question:'An acceptable method of package closure that is also used as an external indicator is:',options:['Paper clips','Indicator tape','Staples','Binder clips'],correct_answer:1,domain:'Packaging',difficulty:'easy',explanation:'Sterilization indicator tape is both an acceptable closure method and an external chemical indicator.'},
  {id:'168',question:'Which must be inside every sterile package?',options:['Biological indicator','Chemical indicator','Count sheet','Expiration label'],correct_answer:1,domain:'Packaging',difficulty:'easy',explanation:'A chemical indicator must be inside every sterile package to confirm sterilant penetration.'},
  {id:'169',question:'The weakest part of a steam sterilizer is the:',options:['Jacket','Gasket','Door','Thermostatic valve'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'The gasket is the weakest part — it is subject to wear and must be inspected regularly.'},
  {id:'170',question:'The most common reason for steam sterilization failure is:',options:['Lack of steam contact with the contents of the load','Insufficient temperature in the sterilizer chamber','Inadequate exposure time','Drying issues'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Lack of steam contact is the most common cause — caused by improper loading, air pockets, or inadequate packaging.'},
  {id:'171',question:'What is used daily to ensure air removal in pre-vacuum steam sterilizers?',options:['Infrared device','Bowie-Dick test','Humidity gauge','Sterilization parameter readout'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'The Bowie-Dick test is run daily in pre-vacuum sterilizers to verify adequate air removal.'},
  {id:'172',question:'EO-sterilized items are aerated to remove residual:',options:['EO','Oxides','Peroxide','Alkali'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'Aeration removes residual ethylene oxide gas from sterilized items — EO residue is toxic.'},
  {id:'173',question:'How should sterile packages be arranged to allow for stock rotation?',options:['Take from the bottom first','Last in first out','First in first out','Last in last out'],correct_answer:2,domain:'Sterile Storage',difficulty:'easy',explanation:'FIFO (First In First Out) is the correct stock rotation method.'},
  {id:'174',question:'The shelving system of choice for the sterile storage area is:',options:['Closed','Semi-closed','Open','Tracked'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'Closed shelving is the preferred system for sterile storage.'},
  {id:'175',question:'The bottom shelf of any sterile storage system should be:',options:['Solid and eight to 10 inches from the floor','Solid and two to four inches from the floor','Made of wire and positioned two to four inches from the floor','Made of wire and positioned eight to 10 inches from the floor'],correct_answer:0,domain:'Sterile Storage',difficulty:'medium',explanation:'The bottom shelf must be solid and 8-10 inches from the floor.'},
  {id:'176',question:'Wrapped trays should not be stacked because:',options:['Tray contents may become damaged','It can cause holes in the wrappers','It will cause the shelving to bend','Trays will be more difficult to rotate'],correct_answer:1,domain:'Sterile Storage',difficulty:'medium',explanation:'Stacking wrapped trays causes holes in the wrappers compromising the sterile barrier.'},
  {id:'177',question:'Outside shipping containers should be removed before items enter sterile storage:',options:['True','False','Only for corrugated boxes','Only for items stored near in-house sterilized items'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'Outside shipping containers must be removed — they are contaminated from transport.'},
  {id:'178',question:'Items should be stored at least how many inches below sprinkler heads?',options:['8','12','18','24'],correct_answer:2,domain:'Sterile Storage',difficulty:'hard',explanation:'Items must be stored at least 18 inches below sprinkler heads to allow full sprinkler operation.'},
  {id:'179',question:'The use of heat to kill all microorganisms except spores is called:',options:['Sterilization','Thermal disinfection','HLD','Mechanical disinfection'],correct_answer:1,domain:'Disinfection',difficulty:'medium',explanation:'Thermal disinfection uses heat to kill all microorganisms except spores.'},
  {id:'180',question:'These chemicals are used on animate living tissue to slow the growth of microorganisms:',options:['Glutaraldehydes','Disinfectants','Halogens','Antiseptics'],correct_answer:3,domain:'Disinfection',difficulty:'easy',explanation:'Antiseptics are used on living tissue to slow microbial growth — disinfectants are used on inanimate objects.'},
  {id:'181',question:'Items introduced directly into the bloodstream are classified as:',options:['Critical items','Semi-critical items','Non-critical items','Equipment'],correct_answer:0,domain:'Disinfection',difficulty:'easy',explanation:'Critical items contact sterile tissue or the bloodstream and require sterilization.'},
  {id:'182',question:'The process by which all forms of microorganisms are completely destroyed is:',options:['HLD','Thermal disinfection','Sterilization','Chemical disinfection'],correct_answer:2,domain:'Sterilization',difficulty:'easy',explanation:'Sterilization is the only process that destroys ALL forms of microorganisms including spores.'},
  {id:'183',question:'Which of the following are classified as high-level disinfectants?',options:['Glutaraldehydes and phenolics','Glutaraldehydes and OPA','Quats and phenolics','Halogens and OPA'],correct_answer:1,domain:'Disinfection',difficulty:'hard',explanation:'Glutaraldehydes and OPA are both classified as high-level disinfectants.'},
  {id:'184',question:'The place where the two parts of a ring-handled instrument meet and pivot is called the:',options:['Ratchet','Spring lock','Box lock','Jaw'],correct_answer:2,domain:'Instrumentation',difficulty:'easy',explanation:'The box lock is where the two parts of a ring-handled instrument meet and pivot.'},
  {id:'185',question:'Tissue forceps have:',options:['Serrated tips','Serrated locks','Gold tips','Teeth'],correct_answer:3,domain:'Instrumentation',difficulty:'easy',explanation:'Tissue forceps have teeth for gripping tissue — dressing forceps have serrations.'},
  {id:'186',question:'An osteotome is:',options:['Used to cut or shave bone','A retractor','Another name for a curette','Used to dissect soft tissue'],correct_answer:0,domain:'Instrumentation',difficulty:'easy',explanation:'An osteotome is a surgical instrument used to cut or shave bone.'},
  {id:'187',question:'Scissors with tungsten carbide cutting edges are usually identified by:',options:['Black handles','Silver handles','Gold handles','The letters TC'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'Tungsten carbide scissors are identified by gold handles or rings.'},
  {id:'188',question:'Which of the following steps happens first when processing flexible endoscopes?',options:['Leak testing','High-level disinfection/sterilization','Manual cleaning','Drying'],correct_answer:0,domain:'Endoscope Reprocessing',difficulty:'hard',explanation:'Leak testing must be performed FIRST before any cleaning — if the endoscope has a leak submersion causes internal damage.'},
  {id:'189',question:'Which statement about endoscopes is true?',options:['Flexible endoscopes are time-consuming to clean','Ultrasonic cleaning is the process of choice for endoscopes','Flexible endoscopes are not easily damaged','All endoscopes should be steam sterilized'],correct_answer:0,domain:'Endoscope Reprocessing',difficulty:'easy',explanation:'Flexible endoscopes ARE time-consuming to clean due to their complex channels and delicate construction.'},
  {id:'190',question:'The FDA classifies sterilization packaging as a:',options:['Class I medical device','Class II medical device','Class III medical device','Class IV medical device'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'The FDA classifies sterilization packaging as a Class II medical device.'},
  {id:'191',question:'IUSS documentation should include:',options:['Patient ID','Sterilizer number and cycle','Name of the instrument sterilized','All the above'],correct_answer:3,domain:'Sterilization',difficulty:'easy',explanation:'IUSS documentation must include patient ID, sterilizer number and cycle, and instrument name.'},
  {id:'192',question:'How frequently should a sterilizer\'s chamber drain strainer be removed and cleaned?',options:['Daily','After each use','Once weekly','Only when indicated by the control gauge'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'The drain strainer should be removed and cleaned daily to prevent buildup.'},
  {id:'193',question:'Humidity in the sterile storage area should be:',options:['Less than 30%','30% to 60%','Greater than 60%','No specific requirement'],correct_answer:1,domain:'Sterile Storage',difficulty:'hard',explanation:'Humidity in sterile storage must be maintained at 30-60%.'},
  {id:'194',question:'Which of the following is not a goal of point-of-use treatment?',options:['Removing gross soil','Transporting instruments within two hours of the end of a procedure','Preventing cross-contamination','Preventing damage during transport'],correct_answer:1,domain:'Infection Prevention',difficulty:'medium',explanation:'Transporting instruments within two hours is NOT a goal of point-of-use treatment.'},
  {id:'195',question:'Which of the following can cause a wet pack?',options:['Placing dry instruments within a package','Heavy or dense instrument sets','Standing a basin on edge and tilting for drainage','Ensuring there is visible space between packs'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'Heavy or dense instrument sets retain moisture during the drying cycle.'},
  {id:'196',question:'The three main phases of a terminal steam sterilizer cycle are:',options:['Gravity exposure and exhaust','Pre-vacuum exposure and exhaust','Exposure exhaust and dry','Conditioning exposure and exhaust'],correct_answer:3,domain:'Sterilization',difficulty:'hard',explanation:'The three phases are conditioning (air removal), exposure (sterilization), and exhaust (pressure release and drying).'},
  {id:'197',question:'Which sterilization method can permeate throughout a wide range of materials to reach recessed areas?',options:['Hydrogen peroxide','Steam sterilization','Ethylene oxide','Glutaraldehyde'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'Ethylene oxide gas permeates through a wide range of materials and packaging to reach recessed areas.'},
  {id:'198',question:'Sterile storage areas should have:',options:['Positive airflow and at least 10 air exchanges per hour','Positive airflow and at least four air exchanges per hour','Negative airflow and at least 10 air exchanges per hour','Negative airflow and at least four air exchanges per hour'],correct_answer:0,domain:'Sterile Storage',difficulty:'hard',explanation:'Sterile storage must have positive airflow and at least 10 air exchanges per hour.'},
  {id:'199',question:'Written cleaning instructions for surgical instruments should be provided by the:',options:['Mechanical washer manufacturer','Device manufacturer','Detergent manufacturer','Healthcare facility'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'The device manufacturer provides written cleaning instructions (IFU) — these must be followed to ensure proper cleaning.'},
  {id:'200',question:'What is the preferred pH for detergents used for most cleaning processes?',options:['Low pH','High pH','Neutral pH','It depends on water temperature and exposure time'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Neutral pH detergents are preferred for most instrument cleaning — effective without damaging instrument surfaces.'},
  {id:'201',question:'Instruments should be kept together with their sets in the user area because:',options:['It reduces the risk that multi-part components will be misplaced','The chance that instruments will be lost is decreased','Reassembly of the set will not be delayed','All the above'],correct_answer:3,domain:'Decontamination',difficulty:'easy',explanation:'All three are valid reasons — keeping sets together prevents lost components, reduces loss risk, and prevents assembly delays.'},
  {id:'202',question:'If soiled items are held in user units before being picked up they must be kept:',options:['At the patient\'s bedside until SP collects them','In a locked area on the nursing unit','In a designated holding area','In a container of water'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Soiled items must be kept in a designated holding area — not at bedside or in water which promotes bacterial growth.'},
  {id:'203',question:'Which is NOT a reason for point-of-use treatment?',options:['It helps reduce the likelihood of biofilm formation','It reduces the SP workload','Dried soil requires more aggressive cleaning measures','It helps prolong the life of the instruments'],correct_answer:1,domain:'Decontamination',difficulty:'hard',explanation:'Point-of-use treatment does not reduce the SP workload — it adds a step at the user end.'},
  {id:'204',question:'A goal of soiled transport is to:',options:['Minimize the risk of cross-contamination','Decrease the time it takes to get soiled items to decontamination','Decrease microbial growth','All the above'],correct_answer:3,domain:'Decontamination',difficulty:'easy',explanation:'All three are goals of soiled transport — minimizing contamination risk, speed, and microbial growth control.'},
  {id:'205',question:'Before transporting soiled devices SP technicians should be aware of:',options:['The number of case carts in the decontamination area','Visiting hours so carts are not transported when visitors are in hallways','The ergonomic principles of lifting pushing and pulling','All the above'],correct_answer:3,domain:'Decontamination',difficulty:'easy',explanation:'All three are important considerations before transporting soiled devices.'},
  {id:'206',question:'Off-site transport policies and procedures should define:',options:['Soil levels','Color of biohazard signage','How to remove biofilm','Separation of clean and dirty'],correct_answer:3,domain:'Decontamination',difficulty:'medium',explanation:'Off-site transport policies must define separation of clean and dirty items to prevent cross-contamination.'},
  {id:'207',question:'Which is not a goal of point-of-use treatment?',options:['Removal of gross soil','Preventing cross-contamination','Transporting items within two hours of the end of the procedure','Preventing damage during transport'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Transporting within two hours is NOT a goal of point-of-use treatment.'},
  {id:'208',question:'The best way to transport contaminated instruments is in a/an:',options:['Open case cart','Dedicated soiled elevator','Cart in a patient elevator','Cart in a high-traffic area'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'A dedicated soiled elevator minimizes exposure to patients, visitors, and clean areas during transport.'},
  {id:'209',question:'During point-of-use treatment instruments should NOT:',options:['Have open hinges','Be disassembled','Be placed in a basin with saline to keep them moist','Be arranged in an orderly manner'],correct_answer:1,domain:'Decontamination',difficulty:'hard',explanation:'Instruments should NOT be disassembled at point-of-use — disassembly is done in the decontamination area.'},
  {id:'210',question:'Injuries or disorders of the muscles nerves tendons or joints are called:',options:['Pain points','Musculoskeletal disorders','Workplace disorders','Ergonomic injuries'],correct_answer:1,domain:'Safety',difficulty:'easy',explanation:'Musculoskeletal disorders are injuries or disorders affecting muscles, nerves, tendons, or joints.'},
  {id:'211',question:'The major source of soiled items received by the SPD is:',options:['Pharmacy','Surgery','Supply Chain','Infection Prevention'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'Surgery (the Operating Room) is the major source of soiled instruments received by the SPD.'},
  {id:'212',question:'When instruments are prepared for transport to the decontamination area it is important to keep them:',options:['Dry and assembled','Moist','Disassembled','In sterile water'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'Instruments must be kept moist during transport to prevent soil from drying and hardening on surfaces.'},
  {id:'213',question:'Tissue body fat blood and other bodily substances are examples of:',options:['Biofilm','Biohazard','Gross soil','Contamination'],correct_answer:2,domain:'Decontamination',difficulty:'easy',explanation:'Gross soil refers to visible tissue, body fat, blood and other bodily substances on instruments.'},
  {id:'214',question:'Soiled instruments should be transported in a/an:',options:['Open case cart','Closed hard-sided cart','Wire basket','Biohazard bag'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'Soiled instruments must be transported in a closed hard-sided cart to contain contamination and protect staff.'},
  {id:'215',question:'Containers and carts used to transport contaminated items should not be used to transport clean items unless they have been thoroughly:',options:['Rinsed','Sterilized','Decontaminated','Inspected'],correct_answer:2,domain:'Decontamination',difficulty:'easy',explanation:'Transport containers must be thoroughly decontaminated between uses to prevent cross-contamination of clean items.'},
  
  {id:'217',question:'Which statement about use of washer-disinfectors is NOT true?',options:['Multi-level trays should be separated','Trays with lids should be opened','Instruments should be disassembled and opened','All items should be washed on the same cycle'],correct_answer:3,domain:'Decontamination',difficulty:'medium',explanation:'All items should NOT be washed on the same cycle — different instruments have different cleaning requirements.'},
  {id:'218',question:'Water must be degassed each time an ultrasonic cleaner\'s tank is changed because excess bubbles:',options:['Reduce the energy of the cavitation process','Reduce the effectiveness of the detergent','Decrease the temperature of the tank','Make it difficult to see items being cleaned'],correct_answer:0,domain:'Decontamination',difficulty:'hard',explanation:'Excess air bubbles reduce the energy of the cavitation process — degassing removes these bubbles to maximize cleaning.'},
  {id:'220',question:'Floors and walls in the decontamination area should be:',options:['Cleaned monthly','Constructed to tolerate cleaning chemicals','Constructed of particulate materials','All the above'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'Floors and walls in decontamination must be constructed to tolerate the cleaning chemicals used in that environment.'},
  {id:'221',question:'Untreated water:',options:['Increases the likelihood of mineral scale deposits','Decreases the likelihood of mineral scale deposits','Is recommended for use during the detergent cycle','Is used for the final rinse process'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'Untreated water contains minerals that leave deposits on instruments — treated water prevents scale buildup.'},
  {id:'222',question:'These are used to breakdown fatty deposits on instruments:',options:['Protease enzymes','Lipase enzymes','Amylase enzymes','Neutral-pH cleaners'],correct_answer:1,domain:'Decontamination',difficulty:'hard',explanation:'Lipase enzymes break down fatty deposits — protease breaks down proteins, amylase breaks down starches.'},
  {id:'223',question:'Instrument lubrication is performed:',options:['Immediately before use','After sterilization','After cleaning and before packaging','Before cleaning'],correct_answer:2,domain:'Assembly',difficulty:'easy',explanation:'Lubrication is performed after cleaning and before packaging — it protects instruments and does not interfere with sterilization.'},
  {id:'224',question:'To prevent coagulation of proteins instruments should be pre-rinsed using:',options:['Cool water','Hot water','A neutral detergent','A disinfectant rinse'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'Cool water prevents protein coagulation — hot water causes proteins to cook onto instrument surfaces.'},
  {id:'225',question:'During manual cleaning instruments should be brushed using a:',options:['Circular motion','To-and-fro motion','Stiff metal brush','Scrubbing pad'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'To-and-fro motion is recommended for manual cleaning — circular motion can push debris into crevices.'},
  {id:'226',question:'Powered surgical instruments cannot be immersed in water:',options:['True','False','Only battery-powered instruments','Only pneumatic instruments'],correct_answer:0,domain:'Decontamination',difficulty:'easy',explanation:'Powered surgical instruments cannot be immersed — they must be cleaned according to manufacturer IFU.'},
  {id:'227',question:'Ultrasonic irrigators are used to:',options:['Clean prion items','Perform finite cleaning for powered surgical equipment','Clean devices with lumens','Clean flexible endoscopes with lumens'],correct_answer:2,domain:'Decontamination',difficulty:'hard',explanation:'Ultrasonic irrigators flush lumens and channels with cleaning solution to remove debris from internal surfaces.'},
  {id:'228',question:'Rigid container filter retention plates should be:',options:['Removed from the container and lid and cleaned separately','Manually cleaned and attached to the lid for mechanical cleaning','Left attached to the lid during the cleaning process','None of the above'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'Filter retention plates must be removed from both the container and lid and cleaned separately.'},
  {id:'229',question:'Instruments with lumens should always be soaked in a:',options:['Vertical position','Horizontal position','Disassembled position','Standing position'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'Instruments with lumens must be soaked vertically so fluid can enter and drain from the lumen by gravity.'},
  {id:'230',question:'The mechanical process by which an ultrasonic cleaner works is called:',options:['Impingement','Cavitation','Aerosolization','Emulsification'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'Cavitation is the process by which ultrasonic cleaners work — high-frequency sound waves create tiny bubbles that implode removing soil.'},
  {id:'231',question:'This low-level disinfectant is incompatible with soap:',options:['Alcohol','Phenol','Quaternary ammonium compounds','OPA'],correct_answer:2,domain:'Disinfection',difficulty:'hard',explanation:'Quaternary ammonium compounds are inactivated by soap and organic materials — they must never be mixed with soap.'},
  {id:'232',question:'When working with glutaraldehyde technicians should always wear:',options:['Latex gloves','Nitrile gloves','Decontamination gloves','Exam gloves'],correct_answer:1,domain:'Safety',difficulty:'medium',explanation:'Nitrile gloves must be worn when working with glutaraldehyde — latex gloves do not provide adequate protection.'},
  {id:'233',question:'How are items that have undergone HLD dried?',options:['Air dried','With HEPA-filtered air','If using an AER no extra drying is required if an alcohol flush is included','All the above'],correct_answer:3,domain:'Disinfection',difficulty:'medium',explanation:'All three are acceptable drying methods for HLD items depending on the process and equipment used.'},
  {id:'234',question:'In a washer-disinfector the key source of disinfection is:',options:['Hydrogen peroxide','Water temperature','Heat','Disinfecting detergent'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Heat is the primary source of disinfection in a washer-disinfector.'},
  {id:'235',question:'The use of test strips to test the MEC in HLD solutions is required:',options:['Weekly preferably daily','Daily','Each time the solution will be used','Only when manual soaking systems are used'],correct_answer:2,domain:'Disinfection',difficulty:'hard',explanation:'MEC test strips must be used each time the HLD solution will be used to ensure adequate concentration.'},
  {id:'240',question:'Iodophors are a member of this chemical family:',options:['Halogens','Quats','Alcohol','Phenolics'],correct_answer:0,domain:'Disinfection',difficulty:'medium',explanation:'Iodophors are iodine-based compounds belonging to the halogen family of disinfectants.'},
  {id:'241',question:'Phenolics are classified as:',options:['Low- to intermediate-level disinfectants','Intermediate- to high-level disinfectants','High-level disinfectants','Sterilants'],correct_answer:0,domain:'Disinfection',difficulty:'medium',explanation:'Phenolics are low- to intermediate-level disinfectants.'},
  {id:'243',question:'Thermal disinfection is accomplished using:',options:['Heated chemicals','Heated glutaraldehyde','Prolonged high-pressure steam','Heat'],correct_answer:3,domain:'Disinfection',difficulty:'easy',explanation:'Thermal disinfection uses heat alone.'},
  {id:'244',question:'How long must alcohol remain in wet contact with an item to achieve reasonable disinfection?',options:['One to two minutes','Two to three minutes','Five to 10 minutes','10 to 20 minutes'],correct_answer:2,domain:'Disinfection',difficulty:'hard',explanation:'Alcohol must remain in wet contact for five to 10 minutes to achieve effective disinfection.'},
  {id:'245',question:'Which chemical is the best choice for HLD of instruments?',options:['Phenolics','Chlorine','Iodophors','OPA'],correct_answer:3,domain:'Disinfection',difficulty:'hard',explanation:'OPA is the best choice for HLD of instruments — effective, less irritating than glutaraldehyde.'},
  {id:'246',question:'A chemical that kills most pathogenic organisms but does not kill spores is called a:',options:['Sterilant','Antiseptic','Disinfectant','Bactericidal agent'],correct_answer:2,domain:'Disinfection',difficulty:'medium',explanation:'A disinfectant kills most pathogenic organisms but not spores — sterilants destroy all forms of microbial life.'},
  {id:'247',question:'The length of time an item must remain in wet contact with a disinfectant is called:',options:['Activation time','Wet contact time','Disinfectant holding time','Sterilization time'],correct_answer:2,domain:'Disinfection',difficulty:'easy',explanation:'Disinfectant holding time is the required contact time for the disinfectant to be effective.'},
  {id:'248',question:'MEC testing using test strips is required:',options:['Weekly','Daily','Each time the solution is used','Only when the solution appears cloudy'],correct_answer:2,domain:'Disinfection',difficulty:'hard',explanation:'MEC test strips must be used each time the HLD solution is used to verify adequate concentration.'},
  {id:'249',question:'When manually disinfecting lumens care should be taken to ensure there are no:',options:['Detergent residues','Air bubbles','Mineral deposits','Chemical residues'],correct_answer:1,domain:'Disinfection',difficulty:'medium',explanation:'Air bubbles inside lumens prevent the disinfectant from contacting all surfaces.'},
  {id:'250',question:'Microgrind and supercut scissors are usually identified by:',options:['Gold rings','Black rings','Teeth on one blade serrations on the other','One black ring and one gold ring'],correct_answer:1,domain:'Instrumentation',difficulty:'medium',explanation:'Microgrind and supercut scissors have black rings on the handles to identify them as premium cutting instruments.'},
  {id:'251',question:'This type of needle holder insert is harder and lasts longer:',options:['Stainless steel','Chromium oxide','Nickel','Tungsten carbide'],correct_answer:3,domain:'Instrumentation',difficulty:'medium',explanation:'Tungsten carbide inserts are harder and last longer than stainless steel.'},
  
  {id:'253',question:'The process used to give instruments a mirror finish is called:',options:['Heat treating','Wiping with chromium oxide','Forging with more nickel','Polishing'],correct_answer:3,domain:'Instrumentation',difficulty:'medium',explanation:'Polishing gives instruments a mirror finish.'},
  
  {id:'255',question:'During instrument manufacturing the process used to build a protective layer on instruments is called:',options:['Passivation','Forging','Polishing','Milling'],correct_answer:0,domain:'Instrumentation',difficulty:'medium',explanation:'Passivation builds a protective chromium oxide layer on stainless steel instruments.'},
  {id:'256',question:'The part of a hemostat that locks and holds it in position is called the:',options:['Ratchet','Box lock','Spring lock','Jaw'],correct_answer:0,domain:'Instrumentation',difficulty:'easy',explanation:'The ratchet is the locking mechanism on hemostats and other clamps.'},
  {id:'257',question:'An acceptable method for instrument identification is:',options:['Powder coating','Identification tape','Laser etching','All the above'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'Laser etching is an acceptable identification method — identification tape can interfere with sterilization.'},
  {id:'258',question:'Which solution can damage surgical instrumentation?',options:['Betadine','Sterile water','Critical water','Utility water'],correct_answer:0,domain:'Instrumentation',difficulty:'medium',explanation:'Betadine is corrosive to surgical instruments and can cause pitting and staining.'},
  
  {id:'260',question:'The purpose of a suction stylet is to:',options:['Unclog the suction during surgery','Clean the suction in the decontamination area','Facilitate the sterilization process','Provide a measuring guide for the surgeon'],correct_answer:0,domain:'Instrumentation',difficulty:'medium',explanation:'A suction stylet is used to unclog the suction cannula during surgery when it becomes blocked with tissue.'},
  {id:'261',question:'Kerrison and laminectomy rongeurs should be tested using:',options:['Tissue paper','A plastic dowel rod','Rubber testing material','An index card'],correct_answer:1,domain:'Instrumentation',difficulty:'hard',explanation:'A plastic dowel rod is used to test Kerrison and laminectomy rongeurs.'},
  
  {id:'263',question:'The best way to clean a suction lumen is:',options:['Using warm running water','Using the proper-sized brush','Soaking in an enzymatic solution for three minutes','Using the appropriate stylet'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Using the proper-sized brush is the best way to clean a suction lumen.'},
  {id:'264',question:'To properly test the sharpness of scissors measuring 4.5 inches and shorter use:',options:['Yellow test material','Red test material','An index card','Orange test material'],correct_answer:1,domain:'Instrumentation',difficulty:'hard',explanation:'Red test material is used to test scissors 4.5 inches and shorter.'},
  {id:'265',question:'A self-retaining retractor is called a:',options:['Gelpi','Richardson','Kerrison','Hemostat'],correct_answer:0,domain:'Instrumentation',difficulty:'medium',explanation:'The Gelpi retractor is self-retaining — it holds itself in place without an assistant.'},
  {id:'266',question:'Tissue forceps have teeth and dressing forceps have:',options:['Teeth','Serrations','Gold tips','Smooth tips'],correct_answer:1,domain:'Instrumentation',difficulty:'easy',explanation:'Tissue forceps have teeth for gripping tissue — dressing forceps have serrations.'},
  {id:'267',question:'Tungsten carbide scissor blades hold a sharp edge longer than stainless steel blades:',options:['True','False','Only for small scissors','Only for large scissors'],correct_answer:0,domain:'Instrumentation',difficulty:'easy',explanation:'True — tungsten carbide is harder than stainless steel and holds a sharp edge significantly longer.'},
  {id:'268',question:'Laser etching is an acceptable method for marking instruments:',options:['True','False','Only for stainless steel','Only for titanium'],correct_answer:0,domain:'Instrumentation',difficulty:'easy',explanation:'True — laser etching is an acceptable permanent identification method that does not damage instruments.'},
  {id:'269',question:'The first step to inspect the insulation of a laparoscopic instrument is to:',options:['Check the collar at the distal tip','Try to slide the insulation back','Check the handle for chipping or cracking','Visually check the instrument\'s shaft'],correct_answer:3,domain:'Instrumentation',difficulty:'medium',explanation:'Visually checking the instrument\'s shaft is the first step — look for cuts, abrasions, or missing insulation.'},
  
  {id:'271',question:'Pneumatic cords are a cleaning concern because:',options:['Of their length','They are dark in color so soil is difficult to see','The electrical plug is very delicate','The cord does not detach from the device'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Pneumatic cords are dark in color making soil very difficult to see.'},
  {id:'272',question:'The purpose of using a decontamination battery or hose when cleaning powered surgical instruments is to:',options:['Keep fluid from entering the unit','Keep batteries and cords clean','Prevent electrical shock','Test the unit while cleaning'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'The decontamination battery or hose keeps fluid from entering the instrument unit during cleaning.'},
  {id:'273',question:'One of the main reasons for powered surgical instrument repair is:',options:['Poor sterilization practices','Lack of preventative maintenance','Kinking of the umbilical cable','Improper storage'],correct_answer:1,domain:'Equipment',difficulty:'medium',explanation:'Lack of preventative maintenance is the primary reason for powered surgical instrument repair.'},
  {id:'274',question:'Powered surgical instrument attachments can be peel packaged for sterilization if approved by the manufacturer:',options:['True','False','Only for electric instruments','Only for pneumatic instruments'],correct_answer:0,domain:'Sterilization',difficulty:'hard',explanation:'Attachments can be peel packaged for sterilization if approved by the manufacturer.'},
  {id:'275',question:'Loaned instruments should:',options:['Be decontaminated if they appear soiled upon arrival','Be sterilized using a low-temperature process','Be decontaminated before use','Should not be used'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'All loaned instruments must be decontaminated before use regardless of appearance.'},
  {id:'276',question:'Information regarding cleaning processes for endoscopes should be provided by the:',options:['SGNA','APIC','Instrument manufacturer','OR staff'],correct_answer:2,domain:'Endoscope Reprocessing',difficulty:'medium',explanation:'The instrument manufacturer provides cleaning instructions (IFU) that must be followed.'},
  {id:'278',question:'Electronic testing of laparoscopic insulation should be done:',options:['In the decontamination area prior to cleaning','In the clean assembly area prior to set assembly','At the factory or onsite repair unit','In the OR at the end of the procedure'],correct_answer:1,domain:'Instrumentation',difficulty:'hard',explanation:'Electronic insulation testing is done in the clean assembly area prior to set assembly.'},
  {id:'279',question:'Pneumatic hoses should be pressurized for proper inspection:',options:['True','False','Only flexible hoses','Only pneumatic cords'],correct_answer:0,domain:'Equipment',difficulty:'hard',explanation:'Pneumatic hoses should be pressurized for proper inspection — this tests for leaks.'},
  {id:'280',question:'Powered surgical instrument batteries should be charged per the manufacturers IFU:',options:['In the OR','In the decontamination area','Before sterilization','During PM inspections'],correct_answer:2,domain:'Equipment',difficulty:'medium',explanation:'Batteries should be charged per manufacturer IFU — typically before sterilization.'},
  {id:'281',question:'Semi-rigid endoscopes should be leak tested prior to cleaning:',options:['True','False','Only when visibly damaged','Only for urological procedures'],correct_answer:0,domain:'Endoscope Reprocessing',difficulty:'medium',explanation:'Semi-rigid endoscopes should be leak tested prior to cleaning to detect leaks before submersion.'},
  {id:'282',question:'Endoscopic cameras should be inspected for:',options:['Cuts nicks or other damage to the cable','Lens clarity only','Battery charge','Sterilization date'],correct_answer:0,domain:'Instrumentation',difficulty:'medium',explanation:'Endoscopic camera cables should be inspected for cuts, nicks, or other damage — cable damage is a common cause of failure.'},
  {id:'283',question:'Robotic instruments:',options:['May have exposed cables','Are processed the same as laparoscopic instruments','Require extensive PM','Are heavy and less susceptible to damage'],correct_answer:2,domain:'Equipment',difficulty:'hard',explanation:'Robotic instruments require extensive preventative maintenance due to their complex mechanical and electrical components.'},
  {id:'284',question:'Leak testing should be performed on each flexible endoscope:',options:['Before every use','On an annual basis only','After every cleaning cycle','Before every cleaning'],correct_answer:3,domain:'Endoscope Reprocessing',difficulty:'hard',explanation:'Leak testing must be performed before every cleaning — submersing a leaking endoscope causes irreparable internal damage.'},
  {id:'285',question:'Loaned instrument trays received sterile from other facilities must be decontaminated and re-sterilized before use:',options:['True','False','Only if visibly soiled','Only if more than 30 days old'],correct_answer:0,domain:'Decontamination',difficulty:'hard',explanation:'All loaned instruments must be decontaminated and re-sterilized regardless of how they arrive.'},
  {id:'286',question:'Endoscope channels should be stored:',options:['Moist','Completely dry','Filled with sterile water','With alcohol in the channels'],correct_answer:1,domain:'Endoscope Reprocessing',difficulty:'medium',explanation:'Endoscope channels must be completely dry before storage — moisture promotes microbial growth.'},
  {id:'288',question:'Which of the following is NOT an acceptable sterilization packaging material?',options:['Muslin','Barrier cloth','Canvas','Twill'],correct_answer:2,domain:'Packaging',difficulty:'hard',explanation:'Canvas is not an acceptable sterilization packaging material.'},
  {id:'289',question:'Count sheets provide:',options:['A description of each instrument in detail','Information for OR trays only','A detailed list of tray contents','Information from the manufacturer\'s IFU'],correct_answer:2,domain:'Assembly',difficulty:'easy',explanation:'Count sheets provide a detailed list of tray contents — they are used to verify all instruments are accounted for.'},
  {id:'290',question:'When arranging paper/plastic pouches in a sterilizer the pouches should be arranged:',options:['Paper to plastic','Paper to paper','Plastic to plastic','Flat'],correct_answer:0,domain:'Packaging',difficulty:'medium',explanation:'Paper/plastic pouches must be arranged paper to plastic so steam can penetrate through the paper side.'},
  {id:'291',question:'How often should the insulation of electrosurgical instruments be tested for integrity?',options:['Only when requested','Every time the instrument is processed','Every fifth time the instrument is processed','Weekly'],correct_answer:1,domain:'Instrumentation',difficulty:'hard',explanation:'Electrosurgical instrument insulation must be tested every time it is processed.'},
  {id:'292',question:'Spunbonded polyolefin is intended for use in this sterilization process:',options:['Steam','Hydrogen peroxide','Liquid','Gravity'],correct_answer:1,domain:'Packaging',difficulty:'hard',explanation:'Spunbonded polyolefin (Tyvek) is designed for hydrogen peroxide sterilization.'},
  {id:'293',question:'When placing hinged instruments in an instrument tray:',options:['Lock the handles to prevent damage','Arrange all sharps on top','Arrange in order of use','Unlock the handles and open the instruments'],correct_answer:3,domain:'Assembly',difficulty:'easy',explanation:'Hinged instruments must be unlocked and open so steam can reach all joint surfaces during sterilization.'},
  {id:'294',question:'Instruments are placed into sets:',options:['Wet','Soiled','Dry','Assembled'],correct_answer:2,domain:'Assembly',difficulty:'easy',explanation:'Instruments must be completely dry before being placed into sets — moisture causes wet packs.'},
  {id:'295',question:'Which cannot be used in an instrument set to protect delicate instruments?',options:['Tip protectors','Plastic peel packs','Approved foam pouches','Silicon mats'],correct_answer:1,domain:'Packaging',difficulty:'hard',explanation:'Plastic peel packs cannot be used inside sets to protect instruments — they trap moisture and prevent steam penetration.'},
  {id:'296',question:'This type of CI is a cycle-specific verification indicator designed to react to all critical parameters:',options:['Type 3','Type 4','Type 5','Type 6'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'Type 5 integrating indicators react to all critical sterilization parameters — the most comprehensive CI type.'},
  {id:'297',question:'Which packaging system is required to be packaged twice for double sterile presentation?',options:['Sterilization container','Sequential flat wrapper','Simultaneous flat wrapper','Containment device'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Sequential flat wrapping applies two wraps in sequence creating a package within a package.'},
  {id:'298',question:'Which of the following items can cause superheating within a sterilization cycle?',options:['Soiled instruments','Wet instruments','Instruments with insulation','Pre-packaged sterile towels'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'Instruments with insulation can cause superheating — the insulation traps heat.'},
  {id:'299',question:'Plastic containers take longer to dry because they:',options:['Lack metal which produces heat by conduction','Are lighter','Crack easily leaving areas for moisture to hide','Can hold more instruments'],correct_answer:0,domain:'Sterilization',difficulty:'hard',explanation:'Plastic lacks metal\'s thermal conductivity — metal conducts heat that aids in drying.'},
  {id:'303',question:'The flat-wrapping technique that applies one wrap on top of another is called:',options:['Square fold','Sequential','Simultaneous','Envelope fold'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Sequential wrapping applies one wrap on top of another — each wrap is a separate sterile barrier.'},
  {id:'304',question:'The government agency that regulates sterilization packaging materials is:',options:['EPA','FDA','CDC','OSHA'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'easy',explanation:'The FDA regulates sterilization packaging as Class II medical devices.'},
  {id:'305',question:'Type of packaging containing no cellulosic materials used for low-temperature sterilization of small items is:',options:['Paper/plastic combinations','Muslin','Spunbond polyolefin-plastic combinations','Barrier cloth'],correct_answer:2,domain:'Packaging',difficulty:'hard',explanation:'Spunbond polyolefin (Tyvek) contains no cellulosic materials and is validated for low-temperature sterilization.'},
  {id:'306',question:'When using paper/plastic combination pouches package content information should be written on:',options:['The paper side','The plastic side','Either side','The label only'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Package content information should be written on the plastic side — writing on paper can damage the barrier.'},
  {id:'307',question:'The wrapping technique most commonly used for small packs and most trays is:',options:['Square fold','Sequential flat wrap','Simultaneous flat wrap','Envelope fold'],correct_answer:3,domain:'Packaging',difficulty:'easy',explanation:'The envelope fold is the most commonly used wrapping technique for small packs and instrument trays.'},
  {id:'308',question:'Barrier packaging prevents microorganisms from entering packages and allows aseptic opening:',options:['True','False','Only for steam sterilization','Only for EO sterilization'],correct_answer:0,domain:'Packaging',difficulty:'easy',explanation:'Barrier packaging prevents microbial entry and allows aseptic presentation.'},
  {id:'309',question:'The process by which instruments are steam sterilized for immediate use is called:',options:['Emergency sterilization','Immediate use steam sterilization','Core sterilization','Rapid reprocessing'],correct_answer:1,domain:'Sterilization',difficulty:'easy',explanation:'IUSS (Immediate Use Steam Sterilization) is the correct term — flash sterilization is an outdated term.'},
  {id:'310',question:'Items to be disinfected or sterilized at the point of use must be:',options:['Properly cleaned per the manufacturer\'s IFU','Semi-critical devices','Non-critical devices','Heat sensitive'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Items for point-of-use processing must still be properly cleaned per manufacturer IFU.'},
  {id:'311',question:'The best way to transport IUSS items at the point of use is:',options:['Covered with a sterile towel','In a rigid container designed for IUSS','In a covered mesh-bottom tray','In a Kraft-paper bag'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'A rigid container designed for IUSS provides the best protection during transport.'},
  {id:'312',question:'What is the length of time after sterilization that an IUSS item can be used?',options:['IUSS items must be used immediately','Up to 4 hours','Up to 8 hours','The next day'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'IUSS items must be used immediately — they cannot be stored for later use.'},
  {id:'313',question:'Which statement about IUSS is true?',options:['It is the sterilization method of choice for metal instruments','It is recommended as a primary sterilization process by AAMI and AORN','It reduces turnaround time because cleaning is not required','It should only be used when there is not enough time to process items using the wrapped method'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'IUSS should only be used when there is insufficient time for wrapped sterilization.'},
  {id:'314',question:'Both AORN and The Joint Commission recommend that:',options:['The use of IUSS be minimized or decreased','IUSS be performed in only one sterilizer per facility','Healthcare facilities receive clearance from the FDA for IUSS','Only SP technicians should operate immediate use steam sterilizers'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Both AORN and TJC recommend minimizing IUSS use.'},
  {id:'315',question:'Implantable devices should not be sterilized using IUSS unless:',options:['It is an emergency','A tracking system is in place to trace the item to the patient','The surgeon approves it','The device is metal'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'Implants should not undergo IUSS unless a tracking system traces the item to the patient.'},
  {id:'316',question:'When transporting items that have undergone IUSS it is required that they be:',options:['Transported in a metal container','Transported to the patient area within five minutes of sterilization','Allowed to cool properly before transport','Transported in a way that reduces the potential for contamination'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'IUSS items must be transported in a way that reduces contamination potential.'},
  {id:'317',question:'Terminal sterilization is:',options:['The process by which instruments are sterilized in their final containers allowing storage until needed','Process designed for cleaning and delivery of patient care items for immediate use','The process by which instruments are disinfected in their final containers','Process designed for cleaning disinfecting and delivery for immediate use'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Terminal sterilization packages items in their final sterile barrier allowing storage until point of use.'},
  {id:'319',question:'Sterilization documentation IS required for items that undergo IUSS:',options:['True','False','Only for implants','Only for high-risk procedures'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Sterilization documentation is REQUIRED for all IUSS items.'},
  {id:'320',question:'IUSS was developed to process items when a facility does not have enough instrumentation:',options:['True','False — IUSS was developed to handle true emergency situations','Only in emergency departments','Only for orthopedic instruments'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'IUSS was NOT developed to compensate for inadequate instrument inventory — it is for true emergencies only.'},
  {id:'321',question:'When loading a steam sterilizer basins should be:',options:['Placed in an upright position','Loaded first','Placed on edge','Placed in a wire basket'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'Basins must be placed on edge and tilted to allow condensate to drain.'},
  {id:'322',question:'The higher the level of bioburden on an object the:',options:['More difficult it will be to sterilize','Less time it will take to sterilize','More biological tests will be needed in the load','Longer it will take to cool after sterilization'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Higher bioburden makes sterilization more difficult — soil protects microorganisms from sterilant contact.'},
  {id:'323',question:'When combining loads rigid containers should be placed on:',options:['The top shelf','The bottom shelf','The middle shelf','Any shelf'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'Rigid containers go on the bottom shelf — textiles on top, pouches on edge.'},
  {id:'324',question:'SP technicians need to understand the anatomy of a steam sterilizer to:',options:['Know how to properly clean the chamber','Understand how the sterilizer operates','Understand how to test the thermostatic trap','All the above'],correct_answer:3,domain:'Sterilization',difficulty:'easy',explanation:'All three are important reasons — technicians must understand sterilizer anatomy for cleaning, operation, and testing.'},
  {id:'328',question:'The coolest area in a steam sterilizer is the:',options:['Gasket','Drain','Jacket','Chamber'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'The drain is the coolest area — cool air and condensate drain from the bottom of the chamber.'},
  {id:'329',question:'Which is not part of the sterilizer physical monitor printout?',options:['Date and time the cycle began','Selected cycle parameters','Statement of guarantee of sterility','Written record of actual cycle activities'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'A statement of guarantee of sterility is NOT on the printout — the printout records cycle data but cannot guarantee sterility.'},
  {id:'330',question:'One common cause of a clogged drain screen is:',options:['Tape','Wrapper particles','Poor steam quality','Malfunctioning baffle plate'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Wrapper particles are the most common cause of clogged drain screens.'},
  {id:'331',question:'For sterilization peel pouches should be placed:',options:['On edge paper to plastic','On edge plastic to plastic','Flat with the plastic side up','Flat with the paper side up'],correct_answer:0,domain:'Packaging',difficulty:'medium',explanation:'Peel pouches go on edge paper to plastic — this allows steam to enter through paper and air/condensate to exit through the drain.'},
  {id:'332',question:'Moisture can create a pathway for microorganisms to travel from the outside to inside of a package:',options:['True','False','Only for muslin wraps','Only for paper pouches'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Moisture creates a wicking pathway — wet packages allow microorganisms to travel from outside to inside.'},
  {id:'336',question:'IUSS items cannot be stored — they must be used immediately:',options:['True','False','Only for implants','Only for Class III devices'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'IUSS items have no sterile barrier packaging and must be used immediately after sterilization.'},
  {id:'337',question:'Placing warm sterilized packages on cool surfaces will cause:',options:['Biofilm formation','Wet packs from condensate','Package seal failure','CI color change reversal'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Condensate forms when warm packages contact cool surfaces — this creates wet packs that compromise the sterile barrier.'},
  {id:'338',question:'The thermostatic trap in a steam sterilizer:',options:['Heats the chamber walls','Seals the door','Measures steam temperature and controls flow of air and condensate','Contains the chamber drain'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'The thermostatic trap measures temperature and automatically controls the flow of air and condensate.'},
  {id:'339',question:'Gravity displacement sterilizers remove air from the chamber by:',options:['Using a vacuum pump','Using steam to force cooler air out through the drain','Using filtered air exchanges','Using a thermostatic valve'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Gravity displacement sterilizers use steam to push heavier cool air downward and out through the chamber drain.'},
  {id:'340',question:'The most frequent cause for sterilization failure is lack of steam:',options:['Temperature','Contact','Pressure','Exposure time'],correct_answer:1,domain:'Sterilization',difficulty:'easy',explanation:'Lack of steam contact is the most frequent cause of sterilization failure.'},
  {id:'341',question:'Why is proper training for low-temperature sterilization important?',options:['Chemicals used have toxic properties','Technicians must know how to prevent instrument corrosion','Low-temperature sterilization is a costly process','Low-temperature methods are new technology with no standards'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'The chemicals used in low-temperature sterilization are toxic — proper training is essential to protect staff.'},
  {id:'342',question:'When an item undergoes low-temperature sterilization what is meant by material compatibility?',options:['Two or more materials on the medical device interact','Two or more materials on the device do not interact','There should not be changes in the device\'s functionality','The manufacturer has validated the device is compatible with a specific low-temperature process'],correct_answer:3,domain:'Sterilization',difficulty:'hard',explanation:'Material compatibility means the manufacturer has validated the device is compatible with the specific sterilization process.'},
  {id:'345',question:'Which of the following items can be sterilized by H2O2?',options:['Antibiotics','Gauze sponges','Baby powder','Telescopes'],correct_answer:3,domain:'Sterilization',difficulty:'hard',explanation:'Telescopes can be sterilized by hydrogen peroxide — cellulosic materials like gauze and powders are not compatible.'},
  {id:'346',question:'Aeration instructions for a medical device can be found in/on the:',options:['Gas cartridge\'s IFU','Sterilizer\'s IFU','Device manufacturer\'s IFU','FDA\'s website'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'Aeration instructions are found in the device manufacturer\'s IFU.'},
  {id:'347',question:'What is a permissible exposure limit (PEL)?',options:['The maximum time an item can undergo sterilization exposure','The maximum amount of sterilant an item can be exposed to','The maximum amount or concentration of a chemical a worker may be exposed to under OSHA regulations','The minimum and maximum time an employee can work with powder sterilization'],correct_answer:2,domain:'Safety',difficulty:'hard',explanation:'The PEL is the maximum chemical concentration a worker may be exposed to according to OSHA regulations.'},
  {id:'348',question:'Information about a device\'s compatibility with a specific sterilization process can be obtained:',options:['On the SDS','On the FDA\'s website','In AAMI standards','In the device\'s IFU'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'Device compatibility with specific sterilization processes is found in the device manufacturer\'s IFU.'},
  {id:'349',question:'To ensure successful sterilization the sterilizer chamber should not be:',options:['Loaded a long time before sterilization','Overloaded','Underloaded','Loaded with mixed types of items'],correct_answer:1,domain:'Sterilization',difficulty:'easy',explanation:'Overloading is the primary loading error — it prevents adequate steam or sterilant penetration and contact.'},
  {id:'350',question:'PELs for low-temperature sterilization methods are established by the:',options:['FDA','CDC','OSHA','EPA'],correct_answer:2,domain:'Safety',difficulty:'medium',explanation:'OSHA establishes Permissible Exposure Limits (PELs) for chemical sterilants like EO and glutaraldehyde.'},
  {id:'351',question:'There should be at least how many air exchanges per hour in a room that has an EO sterilizer?',options:['4','6','10','12'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'A minimum of 10 air exchanges per hour is required in rooms with EO sterilizers.'},
  {id:'352',question:'The probability of a viable microorganism being present on an item after sterilization is the:',options:['Sterility assurance level','Bioburden count','Spore log reduction','Minimum effective concentration'],correct_answer:0,domain:'Sterilization',difficulty:'hard',explanation:'Sterility assurance level (SAL) is the probability that a viable microorganism remains on an item after sterilization.'},
  {id:'353',question:'The bacterial spore used to test EO sterilization cycles is:',options:['Geobacillus stearothermophilus','Bacillus atrophaeus','Clostridium difficile','Staphylococcus aureus'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'Bacillus atrophaeus is the biological indicator organism used to test EO sterilization cycles.'},
  {id:'354',question:'Geobacillus stearothermophilus is used to test:',options:['EO sterilization only','Steam sterilization and hydrogen peroxide sterilization','Low-temperature plasma only','Chemical sterilization only'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'Geobacillus stearothermophilus is the biological indicator organism used to test both steam and H2O2 sterilization.'},
  {id:'355',question:'Personal monitoring for EO exposure requires the device to be affixed:',options:['To the employee\'s wrist','Directly to the employee\'s clothing in the breathing zone','Near the sterilizer','In the employee break room'],correct_answer:1,domain:'Safety',difficulty:'medium',explanation:'Personal monitoring devices must be worn in the breathing zone to accurately measure employee chemical exposure.'},
  {id:'356',question:'Satellite storage areas should:',options:['Be maintained by SP personnel','Be cleaned monthly','Follow the same guidelines used in SP storage','Only use closed shelving'],correct_answer:2,domain:'Sterile Storage',difficulty:'medium',explanation:'Satellite storage areas must follow the same storage guidelines as the main SP storage area.'},
  {id:'357',question:'Endoscopes that have undergone HLD should be stored:',options:['Completely dry','Within a clean wrapper','Hanging in an open cabinet','In a long plastic bag'],correct_answer:2,domain:'Endoscope Reprocessing',difficulty:'hard',explanation:'HLD endoscopes should be stored hanging in an open cabinet to allow continued drying.'},
  {id:'359',question:'The sterile storage process begins:',options:['When items are received in the decontamination area','After items are sterilized and cooled','When the sterilizer door is opened at the end of a cycle','When items are placed inside the sterilizer'],correct_answer:1,domain:'Sterile Storage',difficulty:'medium',explanation:'Sterile storage begins after items are sterilized AND properly cooled.'},
  {id:'363',question:'Trays that overhang shelving:',options:['Can become contaminated','Are acceptable for rigid containers but not flat-wrapped trays','Are appropriate for heavy trays as they allow proper body mechanics','None of the above'],correct_answer:0,domain:'Sterile Storage',difficulty:'medium',explanation:'Trays overhanging shelving can become contaminated by air currents, touch, or contact with non-sterile surfaces.'},
  {id:'364',question:'The type of shelving that leaves packaging the most vulnerable is:',options:['Open','Closed','Semi-closed','Tracked'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'Open shelving leaves packages most vulnerable to contamination from air, dust, and accidental contact.'},
  {id:'366',question:'Sterile trays should:',options:['Not be touched until they are properly cooled','Be lifted not dragged from the sterilizer cart','Be checked to confirm CIs have turned the appropriate color','All the above'],correct_answer:3,domain:'Sterile Storage',difficulty:'easy',explanation:'All three are correct — trays must cool completely, be lifted not dragged, and CIs must be verified.'},
  {id:'369',question:'How long can flexible endoscopes that have undergone HLD or LCS be stored?',options:['One week','One month','Six weeks','According to facility policy'],correct_answer:3,domain:'Sterile Storage',difficulty:'hard',explanation:'Storage time for HLD/LCS endoscopes is determined by facility policy based on storage conditions and packaging.'},
  {id:'371',question:'FIFO stands for:',options:['First In First Out','First In Final Out','Facility Inventory First Order','Final Inspection Final Output'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'FIFO = First In First Out — the required stock rotation method ensuring older items are used before newer ones.'},
  {id:'372',question:'Airflow in the sterile storage area should be:',options:['Negative','Positive','Filtered only','No specific requirement'],correct_answer:1,domain:'Sterile Storage',difficulty:'medium',explanation:'Sterile storage must have positive airflow — this pushes any contaminants out rather than pulling them in.'},
  {id:'373',question:'Packaging that prevents microorganisms from entering packages and allows aseptic opening is called:',options:['Sterile wrap','Barrier packaging','Indicator packaging','Containment packaging'],correct_answer:1,domain:'Packaging',difficulty:'easy',explanation:'Barrier packaging prevents microbial entry and allows aseptic presentation.'},
  {id:'375',question:'Items should not be used after the manufacturer\'s expiration date even if the package integrity is still intact:',options:['True','False','Only for implants','Only for single-use devices'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'Items must not be used after the manufacturer\'s expiration date regardless of package appearance.'},
  {id:'376',question:'Stacking wrapped trays can cause holes and other damage to wrappers:',options:['True','False','Only for muslin wraps','Only when trays are heavy'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'Stacking wrapped trays creates pressure that can puncture or tear the sterile barrier.'},
  {id:'377',question:'When transporting sterile items in a dedicated clean lift they should be contained:',options:['True','False','Only for wrapped items','Only for rigid containers'],correct_answer:0,domain:'Sterile Storage',difficulty:'medium',explanation:'Sterile items must be contained even in a dedicated clean lift to protect them from contamination.'},
  {id:'378',question:'It is important to identify devices that have undergone HLD or LCS as patient-ready because:',options:['It prevents the need to reprocess if the HLD or LCS process is called into question','It helps identify each device\'s storage location','It distinguishes processed from non-processed devices','It documents who processed them last'],correct_answer:0,domain:'Sterilization',difficulty:'hard',explanation:'Identifying patient-ready devices allows targeted reprocessing if the disinfection process is questioned.'},
  {id:'379',question:'Horizontal work surfaces in the decontamination area should be cleaned and disinfected:',options:['Weekly','Monthly','Once per day','After each case'],correct_answer:2,domain:'Decontamination',difficulty:'easy',explanation:'Horizontal surfaces in decontamination must be cleaned and disinfected at least once per day.'},
  {id:'380',question:'To prevent aerosolization items should be brushed:',options:['Above the surface of the water','Below the surface of the water','In a dry container','Outside the sink'],correct_answer:1,domain:'Safety',difficulty:'easy',explanation:'Items must be brushed below the water surface to prevent aerosolization of potentially infectious particles.'},
  {id:'381',question:'Automatic washers clean using a spray-force action called:',options:['Cavitation','Aerosolization','Impingement','Emulsification'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Washer-disinfectors use impingement — a high-pressure spray-force action that removes soil from instrument surfaces.'},
  {id:'382',question:'PPE is required when using IUSS to clean items:',options:['True','False','Only for chemical sterilants','Only in the decontamination area'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'PPE is always required when cleaning instruments regardless of whether they will undergo IUSS.'},
  {id:'383',question:'IUSS is NOT the sterilization method of choice for single-use items:',options:['True','False','Only for metal single-use items','Depends on the device'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'IUSS is not appropriate for single-use devices. Single-use items should not be reprocessed.'},
  {id:'384',question:'Following a procedure on a patient with confirmed CJD IUSS is NOT recommended:',options:['True','False','Only if instruments are visibly contaminated','Only for implants used in the procedure'],correct_answer:0,domain:'Sterilization',difficulty:'hard',explanation:'IUSS is not recommended for CJD cases. Special decontamination protocols are required for prion disease instruments.'},
  {id:'385',question:'The manufacturer\'s IFU must state a device can be sterilized using IUSS before it is processed that way:',options:['True','False','Only for implants','Only for powered instruments'],correct_answer:0,domain:'Sterilization',difficulty:'hard',explanation:'The manufacturer\'s IFU must validate IUSS compatibility. If the IFU does not mention IUSS the device cannot be processed that way.'},
  {id:'386',question:'All items sterilized or HLD at point of use must be carefully monitored and documented:',options:['True','False','Only for implants','Only for reusable devices'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'All point-of-use sterilization and HLD must be monitored and documented for patient traceability.'},
  {id:'387',question:'The interior chamber walls of a sterilizer are heated by steam in the:',options:['Gasket','Jacket','Chamber drain','Thermostatic trap'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'The jacket of the sterilizer heats the chamber walls — this pre-heating reduces condensation.'},
  {id:'388',question:'The chamber drain is located in the floor of the steam sterilizer:',options:['True','False','Only in gravity sterilizers','Only in pre-vacuum sterilizers'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'The chamber drain is located in the floor of the sterilizer — air and condensate drain downward by gravity.'},
  {id:'389',question:'Charts and printouts provide a written record of sterilizer cycle activities:',options:['True','False','Only for pre-vacuum sterilizers','Only for steam sterilizers'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'Charts and printouts are the physical monitors that provide a written record of actual sterilizer cycle activities.'},
  {id:'390',question:'Why is it important to document wet packs?',options:['To identify when it will be safe to unload the sterilizer cart','Because it is required by HHS','Because it is required in the instrument tracking system','Because of the complexity of the issue'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'Wet pack documentation is required in the instrument tracking system so affected items can be identified.'},
  {id:'391',question:'OSHA sets exposure standards for chemical sterilants:',options:['True','False','Only for EO','Only for glutaraldehyde'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'OSHA establishes Permissible Exposure Limits (PELs) for chemical sterilants including EO and glutaraldehyde.'},
  {id:'392',question:'The aeration phase of an EO sterilizer cycle immediately follows the sterilization phase:',options:['True','False','Only for 100% EO','Only for mixed gas EO'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Aeration immediately follows sterilization in an EO cycle to begin removing toxic residual gas.'},
  {id:'393',question:'The method of stock rotation that ensures older items are used first is called:',options:['LIFO','FIFO','FILO','LILO'],correct_answer:1,domain:'Sterile Storage',difficulty:'easy',explanation:'FIFO (First In First Out) is the required stock rotation method.'},
  {id:'394',question:'Because they are mild cleaners dish soaps are the cleaners of choice for surgical instruments:',options:['True','False','Only for delicate instruments','Only for stainless steel'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'False — dish soaps are NOT appropriate for surgical instruments. They may leave residue and cause corrosion.'},
  {id:'395',question:'There is no need to pre-clean items that will be processed in an ultrasonic cleaner:',options:['True','False — pre-cleaning is required','Only for heavily soiled items','Only for powered instruments'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Pre-cleaning IS required before ultrasonic cleaning — gross soil must be removed first.'},
  {id:'396',question:'Instruments received from surgery and tagged for repair do not need to be cleaned until they come back from repair:',options:['True','False — they must be cleaned before being sent for repair','Only if visibly soiled','Only for powered instruments'],correct_answer:1,domain:'Decontamination',difficulty:'hard',explanation:'Instruments tagged for repair must be cleaned before being sent — repair technicians should not handle contaminated instruments.'},
  {id:'397',question:'Powered surgical instruments should be cleaned using a mechanical cleaning process:',options:['True','False — powered surgical instruments cannot be mechanically cleaned','Only if manufacturer approves','Only for electric instruments'],correct_answer:2,domain:'Decontamination',difficulty:'hard',explanation:'Powered surgical instruments may only be mechanically cleaned if the manufacturer\'s IFU approves it.'},
  {id:'398',question:'Laparoscopic instrument insulation failure can cause burns to the patient:',options:['True','False','Only during monopolar cautery','Only if insulation is completely missing'],correct_answer:0,domain:'Endoscope Reprocessing',difficulty:'medium',explanation:'Insulation failure on laparoscopic instruments can cause burns to the patient from stray electrical current during surgery.'},
  {id:'399',question:'The purpose of a decontamination battery or hose is to protect powered instruments from fluid invasion during cleaning:',options:['True','False','Only for battery-powered instruments','Only for pneumatic instruments'],correct_answer:0,domain:'Decontamination',difficulty:'easy',explanation:'A decontamination battery or hose protects powered instruments from fluid invasion during the cleaning process.'},
  {id:'400',question:'A disadvantage of rigid sterilization containers is:',options:['Their barrier qualities','They help eliminate torn wrappers','They help protect instruments during processing storage and transport','Additional cycle time may be required to thoroughly dry the contents'],correct_answer:3,domain:'Packaging',difficulty:'medium',explanation:'Rigid containers require additional drying time — this is their primary disadvantage compared to wrapped packages.'},
  {id:'401',question:'Which of the following best describes the primary mission of the Sterile Processing Department?',options:['To provide cost-effective supply management','To decontaminate reusable medical devices and ensure they are safe for patient use','To manage OR scheduling and instrument needs','To regulate sterile field compliance during surgery'],correct_answer:1,domain:'SPD Overview',difficulty:'easy',explanation:'The primary mission of SPD is to decontaminate reusable medical devices and return them to a safe condition for patient use.',source:'hspa'},
  {id:'402',question:'The SPD department is divided into which main functional zones?',options:['Reception, processing, and distribution','Decontamination, preparation/packaging, and sterile storage','Cleaning, packaging, and sterilization','Receiving, assembly, and dispatch'],correct_answer:1,domain:'SPD Overview',difficulty:'easy',explanation:'SPD is organized into three functional zones: decontamination (soiled), preparation and packaging (clean), and sterile storage.',source:'hspa'},
  {id:'403',question:'Which area of the SPD requires negative air pressure to contain contaminants?',options:['Sterile storage','Assembly area','Decontamination area','Clean corridor'],correct_answer:2,domain:'SPD Overview',difficulty:'medium',explanation:'The decontamination area requires negative air pressure so air flows into the area, containing contaminants and preventing them from spreading to clean zones.',source:'hspa'},
  {id:'404',question:'The preparation and packaging area of the SPD should have air pressure that is:',options:['Negative relative to clean corridors','Positive relative to the decontamination area','Equal to the decontamination area','Unregulated — no ventilation specifications are required'],correct_answer:1,domain:'SPD Overview',difficulty:'medium',explanation:'The prep/pack area should have positive airflow relative to decontamination to prevent contaminants from migrating into clean processing spaces.',source:'hspa'},
  {id:'405',question:'Event-related sterility means that a properly packaged sterile item:',options:['Becomes non-sterile after a defined number of days','Remains sterile as long as the packaging remains intact and is stored properly','Must be resterilized after 30 days regardless of condition','Has its shelf life determined solely by the sterilization date'],correct_answer:1,domain:'SPD Overview',difficulty:'medium',explanation:'Event-related sterility means a correctly packaged item remains sterile until an event compromises the package — such as a tear, moisture, or mishandling — not based on elapsed time.',source:'hspa'},
  {id:'406',question:'Which statement about the SPD staff dress code is correct?',options:['Regular street clothes may be worn in all SPD areas','Surgical scrubs are acceptable everywhere in the department','Dedicated scrubs should be worn in clean areas and full PPE in the decontamination area','Only PPE is required in decontamination; no dress code applies elsewhere'],correct_answer:2,domain:'SPD Overview',difficulty:'easy',explanation:'SPD staff wear dedicated scrubs in clean processing areas and don full PPE (gown, gloves, face protection) in the decontamination area.',source:'hspa'},
  {id:'407',question:'In relation to surgical site infections caused by improperly processed instruments, the SPD is considered the:',options:['First line of defense','Last line of defense','Third line of defense','Secondary line of defense'],correct_answer:1,domain:'SPD Overview',difficulty:'easy',explanation:'SPD is the last line of defense against surgical site infections from inadequately processed instruments — every step is a critical patient safety function.',source:'hspa'},
  {id:'408',question:'Hand hygiene in the SPD should occur:',options:['Only before entering the clean assembly area','Only after removing gloves in decontamination','Before and after glove use and when transitioning between SPD zones','Only when hands are visibly soiled'],correct_answer:2,domain:'SPD Overview',difficulty:'easy',explanation:'Hand hygiene must occur before and after glove use and when moving between different SPD zones to prevent cross-contamination.',source:'hspa'},
  {id:'409',question:'The purpose of a pass-through window between the soiled receiving area and the decontamination room is to:',options:['Allow staff to move freely between soiled and clean areas','Transfer soiled items into decontamination without requiring staff to enter from the clean side','Allow sterilizer exhaust to vent into the clean corridor','Observe decontamination activity from a safe distance'],correct_answer:1,domain:'SPD Overview',difficulty:'medium',explanation:'Pass-through windows allow soiled items to be transferred directly into decontamination without breaching zone separation — maintaining the soiled-to-clean workflow.',source:'hspa'},
  {id:'410',question:'Which area of SPD should have access restricted to trained processing staff only?',options:['The receiving dock only','The instrument storage area only','All SPD processing zones','The decontamination area only'],correct_answer:2,domain:'SPD Overview',difficulty:'easy',explanation:'All SPD zones are restricted areas — unauthorized personnel may not enter any portion of the department to prevent contamination and maintain processing integrity.',source:'hspa'},
  {id:'411',question:'Instrument count sheets (tray lists) serve what primary purpose in SPD?',options:['To track billing charges for OR cases','To ensure all instruments are accounted for and properly assembled in the tray','To document sterilizer cycle parameters for each load','To identify damaged instruments requiring removal from service'],correct_answer:1,domain:'Assembly',difficulty:'easy',explanation:'Instrument count sheets ensure all instruments are accounted for after a procedure and correctly assembled in the tray before the next sterilization cycle.',source:'hspa'},
  {id:'412',question:'Instruments should be placed in trays with ratchets:',options:['Closed and tips pointed up','Open, with heavier items placed on the bottom','Fully closed and uniformly stacked to save space','Open with tips pointed outward for easy access during surgery'],correct_answer:1,domain:'Assembly',difficulty:'easy',explanation:'Ratchets must be open to allow steam penetration into box locks, and heavier items placed on the bottom to prevent damage to delicate instruments.',source:'hspa'},
  {id:'413',question:'Instrument tip protectors used during sterilization must be:',options:['Solid plastic to prevent contact damage between instrument tips','Vented or perforated to allow sterilant penetration around all surfaces','Removed before the instruments are placed in the sterilizer','Made of metal to withstand sterilization temperatures'],correct_answer:1,domain:'Assembly',difficulty:'medium',explanation:'Tip protectors used during sterilization must be vented or perforated — solid plastic can trap air or moisture and prevent sterilant from reaching all instrument surfaces.',source:'hspa'},
  {id:'414',question:'Before assembly, instruments should be inspected for all of the following EXCEPT:',options:['Residual soil from the cleaning process','Functional integrity of all moving parts and ratchets','Brand name or manufacturer marking','Physical defects such as cracks, pitting, or corrosion'],correct_answer:2,domain:'Assembly',difficulty:'medium',explanation:'Inspection covers cleanliness, function, and physical condition. Brand name is not a relevant safety inspection criterion and does not affect patient safety or instrument function.',source:'hspa'},
  {id:'415',question:'A ratchet on a hemostat should be tested by:',options:['Closing it to the first ratchet tooth and confirming it holds without added pressure','Squeezing it firmly and listening for a distinct click sound','Performing visual inspection of the ratchet teeth only','Submerging it in water to check for smooth mechanical operation'],correct_answer:0,domain:'Assembly',difficulty:'medium',explanation:'A ratchet is tested by closing to the first tooth — it should hold without additional force. A ratchet that springs open is defective and must be removed from service.',source:'hspa'},
  {id:'416',question:'Why must multi-piece instruments be fully disassembled before cleaning and sterilization?',options:['To reduce the overall weight of each instrument tray','To expose all surfaces for effective cleaning and sterilant contact','To allow individual components to be replaced if damaged','To comply with OR scheduling turnaround time requirements'],correct_answer:1,domain:'Assembly',difficulty:'easy',explanation:'Multi-piece instruments must be fully disassembled so all surfaces — including hidden internal components — can be properly cleaned and reached by the sterilant.',source:'hspa'},
  {id:'417',question:'Which type of lubricant is appropriate for surgical instruments before sterilization?',options:['Water-soluble instrument lubricant applied after cleaning and before packaging','Oil-based lubricant applied before the cleaning process','Any silicone spray available in the decontamination area','No lubricant should ever be applied to surgical instruments'],correct_answer:0,domain:'Assembly',difficulty:'medium',explanation:'Water-soluble (steam-permeable) instrument lubricant is applied after cleaning and before sterilization to protect box locks and moving parts. Oil-based lubricants block steam penetration.',source:'hspa'},
  {id:'418',question:'The purpose of using magnification during instrument inspection is to:',options:['Read instrument serial numbers and engraving more easily','Detect hairline cracks, pitting, and subtle damage not visible to the naked eye','Verify that instrument counts on the tray sheet are correct','Check sterilization indicators for color change after the cycle'],correct_answer:1,domain:'Assembly',difficulty:'medium',explanation:'Magnification allows detection of hairline cracks, pitting, corrosion, and other defects invisible to the naked eye that could harbor microorganisms and compromise patient safety.',source:'hspa'},
  {id:'419',question:'Loaner instruments received from a vendor must be:',options:['Used directly if vendor packaging is sealed and marked sterile','Inspected, cleaned, and sterilized before use regardless of packaging condition','Cleared by Risk Management only before any sterilization step','Sterilized only if they appear visibly soiled upon inspection'],correct_answer:1,domain:'Assembly',difficulty:'hard',explanation:'All loaner instruments must be fully inspected, cleaned, and sterilized before use — vendor packaging does not guarantee cleanliness or sterility.',source:'hspa'},
  {id:'420',question:'When assembling a peel-pack into a rigid container tray, the peel-pack should be positioned:',options:['Sealed end down to anchor and weight the pack','Paper side up to allow steam penetration through the porous paper layer','Plastic side up to protect the heat-sealed seam','Diagonally across the tray to maximize available tray space'],correct_answer:1,domain:'Assembly',difficulty:'medium',explanation:'Peel-packs inside trays should be paper side up — paper allows steam penetration while plastic does not, ensuring sterilant reaches all instrument surfaces.',source:'hspa'},
  {id:'421',question:'Instrument stringers or mesh basket inserts are used in instrument trays to:',options:['Prevent corrosion from metal-on-metal contact during sterilization','Prevent small parts from falling through tray perforations and being lost','Reduce total sterilization cycle time for the load','Satisfy TJC documentation requirements for instrument accountability'],correct_answer:1,domain:'Assembly',difficulty:'easy',explanation:'Stringers and mesh inserts capture small parts — screws, tips, caps — preventing loss during processing or at the sterile field.',source:'hspa'},
  {id:'422',question:'An instrument set is best defined as:',options:['A single instrument individually packaged in a peel pouch','A defined group of instruments assembled together for a specific surgical procedure','Any two instruments that are routinely used together in surgery','A collection of instruments pulled from multiple surgical specialties'],correct_answer:1,domain:'Assembly',difficulty:'easy',explanation:'An instrument set is a specific, defined group of instruments assembled into a tray for a particular surgical procedure, based on the instrument count sheet.',source:'hspa'},
  {id:'423',question:'The ABC inventory classification system categorizes items based on:',options:['Alphabetical order of item names for easy location','Value and frequency of use to prioritize management effort and resources','The age of items currently held in storage','Whether items are reusable or single-use disposables'],correct_answer:1,domain:'Inventory & Distribution',difficulty:'medium',explanation:'ABC inventory assigns highest management attention to high-value, high-use items (A items) and progressively less focus to lower-value, lower-use items (B and C items).',source:'hspa'},
  {id:'424',question:'Perpetual inventory tracking means that:',options:['All inventory is physically counted and verified every week','Stock levels are continuously updated with every transaction in real time','Items are ordered on a fixed monthly schedule regardless of usage','Inventory management is delegated entirely to the purchasing department'],correct_answer:1,domain:'Inventory & Distribution',difficulty:'medium',explanation:'Perpetual inventory continuously tracks stock — every receipt, issue, and return is immediately recorded, providing an accurate real-time count at all times.',source:'hspa'},
  {id:'425',question:'When distributing sterile supplies to patient care units, the technician should verify:',options:['That the item is packaged in the correct facility color-coded bag','Package integrity and correct item identity before distribution','That the item was sterilized within the current calendar week','That the requisition form is signed by the receiving nursing manager'],correct_answer:1,domain:'Inventory & Distribution',difficulty:'easy',explanation:'Before distributing any sterile supply, package integrity must be confirmed and the correct item identity verified — compromised packages must not be distributed.',source:'hspa'},
  {id:'426',question:'FIFO stock rotation requires that:',options:['The newest items received are dispensed first to minimize storage time','Older items are used before newer stock to ensure proper turnover','Items are organized by frequency of use rather than receipt date','Physical stock rotation is performed quarterly by a dedicated team'],correct_answer:1,domain:'Inventory & Distribution',difficulty:'easy',explanation:'FIFO — First In, First Out — ensures older stock is used before newer stock, preventing items from remaining in storage past their appropriate shelf life.',source:'hspa'},
  {id:'427',question:'A PAR level in inventory management represents:',options:['The maximum quantity of stock that should ever be maintained','The minimum stock level at which a reorder is triggered','The standard purchase unit price for a given item','The quantity ordered in each replenishment transaction'],correct_answer:1,domain:'Inventory & Distribution',difficulty:'medium',explanation:'PAR (Periodic Automatic Replenishment) level is the minimum threshold — when stock falls to or below this level, replenishment is initiated to prevent stockouts.',source:'hspa'},
  {id:'428',question:'Unused sterile items returned from the OR or a patient care unit should be:',options:['Returned directly to sterile storage if packaging appears intact at a glance','Carefully inspected for package integrity before being returned to sterile inventory','Always reprocessed from scratch regardless of packaging condition','Discarded since returned items can never be confirmed as sterile'],correct_answer:1,domain:'Inventory & Distribution',difficulty:'medium',explanation:'Returned items require careful inspection — confirmed intact packages may return to inventory; any compromised packaging requires full reprocessing.',source:'hspa'},
  {id:'429',question:'The exchange cart system benefits clinical areas primarily by:',options:['Eliminating the need for a dedicated sterile storage room','Providing continuous supply availability while one cart is being restocked','Reducing the total number of sterilization cycles required per day','Automating instrument tracking and documentation across user units'],correct_answer:1,domain:'Inventory & Distribution',difficulty:'medium',explanation:'The exchange cart system keeps one fully stocked cart in the clinical area while the other is being restocked by SPD — ensuring uninterrupted supply availability.',source:'hspa'},
  {id:'430',question:'Sterile items transported between SPD and patient care areas should be:',options:['Carried on open wire shelving carts to prevent package compression','Transported in enclosed or covered carts to protect packages from contamination','Placed in uncovered bins for rapid identification during transport','Carried by hand for small quantities to avoid unnecessary cart trips'],correct_answer:1,domain:'Inventory & Distribution',difficulty:'easy',explanation:'Sterile items must travel in enclosed or covered carts to protect packages from contamination, moisture, and physical damage during transit.',source:'hspa'},
  {id:'431',question:'Sterile storage areas must protect items from all of the following EXCEPT:',options:['Moisture and condensation from HVAC systems','Fluorescent lighting at normal indoor levels','Extreme temperature fluctuations','Dust, insects, and vermin'],correct_answer:1,domain:'Inventory & Distribution',difficulty:'medium',explanation:'Standard fluorescent lighting at normal indoor levels does not compromise sterile packaging. Moisture, temperature extremes, dust, and vermin all threaten package integrity and sterility maintenance.',source:'hspa'},
  {id:'432',question:'An instrument tracking system supports product recalls primarily by:',options:['Automatically quarantining affected items inside the sterilizer chamber','Enabling rapid identification of all patients who received a potentially affected item','Placing replacement orders with the product manufacturer immediately','Notifying the infection prevention team through automated alerts'],correct_answer:1,domain:'Inventory & Distribution',difficulty:'hard',explanation:'Instrument tracking enables rapid identification of every patient who received an item from a failed sterilization load or recalled product lot — a critical patient safety capability.',source:'hspa'},
  {id:'433',question:'An instrument tracking system primarily improves patient safety by:',options:['Replacing the need for biological indicator monitoring in routine loads','Linking each sterilized item to the specific patient it was used on for full traceability','Automatically configuring sterilizer cycle parameters for each load','Eliminating the need for manual instrument count sheets in the OR'],correct_answer:1,domain:'Information Technology',difficulty:'medium',explanation:'Instrument tracking creates a chain of custody from processing through patient use — enabling rapid traceability and recall action in sterilization failure or product recall events.',source:'hspa'},
  {id:'434',question:'A barcode label on an instrument tray typically captures:',options:['Patient billing and insurance information only','Tray identity, sterilizer used, cycle number, and processing date','Instrument purchase cost and remaining warranty period','Names of staff members who assembled and loaded the tray'],correct_answer:1,domain:'Information Technology',difficulty:'medium',explanation:'Tray barcodes capture identity and tracking data — tray name, sterilizer ID, cycle number, and load date — enabling full sterilization traceability.',source:'hspa'},
  {id:'435',question:'RFID technology differs from traditional barcodes primarily because RFID:',options:['Requires direct line-of-sight between the tag and reader','Can be read without line-of-sight and from a distance through most non-metallic materials','Functions only on single-use disposable supply items','Requires a staff member to manually scan each individual item'],correct_answer:1,domain:'Information Technology',difficulty:'medium',explanation:'RFID transmits data via radio waves without requiring line-of-sight — enabling automated, hands-free identification and real-time location tracking of instruments throughout the facility.',source:'hspa'},
  {id:'436',question:'Electronic sterilizer records provide an advantage over paper records because they:',options:['Replace biological indicator requirements under current AAMI standards','Provide tamper-resistant documentation with instant searchability for audits and investigations','Are exclusively required by TJC and not by AAMI ST79','Do not require trained staff to maintain or validate for accuracy'],correct_answer:1,domain:'Information Technology',difficulty:'medium',explanation:'Electronic records are tamper-resistant and instantly searchable — enabling rapid retrieval for audits, recalls, and investigations far more effectively than manual paper logs.',source:'hspa'},
  {id:'437',question:'If the instrument tracking system experiences an unplanned downtime, SPD should:',options:['Suspend all processing activities until the system is fully restored','Activate paper-based downtime procedures that capture the same tracking data','Continue processing without any documentation until electronic systems are restored','Wait for the IT vendor to complete remote repairs before resuming any work'],correct_answer:1,domain:'Information Technology',difficulty:'hard',explanation:'Downtime procedures using paper forms must replicate the same data — processing must continue to support patient care, with documentation captured manually until electronic systems are restored.',source:'hspa'},
  {id:'438',question:'Integration between the SPD tracking system and the electronic health record (EHR) enables:',options:['Automatic patient billing for instrument usage by the OR','Linking specific instrument sets to patient surgical records for complete audit trails','Nurses to order instruments directly from SPD\'s inventory system','Replacement of the physical sterilizer monitoring printout with a digital record'],correct_answer:1,domain:'Information Technology',difficulty:'hard',explanation:'EHR integration connects processed instrument data to patient surgical records — enabling a complete audit trail from decontamination through patient use, critical for infection investigations.',source:'hspa'},
  {id:'439',question:'Data integrity in the SPD tracking system means that records are:',options:['Stored in a physically secure, locked server room on-site','Accurate, complete, and unaltered — reliably representing what actually occurred','Backed up daily to an off-site cloud server for disaster recovery','Accessible only to department managers and infection prevention staff'],correct_answer:1,domain:'Information Technology',difficulty:'medium',explanation:'Data integrity means tracking records faithfully represent real events — accurate dates, cycle parameters, and sterilizer IDs that are reliable for patient safety purposes and regulatory compliance.',source:'hspa'},
  {id:'440',question:'The primary regulatory benefit of a complete instrument tracking system is:',options:['Reduced sterilizer preventive maintenance costs over the equipment lifespan','The ability to demonstrate compliance and execute rapid recalls when required','Elimination of routine biological indicator monitoring requirements','Reduced orientation and training time for newly hired technicians'],correct_answer:1,domain:'Information Technology',difficulty:'medium',explanation:'Complete tracking enables a facility to demonstrate regulatory compliance to TJC and AAMI and to rapidly execute accurate recalls when a sterilization failure or product recall is identified.',source:'hspa'},
  {id:'441',question:'The purpose of sequential (double) wrapping for instrument sets is to:',options:['Accelerate sterilant penetration during the sterilization cycle','Provide an additional sterile protective layer and a contained field when opening at the sterile field','Satisfy OSHA requirements for heavy-weight instrument trays','Eliminate the need for rigid sterilization container systems'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Sequential wrapping creates an outer protective layer; when removed, the inner wrap remains sterile — creating a contained aseptic field during package opening at the sterile field.',source:'hspa'},
  {id:'442',question:'Peel-pouch seal integrity testing should be performed:',options:['Only when a seal visibly appears damaged or compromised','Routinely at the start of each shift and after any adjustment to packaging equipment settings','Weekly as part of scheduled preventive maintenance','Only when a complaint about packaging quality is received from the OR'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Seal integrity testing must be routine — performed at shift start and after any packaging equipment change — to catch failures before processed items are distributed to user units.',source:'hspa'},
  {id:'443',question:'Polypropylene non-woven wrap is NOT appropriate for use in which sterilization method?',options:['Pre-vacuum (dynamic air removal) steam sterilization','Gravity displacement steam sterilization at standard cycle parameters','Hydrogen peroxide sterilization per the manufacturer\'s IFU','Low-temperature sterilization methods such as EO'],correct_answer:1,domain:'Packaging',difficulty:'hard',explanation:'Polypropylene non-woven wraps are validated for pre-vacuum sterilizers — gravity displacement cycles do not achieve adequate sterilant penetration through polypropylene under standard conditions.',source:'hspa'},
  {id:'444',question:'Indicator tape is used to seal sterile packages because it:',options:['Can substitute for any adhesive tape available in the facility','Serves as both a package seal and an external process indicator for the sterilization method used','Is more cost-effective than heat-sealing equipment for all package types','Is required by OSHA for all packaged materials used in healthcare settings'],correct_answer:1,domain:'Packaging',difficulty:'easy',explanation:'Indicator tape designed for the specific sterilization method seals the package and functions as an external chemical indicator — confirming the package was exposed to the sterilization process.',source:'hspa'},
  {id:'445',question:'A peel pouch should be filled to approximately what capacity level?',options:['100% — completely filled to minimize packaging material waste','No more than 75% of capacity to allow adequate sterilant circulation around instrument surfaces','50% to leave room for a protective inner wrap inside the pouch','As full as possible while the heat seal can still be completed cleanly'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Peel pouches should be filled to no more than approximately 75% capacity — leaving space allows sterilant to circulate freely around the instrument rather than being trapped against pouch walls.',source:'hspa'},
  {id:'446',question:'Rigid sterilization container filters must be:',options:['Replaced monthly on a fixed calendar schedule regardless of their condition','Inspected before each use and replaced per the manufacturer\'s validated schedule','Used until they show visible holes or physical damage','Replaced only after a positive biological indicator result in the associated load'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Container filters must be inspected before every use for integrity and replaced on the manufacturer\'s validated schedule — compromised filters invalidate the sterility of the contained items.',source:'hspa'},
  {id:'447',question:'Items should be labeled before sterilization with:',options:['The name of the patient who is scheduled to receive the instrumentation','Tray name, contents identification, and required tracking information','Only the sterilization date — other labeling is applied after the cycle is complete','No pre-sterilization labeling — labels are applied upon arrival in sterile storage'],correct_answer:1,domain:'Packaging',difficulty:'easy',explanation:'Items are labeled before sterilization with tray name, contents, and tracking identifiers. The external chemical indicator applied during packaging then confirms the item underwent the sterilization process.',source:'hspa'},
  {id:'448',question:'The closed-corner (envelope fold) wrapping technique is:',options:['The standard method for wrapping rigid instrument trays','Used only for wrapping soft goods such as linen towels and gowns','An outdated method replaced by sequential wrapping in all modern SPD practice','Required only for implants that will be sterilized using steam'],correct_answer:0,domain:'Packaging',difficulty:'medium',explanation:'The closed-corner envelope fold is the standard technique for wrapping rigid instrument trays — it creates secure sequential folds that maintain sterility and allow aseptic opening.',source:'hspa'},
  {id:'449',question:'Packaging materials must:',options:['Be used regardless of date since they function as sterile barriers indefinitely','Be used before their manufacturer-defined expiration date','Have expiration dates checked only when packaging high-risk implantable items','Only expire if stored in humid or temperature-extreme conditions'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'All packaging materials have manufacturer-defined expiration dates that must be respected — expired materials may no longer provide the validated barrier protection required for sterility maintenance.',source:'hspa'},
  {id:'450',question:'An external chemical indicator such as indicator tape on a package confirms:',options:['That sterility was definitively achieved inside the package','That the package was exposed to the sterilization process','That the biological indicator within the load was negative for growth','That the item may be dispensed directly to the sterile field without further verification'],correct_answer:1,domain:'Packaging',difficulty:'easy',explanation:'External CIs confirm the package was exposed to the sterilization process — they do NOT confirm sterility was achieved. Only a negative biological indicator confirms process efficacy.',source:'hspa'},
  {id:'451',question:'Hydrogen peroxide gas plasma sterilization is most appropriate for:',options:['Heat- and moisture-sensitive devices such as certain cameras and electronics','All surgical instruments regardless of material composition or lumen configuration','Items with very long, narrow lumens exceeding 6mm in internal diameter','Cellulose-based packaging materials such as paper wraps and towels'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Hydrogen peroxide gas plasma is ideal for heat- and moisture-sensitive devices. It cannot be used with cellulose materials or with very narrow, long lumens that cannot be adequately penetrated.',source:'hspa'},
  {id:'452',question:'Vaporized hydrogen peroxide (VHP) sterilization achieves its effect by:',options:['Applying high heat to denature microbial proteins throughout the load','Diffusing hydrogen peroxide vapor throughout the chamber to oxidize all microbial components','Releasing ethylene oxide gas under elevated chamber pressure','Generating a plasma field that produces high-energy reactive ions'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'VHP diffuses hydrogen peroxide vapor to contact and oxidize all microbial components without heat — making it suitable for heat-sensitive devices that cannot withstand steam sterilization.',source:'hspa'},
  {id:'453',question:'Peracetic acid liquid sterilization systems are most commonly used for:',options:['Terminal sterilization of wrapped rigid instrument sets in central processing','Immediate-use sterilization of heat-sensitive items such as certain flexible endoscopes','Dry heat sterilization of metal instruments and cutting edges in ophthalmic settings','Sterilization of implantable orthopedic devices and total joint components'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'Peracetic acid systems (e.g., Steris System 1E) provide immediate-use sterilization for heat-sensitive devices like endoscopes that cannot undergo terminal high-temperature sterilization.',source:'hspa'},
  {id:'454',question:'The aeration phase following ethylene oxide (EO) sterilization serves to:',options:['Cool sterilized items before staff handle them to prevent burns','Remove residual toxic EO gas from items to safe levels before patient use','Dry residual moisture from the sterilizer chamber walls and load','Confirm that the biological indicator incubation period is complete'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Aeration removes residual EO — a toxic and carcinogenic gas — from sterilized items. The aeration cabinet maintains temperature and air exchange to reduce EO to levels safe for patient contact.',source:'hspa'},
  {id:'455',question:'Implants sterilized in a steam sterilizer should be:',options:['Released immediately after the cycle if the external chemical indicator shows a color change','Quarantined until the biological indicator result confirms no microbial growth','Released based on the physical monitor printout data and cycle parameters alone','Released at the discretion of the senior technician when the OR needs them urgently'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'Implants must be quarantined until the BI result is confirmed negative — chemical indicators and physical monitors alone are insufficient to release implants due to the high patient risk.',source:'hspa'},
  {id:'456',question:'Dry heat sterilization is most appropriate for items that:',options:['Are heat-sensitive but compatible with moisture-based processes','Cannot be sterilized with moisture — such as anhydrous oils, powders, and petroleum products','Require the fastest possible turnaround in urgent surgical situations','Are made of materials compatible with steam but incompatible with EO exposure'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Dry heat is used for items damaged by moisture or not effectively penetrated by steam — such as petroleum products, oils, and powders that would be compromised by steam.',source:'hspa'},
  {id:'457',question:'A wet pack discovered after steam sterilization indicates:',options:['That the cycle achieved the correct temperature and pressure for the full exposure time','A sterilization failure requiring reprocessing of all affected items','Normal condensation that will evaporate safely during routine sterile storage','A successful Bowie-Dick test result confirming complete air removal from the load'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'A wet pack indicates a sterilization failure — moisture compromises the sterile barrier, allowing potential microbial contamination. All affected items must be reprocessed.',source:'hspa'},
  {id:'458',question:'The sterilizer manufacturer\'s Instructions for Use (IFU) defines:',options:['The maximum number of sterilization cycles before the sterilizer must be replaced','The validated parameters required to achieve sterility for items processed in that sterilizer','The AAMI standards applicable only to Class III implantable medical devices','The specific biological indicator brand validated for use with that sterilizer model'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'The sterilizer IFU establishes the validated parameters (temperature, time, exposure, packaging requirements) that must be followed — deviating from the IFU invalidates the sterilization process.',source:'hspa'},
  {id:'459',question:'A sterilizer should be removed from service when:',options:['Only when a biological indicator result is positive — and not for any other reason','Any monitoring system (physical, chemical, or biological) fails or a mechanical malfunction is detected','The unit is more than 10 years old per current AAMI maintenance guidelines','Visible external damage to the door handle or control panel is identified'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'A sterilizer must be removed from service when any monitoring mode fails or a malfunction is detected — all loads since the last successful monitoring must be recalled and reprocessed.',source:'hspa'},
  {id:'460',question:'Items loaded into a steam sterilizer should be arranged so that:',options:['The sterilizer is packed as tightly as possible to maximize load throughput','Items do not touch chamber walls and adequate space exists for steam to circulate freely','Wrapped packages are stacked directly on top of each other to reduce cycle count','Heavier items are positioned on upper shelves to allow condensate drainage downward'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Items must not contact chamber walls and must allow space for steam to circulate freely around all surfaces — overpacking prevents effective sterilization.',source:'hspa'},
  {id:'461',question:'Point-of-use treatment of instruments immediately after a surgical procedure means:',options:['Performing full decontamination in the operating room before transport','Removing gross soil immediately after use to prevent biofilm formation during transport to SPD','Soaking instruments in sterile saline until they arrive at the SPD decontamination area','Using a sterilizer located in or immediately adjacent to the OR suite for rapid reuse'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'Point-of-use treatment involves removing gross soil immediately — wiping, flushing, or moistening — to prevent biofilm development during transport. It is not a substitute for full decontamination.',source:'hspa'},
  {id:'462',question:'Cannulated (hollow-lumen) instruments require special cleaning attention because:',options:['They cannot be processed in washer-disinfectors under any circumstances','Lumens are difficult to access and can harbor biofilm if not flushed and brushed throughout their length','They are manufactured from softer alloys that react adversely to enzymatic cleaning agents','They are used exclusively in endoscopic procedures and therefore require high-level disinfection'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Lumens can harbor soil and biofilm that automated washing alone may not remove. All channels must be manually flushed and brushed with appropriately sized brushes to ensure thorough cleaning.',source:'hspa'},
  {id:'463',question:'The ultrasonic cleaner achieves cleaning through a process called:',options:['Mechanical spray impingement applied at high pressure throughout the chamber','Cavitation — microscopic imploding bubbles that dislodge soil from hard-to-reach surfaces','High-temperature thermal denaturation of organic soil on instrument surfaces','Chemical digestion by concentrated enzymatic solutions at elevated temperatures'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Cavitation — the formation and implosion of microscopic bubbles — dislodges soil from box locks, serrations, and joints inaccessible to mechanical scrubbing. The ultrasonic cleaner does not sterilize.',source:'hspa'},
  {id:'464',question:'The ultrasonic cleaner solution should be changed:',options:['Only when it appears visibly dirty or discolored during use','At regular intervals per manufacturer guidelines — at minimum daily during active use','Weekly regardless of usage volume or the number of loads processed','Only after cleaning heavily contaminated trauma or orthopedic instrument sets'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Ultrasonic solution must be changed per manufacturer guidelines — typically at least daily — as accumulated soil reduces cleaning efficacy and increases recontamination risk.',source:'hspa'},
  {id:'465',question:'Before activating the ultrasonic cleaner for a load of instruments, the technician should:',options:['Apply instrument lubricant to all box locks to protect surfaces during cavitation','Pre-rinse instruments to remove gross soil and degas the solution by running it briefly without instruments','Allow instruments to air dry fully to prevent diluting the cleaning solution concentration','Confirm the cleaning solution has reached sterilization temperature before loading'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Pre-rinsing removes gross soil that would rapidly contaminate the solution. Degassing — running the unit briefly without instruments — removes dissolved air that would otherwise dampen cavitation efficiency.',source:'hspa'},
  {id:'466',question:'Which cleaning method is generally NOT recommended for delicate ophthalmic microsurgical instruments?',options:['Gentle manual cleaning using soft-bristle brushes','Enzymatic pre-soak followed by careful manual cleaning and inspection','High-pressure automated spray washing in a standard washer-disinfector','Low-frequency ultrasonic cleaning per the instrument manufacturer\'s IFU'],correct_answer:2,domain:'Decontamination',difficulty:'hard',explanation:'High-pressure spray washing can permanently damage delicate ophthalmic instruments. These items typically require gentle manual cleaning or validated ultrasonic cleaning per specific manufacturer guidance.',source:'hspa'},
  {id:'467',question:'The quality of water used in the final rinse of a washer-disinfector is important because:',options:['Tap water is adequate for all rinse stages in modern validated washer-disinfectors','Poor-quality water can leave mineral deposits on instrument surfaces and introduce waterborne contaminants','The final rinse water must be sterile per AAMI ST79 requirements for reusable devices','Water quality only affects chemical sterilization methods and not steam sterilization outcomes'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Poor-quality water in the final rinse leaves mineral deposits and spotting on instruments and can introduce waterborne microorganisms. High-purity water (treated or deionized) is required for the final rinse.',source:'hspa'},
  {id:'468',question:'After successful decontamination, instruments should be considered:',options:['Sterile and safe for direct distribution to clinical areas and patient use','Decontaminated with a significantly reduced bioburden — not sterile — still requiring packaging and sterilization','Safe for immediate use in emergency situations when sterilization is not feasible','Disinfected to a level equivalent to high-level disinfection for semi-critical items'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'Decontamination significantly reduces bioburden but does NOT achieve sterility. Instruments must still be assembled, packaged, and subjected to a validated sterilization process before patient use.',source:'hspa'},
  {id:'469',question:'Pre-soaking instruments during decontamination is indicated when:',options:['Pre-soaking is never recommended in modern evidence-based SPD workflow','Immediate cleaning is not possible and gross soil has begun to dry and form biofilm','Only for orthopedic instruments with complex porous surface geometries','Only when the primary washer-disinfector is temporarily out of service for maintenance'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Pre-soaking prevents dried soil from hardening into biofilm when immediate cleaning is not possible — making subsequent cleaning more effective and reducing bioburden on instruments.',source:'hspa'},
  {id:'470',question:'Robotic surgical instruments require special cleaning attention because they:',options:['Are manufactured from materials incompatible with all water-based cleaning solutions','Have complex multi-channel lumens, delicate articulating joints, and highly specific manufacturer IFU requirements','Must be sterilized exclusively using ethylene oxide gas — no other method is acceptable','Are designed as single-use items and should not be reprocessed after any patient use'],correct_answer:1,domain:'Decontamination',difficulty:'hard',explanation:'Robotic instruments (e.g., da Vinci) have complex lumen systems, articulating wrists, and very specific IFUs. Failure to follow them exactly results in residual soil, inadequate sterilization, and patient risk.',source:'hspa'}
,
  {id:'471',question:'Which of the following statements about emergency eyewash stations is TRUE?',options:['They are only needed in the decontamination area.','Plumbed eyewash stations are the only type available.','Testing of the eyewash unit should be performed yearly.','An eyewash unit should not be installed on a decontamination sink.'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'medium',explanation:'OSHA requires annual certification/testing of eyewash stations to ensure they function properly in emergencies. Options A and D are incorrect because eyewash stations are needed in multiple areas and can be mounted on decontamination sinks; B is incorrect because both plumbed and portable eyewash units exist.'},
  {id:'472',question:'Control of emissions into the air and water is regulated by the:',options:['Food and Drug Administration.','Environmental Protection Agency.','Occupational Safety and Health Administration.','Centers for Disease Control and Prevention.'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The EPA specifically regulates emissions into air and water under environmental protection laws. FDA regulates drugs/devices, OSHA handles workplace safety, and CDC controls disease transmission—none regulate environmental emissions.'},
  {id:'473',question:'Ethics is the practice of:',options:['Doing the right thing.','Dealing with what is bad.','Not recognizing cultural beliefs.','Discussing patient issues with friends.'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Ethics is fundamentally about doing the right thing and making morally sound decisions. Options B-D are incorrect because ethics actively recognizes cultural beliefs, isn\'t just about bad behavior, and strictly prohibits discussing patient issues with unauthorized people.'},
  {id:'474',question:'Compliance with Occupational Safety and Health Administration regulations is:',options:['Optional.','Required by law.','Recommended whenever there is time.','Doing what you want to do.'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'medium',explanation:'OSHA compliance is mandated by federal law and not optional for healthcare facilities. Options A, C, and D are all incorrect because compliance is mandatory, must occur regardless of time availability, and is not discretionary.'},
  {id:'475',question:'Which of the following establishes sterilization practice standards based on opinion, research, and/or theory?',options:['Occupational Safety and Health Administration','Association for the Advancement of Medical Instrumentation','Environmental Protection Agency','Food and Drug Administration'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'medium',explanation:'AAMI establishes sterilization standards based on opinion, research, and theory rather than legal mandate. OSHA and EPA issue regulations, while FDA approves devices but doesn\'t establish sterilization practice standards in this manner.'},
  {id:'476',question:'Recommended practices are:',options:['Documents that reflect state and federal regulations.','Principles, laws, or rules designed to govern behavior.','Established norms determined by opinion, authority, research, and/or theory.','Statements of sound principles of practice that are based on scientific data and the opinions of experts.'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Recommended practices are specifically based on scientific data and expert opinions rather than laws or legal requirements. Options A and B describe regulations/standards (which are legally binding), while C is too vague about the source.'},
  {id:'477',question:'The Environmental Protection Agency, Food and Drug Administration, Occupational Safety and Health Administration, and State Departments of Health primarily issue:',options:['Standards','Regulations','Professional practices','Recommended practices'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Government agencies like EPA, FDA, OSHA, and State Departments of Health issue regulations—enforceable legal requirements. Standards are developed by professional organizations, and recommended practices are professional guidelines rather than legal mandates.'},
  {id:'478',question:'Standards for sterile processing practice are developed by the:',options:['Food and Drug Administration.','Environmental Protection Agency.','State Departments of Health.','Association for the Advancement of Medical Instrumentation.'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'AAMI develops sterilization practice standards based on research and expert consensus. FDA regulates devices, EPA focuses on environmental protection, and State Departments of Health implement but don\'t develop national standards.'},
  {id:'479',question:'The Health Insurance Portability and Accountability Act provides for which ethical issue?',options:['Confidentiality','Employee rights','Cultural diversity','Theft of hospital property'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'medium',explanation:'HIPAA specifically addresses the confidentiality and privacy of protected health information in healthcare settings. Employee rights are OSHA\'s domain, cultural diversity is not HIPAA\'s focus, and theft is not HIPAA\'s primary concern.'},
  {id:'480',question:'Which of the following classes of fire extinguishers would be used for an electrical equipment fire?',options:['Class A','Class B','Class C','Class D'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Class C fire extinguishers are specifically designed for electrical equipment fires because they use non-conductive agents. Class A is for ordinary combustibles, B for flammable liquids, and D for combustible metals.'},
  {id:'481',question:'An established norm which is based on theory is called a:',options:['Policy','Standard','Regulation','Recommended practice'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'medium',explanation:'A standard is an established norm based on theory, research, and opinion without legal mandate. Policies are specific guidelines, regulations are legally mandated requirements, and recommended practices are professional guidelines.'},
  {id:'482',question:'Before a pesticide can be marketed and used in the United States, it must be evaluated and registered by which of the following?',options:['Food and Drug Administration','Environmental Protection Agency','Occupational Safety and Health Administration','Centers for Disease Control and Prevention'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The EPA evaluates and registers pesticides before they can be marketed in the US under the Federal Insecticide, Fungicide, and Rodenticide Act. FDA regulates drugs/devices, OSHA handles workplace safety, and CDC controls disease.'},
  {id:'483',question:'Chemical and biological indicators must be cleared by which of the following agencies?',options:['Food and Drug Administration','Environmental Protection Agency','Centers for Disease Control and Prevention','Occupational Safety and Health Administration'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The FDA clears chemical and biological indicators as medical devices to ensure their reliability for sterilization validation. EPA, CDC, and OSHA do not regulate medical device indicators.'},
  {id:'484',question:'If healthcare facilities reprocess single-use devices, the devices must be cleared by the:',options:['Food and Drug Administration','Occupational Safety and Health Administration','Environmental Protection Agency','Centers for Disease Control and Prevention'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The FDA must clear the reprocessing of single-use devices through a 510(k) or other approval pathway before facilities can legally reprocess them. OSHA, EPA, and CDC do not have authority over medical device reprocessing approval.'},
  {id:'485',question:'For hazardous chemicals, the blue diamond represents which type of hazard?',options:['Health','Flammability','Instability','Special hazard'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'medium',explanation:'In the NFPA 704 hazard diamond, the blue diamond represents health hazards. Red represents flammability, yellow represents instability/reactivity, and white represents special hazards.'},
  {id:'486',question:'Which of the following statements is TRUE?',options:['An implant is considered a critical device.','A cardiac catheter is a semicritical device.','A bronchoscope is considered a noncritical device.','A blood pressure cuff is a semicritical device.'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Implants are critical items requiring sterilization because they enter sterile tissues/bloodstream; cardiac catheters and bronchoscopes are actually critical/semicritical respectively, and blood pressure cuffs are noncritical items.'},
  {id:'487',question:'The Medical Device Reporting regulation requires:',options:['Sterile processing employees to report all work-related injuries.','Healthcare facilities to register single-use devices to be reprocessed.','Sterile processing employees to report failure to wear personal PPE.','Healthcare facilities to report deaths or serious injuries from medical devices.'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'MDR requires healthcare facilities to report deaths or serious injuries associated with medical device use to the FDA. Work injuries are OSHA\'s domain, SUD registration is separate FDA requirement, and PPE violations are OSHA concerns.'},
  {id:'488',question:'Which agency requires that eyewash stations be available for emergency use?',options:['Association for the Advancement of Medical Instrumentation','Food and Drug Administration','Centers for Disease Control and Prevention','Occupational Safety and Health Administration'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'OSHA\'s Bloodborne Pathogens Standard specifically requires eyewash stations be readily available for emergency eye flushing in areas with chemical/biological exposure. AAMI develops standards, FDA and CDC do not mandate this equipment.'},
  {id:'489',question:'The SPD Loaned Instrument policy should specify:',options:['How to process the loaned instruments.','The time frame during which the instruments should be delivered.','That the weight of each set cannot exceed 30 pounds.','The maximum number of trays that can be delivered.'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The loaned instrument policy\'s primary purpose is to specify processing procedures to ensure instruments meet the facility\'s sterilization standards before use. Delivery timeframes, weight limits, and tray quantity limits are secondary operational details.'},
  {id:'490',question:'The Occupational Safety and Health Administration\'s Hazard Communication Standard requires that an SDS (Safety Data Sheet) must be available for which of the following?',options:['All instrument trays','All packaging material','Chemicals that can harm you','Each chemical in the department'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'OSHA\'s Hazard Communication Standard requires an SDS be available for each individual chemical used in the department regardless of quantity. SDSs are not required for trays or packaging materials themselves.'},
  {id:'491',question:'To comply with the Occupational Safety and Health Administration\'s Hazard Communication Standard (Right-to-Know Standard), employers must ensure that which of the following is available for employees?',options:['Emergency eyewash stations','Information on exposure limits for ethylene oxide','Bloodborne pathogen exposure plan','Safety Data Sheets for chemicals'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The Hazard Communication Standard specifically requires employers to provide Safety Data Sheets (SDS) so employees understand chemical hazards and exposure information. Emergency eyewash stations, bloodborne pathogen plans, and exposure limits are separate requirements or components of SDS, not the primary HCS requirement.'},
  {id:'492',question:'Any injury to an employee, no matter how slight, should be:',options:['Examined by a physician.','Checked by Infection Prevention.','Documented in an incident report.','Documented by the emergency room nurse.'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'medium',explanation:'All injuries must be documented in incident reports regardless of severity to track safety trends and ensure accountability. Medical examination by a physician, infection prevention review, or ER documentation may not occur for minor injuries but incident reporting is mandatory.'},
  {id:'493',question:'Which of the following defines what a department must do?',options:['Policies','Standards','Procedures','Recommended practices'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Policies establish mandatory requirements and define what departments must do, while standards are guidelines, procedures explain how to implement them, and recommended practices are optional suggestions.'},
  {id:'494',question:'For fire safety, SPD personnel should know:',options:['At least one means of exit from the area.','The location of two fire alarm pull boxes.','That fire doors can be propped open during the night hours.','The three classifications of fire extinguishers.'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Knowing at least one evacuation route is essential for personal safety during emergencies. Multiple fire alarm locations aren\'t required, fire doors must never be propped open as a fire hazard, and not all staff need to memorize all extinguisher classifications.'},
  {id:'495',question:'Any equipment with an electrical cord that is cracked, frayed, or broken should be:',options:['Thrown away.','Sent out for repair.','Cleaned and distributed.','Disinfected and sent out for repair.'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Damaged electrical cords are electrical hazards requiring professional repair rather than disposal, cleaning, or disinfection, as the structural damage creates safety risks that cleaning cannot resolve.'},
  {id:'496',question:'Which branch of science refers to the form and organization of body parts?',options:['Biology','Anatomy','Physiology','Microbiology'],correct_answer:1,domain:'Anatomy',difficulty:'medium',explanation:'Anatomy is the branch of science studying the structure and organization of body parts. Physiology studies function, biology is general life science, and microbiology studies microorganisms.'},
  {id:'497',question:'Which branch of science refers to the function of specific body parts?',options:['Biology','Anatomy','Physiology','Microbiology'],correct_answer:2,domain:'Anatomy',difficulty:'medium',explanation:'Physiology specifically examines how body parts function and their mechanisms of action. Anatomy studies structure, biology is broader, and microbiology focuses on microorganisms.'},
  {id:'498',question:'The smallest and most numerous structural units possessing the basic characteristics of life are called:',options:['Cells','Tissues','Organs','Systems'],correct_answer:0,domain:'Anatomy',difficulty:'medium',explanation:'Cells are the smallest units that possess all characteristics of life and self-replication capability. Tissues, organs, and systems are progressively larger organizational structures composed of multiple cells.'},
  {id:'499',question:'Which of the following is the most abundant substance in the body?',options:['Blood','Water','Sodium','Potassium'],correct_answer:1,domain:'Anatomy',difficulty:'medium',explanation:'Water comprises 60-70% of body weight and is essential for all metabolic and physiological functions. Blood, sodium, and potassium exist in much smaller quantities.'},
  {id:'500',question:'In which part of the cell are genes and DNA located?',options:['Nucleus','Cytoplasm','Cell wall','Cell membrane'],correct_answer:0,domain:'Anatomy',difficulty:'medium',explanation:'The nucleus is the membrane-bound organelle that contains chromosomes with DNA and genes. Cytoplasm surrounds the nucleus, the cell membrane is the outer boundary, and the cell wall is only in plant cells.'},
  {id:'501',question:'In which part of the cell are food molecules received, processed, and used?',options:['Cell wall','Cytoplasm','Cell membrane','Nuclear membrane'],correct_answer:1,domain:'Anatomy',difficulty:'medium',explanation:'The cytoplasm is the gel-like substance where cellular metabolism, food processing, and energy production occur. The cell membrane is a boundary, cell wall is in plants, and the nuclear membrane surrounds the nucleus.'},
  {id:'502',question:'Complex structures with specialized functions within the body are known as:',options:['Cell wall','Cytoplasm','Cell membrane','Nuclear membrane'],correct_answer:2,domain:'Anatomy',difficulty:'medium',explanation:'The cell membrane provides the structural boundary and controls what enters/exits the cell, serving the specialized function of selective permeability. The other options are also cellular structures but the membrane is the defining structure of a cell.'},
  {id:'503',question:'Red blood cells develop in which part of the body?',options:['Heart','Spleen','Gall bladder','Bone marrow'],correct_answer:3,domain:'Anatomy',difficulty:'medium',explanation:'Red blood cells are produced in bone marrow through hematopoiesis. The heart pumps blood, the spleen stores and filters RBCs, and the gallbladder stores bile, none of which produce RBCs.'},
  {id:'504',question:'Which of the following statements is TRUE about the ear?',options:['It contains no membranes.','There are four bones in the middle ear.','The malleus is one of the middle ear bones.','The Eustachian tube connects the outer ear to the middle ear.'],correct_answer:2,domain:'Anatomy',difficulty:'medium',explanation:'The malleus is one of the three ossicles (middle ear bones); the other options are false because the ear has membranes, contains three (not four) bones, and the Eustachian tube connects the middle ear to the nasopharynx, not the outer ear.'},
  {id:'505',question:'Which of the following supports the tongue and functions in swallowing?',options:['Skull','Vertebrae','Hyoid bone','Thoracic cage'],correct_answer:2,domain:'Anatomy',difficulty:'medium',explanation:'The hyoid bone is a horseshoe-shaped bone that suspends and supports the tongue and assists in swallowing. The skull, vertebrae, and thoracic cage serve other skeletal functions.'},
  {id:'506',question:'Which of the following best defines the system level of organization in the human body?',options:['Structures of cells that exhibit the basic characteristics of life','A group of similar cells that develop together to perform a certain function','A structure made of several kinds of tissues that together perform a special function','Various numbers and kinds of organs which together perform complex functions for the body'],correct_answer:3,domain:'Anatomy',difficulty:'medium',explanation:'A body system consists of multiple organs of different types working together to perform complex functions, which is the highest level of structural organization. Individual cells, tissues, and organs represent lower organizational levels.'},
  {id:'507',question:'Which of the following is the longest bone in the body?',options:['Tibia','Radius','Femur','Sternum'],correct_answer:2,domain:'Anatomy',difficulty:'medium',explanation:'The femur (thighbone) is the longest and strongest bone in the human body. The tibia and fibula are in the lower leg, and the radius is in the forearm.'},
  {id:'508',question:'The femur, tibia, and fibula are bones of the:',options:['Upper limbs','Pelvic girdle','Lower limbs','Pectoral girdle'],correct_answer:2,domain:'Anatomy',difficulty:'medium',explanation:'The femur, tibia, and fibula are all located in the lower limbs (legs). The upper limbs contain the humerus, radius, and ulna; the pelvic and pectoral girdles are different skeletal regions.'},
  {id:'509',question:'The humerus, radius, and ulna are bones of the:',options:['Upper limbs','Pelvic girdle','Lower limbs','Pectoral girdle'],correct_answer:0,domain:'Anatomy',difficulty:'medium',explanation:'The humerus, radius, and ulna are all located in the upper limbs (arms). The lower limbs contain the femur, tibia, and fibula; the pelvic and pectoral girdles are different skeletal regions.'},
  {id:'510',question:'Which of the following statements is TRUE regarding smooth muscles?',options:['Require voluntary control to contract.','Usually cannot be consciously stimulated.','Are faster to contract and relax.','Contain striations.'],correct_answer:1,domain:'Anatomy',difficulty:'medium',explanation:'Smooth muscle is involuntary and cannot be consciously controlled, unlike skeletal muscle. Smooth muscle contracts slowly, lacks striations, and lines internal organs and blood vessels where conscious control is unnecessary.'},
  {id:'511',question:'Cardiac muscle:',options:['Is fibrous.','Is striated.','Contracts under conscious control.','Contracts involuntarily.'],correct_answer:3,domain:'Anatomy',difficulty:'medium',explanation:'Cardiac muscle is involuntary, controlled by the autonomic nervous system and specialized conducting tissue (not conscious thought). Options A, B, C incorrectly describe cardiac muscle as fibrous, striated, or consciously controlled—while cardiac muscle is indeed striated, only option D captures the functional distinction that matters: it contracts without voluntary control.'},
  {id:'512',question:'Specialized cells responsible for contractions in the body are called:',options:['Skin','Bones','Nerves','Muscles'],correct_answer:3,domain:'Anatomy',difficulty:'medium',explanation:'Muscles are the specialized tissues composed of contractile cells designed specifically for contraction and movement. Skin, bones, and nerves serve other functions; only muscles are specialized for generating contractions.'},
  {id:'513',question:'Which of the following is the largest organ of the human body?',options:['Skin','Liver','Heart','Colon'],correct_answer:0,domain:'Anatomy',difficulty:'medium',explanation:'The skin is the largest organ by surface area, covering the entire external body surface. The liver, heart, and colon are internal organs that are significantly smaller by both mass and surface area.'},
  {id:'514',question:'Which of the following is responsible for providing immunity?',options:['White blood cells','Red blood cells','Hormones','Platelets'],correct_answer:0,domain:'Anatomy',difficulty:'medium',explanation:'White blood cells (leukocytes) are the primary immune cells that fight infections and provide immunity. Red blood cells carry oxygen, hormones are regulatory molecules, and platelets function in blood clotting—none directly provide immunity.'},
  {id:'515',question:'How many layers are in the integumentary system?',options:['One','Two','Three','Four'],correct_answer:1,domain:'Anatomy',difficulty:'medium',explanation:'The integumentary system consists of two main layers: the epidermis (outer) and dermis (inner). While the subcutaneous tissue/hypodermis lies beneath, the standard anatomical answer is two primary layers.'},
  {id:'516',question:'Which of the following statements is TRUE regarding the respiratory system?',options:['Filters, warms, and humidifies the air breathed in.','Supplies carbon dioxide to the cells of the body.','Carries hormones from their site of origin to distant tissues.','Aids in the clotting of blood when vessels are damaged.'],correct_answer:0,domain:'Anatomy',difficulty:'medium',explanation:'The upper respiratory tract (nasal passages, pharynx, larynx) filters, warms, and humidifies incoming air before it reaches the lungs. Option B reverses gas exchange (removes CO₂, supplies O₂); C describes the endocrine system; D is a platelet function.'},
  {id:'517',question:'Which of the following transports food to the stomach?',options:['Tongue','Larynx','Pharynx','Esophagus'],correct_answer:3,domain:'Anatomy',difficulty:'medium',explanation:'The esophagus is the muscular tube that transports the bolus (food) from the pharynx to the stomach. The tongue and larynx are in the mouth/throat; the pharynx initiates swallowing but the esophagus performs the transport.'},
  {id:'518',question:'Which organ produces bile?',options:['Gallbladder','Large intestine','Small intestine','Liver'],correct_answer:3,domain:'Anatomy',difficulty:'medium',explanation:'The liver produces bile, which is stored in the gallbladder and aids in fat digestion. The gallbladder stores (not produces) bile; the large and small intestines absorb nutrients and water but don\'t produce bile.'},
  {id:'519',question:'The entire delicate central nervous system is protected by:',options:['Fluid','Muscle','Fatty tissue','Bony encasements'],correct_answer:3,domain:'Anatomy',difficulty:'medium',explanation:'The central nervous system (brain and spinal cord) is protected by bony encasements: the skull protects the brain and the vertebral column protects the spinal cord. Fluid, muscle, and fatty tissue provide additional cushioning but the primary protection is bone.'},
  {id:'520',question:'The tympanic membrane is located in the:',options:['Ear','Eye','Nose','Throat'],correct_answer:0,domain:'Anatomy',difficulty:'medium',explanation:'The tympanic membrane (eardrum) is located in the middle ear canal, part of the ear structure. The eye, nose, and throat are separate sensory organs.'},
  {id:'521',question:'The seminal vesicles and bulbourethral glands are part of the:',options:['Sensory system','Endocrine system','Male reproductive system','Female reproductive system'],correct_answer:2,domain:'Anatomy',difficulty:'medium',explanation:'The seminal vesicles and bulbourethral glands are accessory organs of the male reproductive system that secrete components of seminal fluid. They are not part of the sensory, endocrine, or female reproductive systems.'},
  {id:'522',question:'The deltoid muscle is located in the:',options:['Thigh','Back','Upper arm','Lower leg'],correct_answer:2,domain:'Anatomy',difficulty:'medium',explanation:'The deltoid is the large triangular muscle of the shoulder that covers the upper arm area. The thigh contains the quadriceps, the back has the latissimus dorsi, and the lower leg has the gastrocnemius.'},
  {id:'523',question:'The surgical procedure known as mediastinoscopy would be performed on the:',options:['Abdomen','Gallbladder','Chest','Ileum'],correct_answer:2,domain:'Anatomy',difficulty:'medium',explanation:'Mediastinoscopy is the visual examination of the mediastinum (central chest cavity between the lungs), making it a procedure performed on the chest. The abdomen, gallbladder, and ileum are separate body regions.'},
  {id:'524',question:'The term "pathogenic" means:',options:['Contagious.','Fermentation.','Poisonous vapors.','Disease-producing.'],correct_answer:3,domain:'Microbiology',difficulty:'medium',explanation:'"Pathogenic" literally means disease-producing (patho = disease; genic = producing). Contagious relates to transmission (not the definition), fermentation is an unrelated process, and poisonous vapors reflects the discredited miasma theory.'},
  {id:'525',question:'What color do Gram-positive microorganisms stain?',options:['Red or pink','Blue or purple','Black or brown','Yellow or green'],correct_answer:1,domain:'Microbiology',difficulty:'medium',explanation:'Gram-positive bacteria retain the crystal violet stain and appear blue or purple under the microscope. Red/pink indicates gram-negative bacteria; black/brown and yellow/green are incorrect staining colors.'},
  {id:'526',question:'What color do Gram-negative microorganisms stain?',options:['Red or pink','Blue or purple','Black or brown','Yellow or green'],correct_answer:0,domain:'Microbiology',difficulty:'medium',explanation:'Gram-negative bacteria cannot retain the primary crystal violet stain and appear red or pink when counterstained with safranin. Blue/purple indicates gram-positive bacteria; other colors are incorrect.'},
  {id:'527',question:'Microorganisms are measured in:',options:['Inches','Microns','Molecules','Millimeters'],correct_answer:1,domain:'Microbiology',difficulty:'medium',explanation:'Microns (micrometers, μm) are the standard unit for measuring microscopic organisms and cells. Inches and millimeters are too large; molecules are too small for typical microorganism measurement.'},
  {id:'528',question:'The shape of the Streptococcus is:',options:['Spiral','Rod-like','Flagella-like','Spherical'],correct_answer:3,domain:'Microbiology',difficulty:'medium',explanation:'Streptococcus bacteria are spherical (round) cocci, typically arranged in chains. Spiral describes spirilla; rod-like describes bacilli; flagella-like describes flagella (appendages, not bacterial shapes).'},
  {id:'529',question:'The shape of a spirochete is:',options:['Oval','Corkscrew','Round','Spherical'],correct_answer:1,domain:'Microbiology',difficulty:'medium',explanation:'Spirochetes have a distinctive corkscrew or spiral shape that enables them to move through tissues and mucous membranes. Other bacterial shapes include cocci (round), bacilli (rod), and others, but spirochetes are uniquely corkscrew-shaped.'},
  {id:'530',question:'Bacteria are unicellular and reproduce by:',options:['Metabolism','Binary fission','Pasteurization','Photosynthesis'],correct_answer:1,domain:'Microbiology',difficulty:'medium',explanation:'Bacteria reproduce asexually through binary fission, where one cell divides into two identical daughter cells. Metabolism is energy acquisition, pasteurization is a sterilization method, and photosynthesis is an energy pathway—none are reproductive mechanisms.'},
  {id:'531',question:'Which type of microorganism has the ability to slow down its metabolism and become dormant?',options:['Gram-negative bacillus','Gram-positive bacillus','Gram-negative virus','Gram-positive virus'],correct_answer:1,domain:'Microbiology',difficulty:'medium',explanation:'Gram-positive bacilli (like Bacillus species) form protective spores that enable dormancy and slowed metabolism. Gram-negative bacilli lack this spore-forming ability, and viruses are acellular with no independent metabolism.'},
  {id:'532',question:'Rod-shaped bacteria are called:',options:['Flagella','Cocci','Bacilli','Spiral'],correct_answer:2,domain:'Microbiology',difficulty:'medium',explanation:'Bacilli is the correct morphological term for rod-shaped bacteria. Flagella are motility structures, cocci are round bacteria, and spiral describes a different shape.'},
  {id:'533',question:'Which of the following is a slimy, waxy layer that can form on the outside of a cell wall?',options:['Capsule','Enterotoxin','Endospore','Lipid'],correct_answer:0,domain:'Microbiology',difficulty:'medium',explanation:'A capsule is the slimy, gelatinous outer layer surrounding bacterial cell walls. Enterotoxin is a bacterial toxin, endospore is a dormant structure, and lipids are molecular components.'},
  {id:'534',question:'Which of the following is used to test the effectiveness of sterilization cycles?',options:['Vegetative bacteria','Mycobacteria','Spores','Prions'],correct_answer:2,domain:'Microbiology',difficulty:'medium',explanation:'Spores are the most resistant microorganisms and serve as biological indicators to validate sterilization efficacy. Vegetative bacteria are easily destroyed; mycobacteria and prions are not standard indicators.'},
  {id:'535',question:'A dehydrated microorganism with a thick, shell-like wall is known as a:',options:['Capsule','Spore','Prion','Fungus'],correct_answer:1,domain:'Microbiology',difficulty:'medium',explanation:'A spore is a dehydrated, dormant microbial form with a thick protective wall designed for extreme resistance. Capsule is an outer layer, prion is a protein, and fungus is an organism class.'},
  {id:'536',question:'Which of the following can survive extreme heat, lack of water, and exposure to many toxic chemicals and radiation?',options:['Spores','Viruses','Prions','Fungi'],correct_answer:0,domain:'Microbiology',difficulty:'medium',explanation:'Spores possess the highest resistance to extreme heat, desiccation, chemicals, and radiation due to their protective shell structure. Viruses, prions, and fungi lack this comprehensive resistance profile.'},
  {id:'537',question:'In order to survive, aerobic bacteria require:',options:['Oxygen','Liquids','Cold','Light'],correct_answer:0,domain:'Microbiology',difficulty:'medium',explanation:'Aerobic bacteria require oxygen for cellular respiration and energy production; this is the defining characteristic of aerobic organisms. Liquids, cold, and light are not metabolic requirements.'},
  {id:'538',question:'Creutzfeldt-Jakob Disease (CJD) is caused by:',options:['Bacteria','Protozoa','Viruses','Prions'],correct_answer:3,domain:'Microbiology',difficulty:'medium',explanation:'CJD is a neurodegenerative disease caused by prions (misfolded proteins), not infectious agents like bacteria, protozoa, or viruses.'},
  {id:'539',question:'Protozoa are:',options:['Single-celled microorganisms','Double-celled microorganisms','Multiple-celled microorganisms','Non-celled microorganisms'],correct_answer:0,domain:'Microbiology',difficulty:'medium',explanation:'Protozoa are eukaryotic single-celled organisms, distinguishing them from multicellular or non-cellular pathogens.'},
  {id:'540',question:'Which of the following pathogens causes tuberculosis?',options:['Mycobacteria','Protozoa','Viruses','Prions'],correct_answer:0,domain:'Microbiology',difficulty:'medium',explanation:'Mycobacterium tuberculosis specifically causes tuberculosis; protozoa, viruses, and prions do not cause this bacterial infection.'},
  {id:'541',question:'Which of the following is TRUE of fungi?',options:['All types have flagella.','They are all microscopic.','They include single-celled yeasts.','They absorb matter through the nucleus.'],correct_answer:2,domain:'Microbiology',difficulty:'medium',explanation:'Fungi include single-celled yeasts (like Candida and Saccharomyces) alongside multicellular molds. Not all fungi have flagella, not all are microscopic, and absorption occurs through the cell membrane, not nucleus.'},
  {id:'542',question:'Which of the following diseases is NOT caused by a virus?',options:['Herpes','Poliomyelitis','AIDS (acquired immune deficiency syndrome)','CJD (Creutzfeldt-Jakob disease)'],correct_answer:3,domain:'Microbiology',difficulty:'medium',explanation:'CJD is caused by prions (abnormal proteins), not viruses; herpes, poliomyelitis, and AIDS are all viral diseases.'},
  {id:'543',question:'Influenza is caused by a:',options:['Bacteria','Yeast','Virus','Prion'],correct_answer:2,domain:'Microbiology',difficulty:'medium',explanation:'Influenza is caused by influenza viruses (orthomyxoviruses), not bacteria, yeast, or prions.'},
  {id:'544',question:'Which of the following best describes a prion?',options:['An abnormal protein','A single-celled yeast','An aerobic mycobacterium','A single-celled microorganism'],correct_answer:0,domain:'Microbiology',difficulty:'medium',explanation:'A prion is fundamentally an abnormal, misfolded protein that causes conformational disease; it is not a cellular organism, yeast, or mycobacterium.'},
  {id:'545',question:'Which of the following statements about bacteria is TRUE?',options:['Round-shaped bacteria belong to the bacillus group.','Only bacilli cause infections in humans.','All bacteria need cool temperatures to live.','Bacteria are unicellular.'],correct_answer:3,domain:'Microbiology',difficulty:'medium',explanation:'Bacteria are unicellular prokaryotes; round bacteria are cocci (not bacilli), not all cause infections, and temperature requirements vary by species.'},
  {id:'546',question:'Vancomycin-resistant enterococcus can survive on hard surfaces for 5 to 7 days and on the hands for:',options:['Days','Weeks','Hours','Minutes'],correct_answer:0,domain:'Microbiology',difficulty:'medium',explanation:'VRE survives on hands for days (shorter duration than hard surfaces\' 5-7 days but longer than hours/minutes), reflecting its moderate persistence on skin.'},
  {id:'547',question:'It is estimated that one in how many patients a day acquire at least one healthcare-associated infection?',options:['10','15','25','50'],correct_answer:2,domain:'Infection Prevention',difficulty:'medium',explanation:'Approximately 1 in 25 patients daily acquire healthcare-associated infections, emphasizing the critical importance of proper sterilization and infection control practices.'},
  {id:'548',question:'The ability of the body to specifically counteract antigens refers to:',options:['Defense','Resistance','Immunity','Pathogenicity'],correct_answer:2,domain:'Infection Prevention',difficulty:'medium',explanation:'Immunity specifically refers to the body\'s targeted immune response against particular antigens. Defense and resistance are general/nonspecific, and pathogenicity is disease-causing ability.'},
  {id:'549',question:'The principal living reservoir of human disease is:',options:['Wild animals','The human body','Reptiles','Sheep and cattle'],correct_answer:1,domain:'Infection Prevention',difficulty:'medium',explanation:'Humans serve as the principal living reservoir for human pathogens, despite animals potentially harboring some zoonotic diseases.'},
  {id:'550',question:'Water that has been contaminated by the feces of humans and other animals is most notably responsible for:',options:['Herpes','Ringworm','Respiratory disease','Gastrointestinal disease'],correct_answer:3,domain:'Infection Prevention',difficulty:'medium',explanation:'Fecal-contaminated water transmits enteric pathogens causing gastrointestinal disease; the other conditions are not characteristically spread this way.'},
  {id:'551',question:'The principal route of transmission of healthcare-associated infections is:',options:['Coughing','Sneezing','Direct contact','Faulty housekeeping'],correct_answer:2,domain:'Infection Prevention',difficulty:'medium',explanation:'Direct contact is the primary transmission route for HAIs in healthcare settings; respiratory droplet transmission (coughing/sneezing) and housekeeping are secondary factors.'},
  {id:'552',question:'The general term for any inanimate object involved in the spread of infection is:',options:['Fomite','Vector','Axon','Cell'],correct_answer:0,domain:'Infection Prevention',difficulty:'medium',explanation:'Fomite is the medical term for inanimate objects that transmit infection; vectors are living organisms, while cells and axons are biological structures not involved in transmission.'},
  {id:'553',question:'Living things responsible for causing disease are called:',options:['Cells','Fomites','Vectors','Droplets'],correct_answer:2,domain:'Infection Prevention',difficulty:'medium',explanation:'Vectors are living organisms (insects, animals) that transmit pathogens; fomites are inanimate objects and droplets are non-living particles.'},
  {id:'554',question:'One of the most common portals of exit in the transmission of disease is:',options:['Intact skin','Conjunctiva','Parenteral tissue','Skin'],correct_answer:0,domain:'Infection Prevention',difficulty:'medium',explanation:'Skin can be a portal of exit through natural shedding of microorganisms; conjunctiva and parenteral tissue are not primary exit routes for most diseases.'},
  {id:'555',question:'An infection caused by a needlestick enters through which portal of entry?',options:['Intact skin','Conjunctiva','Parenteral tissue','The respiratory tract'],correct_answer:1,domain:'Infection Prevention',difficulty:'medium',explanation:'Parenteral entry occurs through skin-breaching injuries like needlesticks; conjunctiva (eye membrane) and respiratory tract are not affected by needlestick injuries.'},
  {id:'556',question:'Lyme disease is generally transmitted by:',options:['Vectors','Fomites','Vehicles','Droplets'],correct_answer:0,domain:'Infection Prevention',difficulty:'medium',explanation:'Lyme disease is transmitted by infected ticks; fomites, vehicles, and droplets are inanimate transmission methods that cannot transmit Lyme disease.'},
  {id:'557',question:'The sterile processing technician does NOT have an impact on which of the following elements of the chain of infection?',options:['Portal of entry','Pathogenic organisms','Reservoir of infection','Susceptible host'],correct_answer:3,domain:'Infection Prevention',difficulty:'medium',explanation:'SPD technicians impact sterilization, decontamination, and infection control practices but cannot influence a patient\'s immune status or susceptibility to infection.'},
  {id:'558',question:'Unless the water turns off automatically after handwashing, the water should be:',options:['Left running.','Turned off using your elbow.','Turned off using your right wrist.','Turned off using a disposable towel.'],correct_answer:3,domain:'Infection Prevention',difficulty:'medium',explanation:'Using a disposable towel prevents recontamination of clean hands after washing; elbows are awkward for turning off water and wrists risk recontamination.'},
  {id:'559',question:'Bloodborne pathogen exposure is regulated by the:',options:['Occupational Safety and Health Administration','Centers for Disease Control and Prevention','Food and Drug Administration','Environmental Protection Agency'],correct_answer:0,domain:'Infection Prevention',difficulty:'medium',explanation:'OSHA regulates bloodborne pathogen exposure in occupational settings; CDC issues guidelines, FDA regulates medical devices, and EPA addresses environmental concerns.'},
  {id:'560',question:'Which concentration is most effective in alcohol-based hand sanitizers?',options:['10% to 35%','60% to 95%','75% to 100%','50% to 75%'],correct_answer:1,domain:'Infection Prevention',difficulty:'medium',explanation:'Alcohol concentrations of 60-95% are most antimicrobially effective; lower concentrations are insufficient and higher concentrations unnecessarily concentrated.'},
  {id:'561',question:'Under Standard Precautions, all blood and other potentially infectious materials are:',options:['Handled as if they were infectious.','Handled wearing a respirator.','Sterilized prior to disposal.','Discarded as regular trash.'],correct_answer:0,domain:'Infection Prevention',difficulty:'medium',explanation:'Standard Precautions assumes all blood and body fluids are potentially infectious regardless of apparent condition; respirators and sterilization are not universally required.'},
  {id:'562',question:'A confidential medical evaluation must be performed when an employee:',options:['Requests one.','Changes jobs.','Is first hired.','Is exposed to blood or body fluids.'],correct_answer:3,domain:'Infection Prevention',difficulty:'medium',explanation:'Occupational exposure to blood or body fluids triggers mandatory medical evaluation and documentation; initial hire, job changes, and voluntary requests do not require this.'},
  {id:'563',question:'Which of the following are vectors for pathogenic organisms?',options:['Mosquitoes and flies','Bandages and dressings','Surgical instruments','Patient care equipment'],correct_answer:0,domain:'Infection Prevention',difficulty:'medium',explanation:'Mosquitoes and flies are living vectors that transmit pathogens; bandages, instruments, and equipment are inanimate fomites incapable of actively transmitting disease.'},
  {id:'564',question:'Animal reservoirs of disease are of concern with which of the following diseases?',options:['Smallpox','Lyme disease','Botulism','Gas gangrene'],correct_answer:1,domain:'Infection Prevention',difficulty:'medium',explanation:'Lyme disease uses ticks as vectors and maintains animal reservoirs in wildlife populations; smallpox, botulism, and gas gangrene are not maintained in animal reservoirs.'},
  {id:'565',question:'The removal of contamination from an item to the extent necessary for further processing or for the intended use is the AAMI definition of:',options:['Cleaning','Sterilization','Disinfection','Decontamination'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'AAMI defines cleaning as removing contamination to extent necessary for further processing; sterilization eliminates all microorganisms while disinfection reduces them.'},
  {id:'566',question:'The use of physical or chemical means to remove, inactivate, or destroy bloodborne pathogens on the surface of an item is known as:',options:['Cleaning','Sterilization','Disinfection','Decontamination'],correct_answer:3,domain:'Decontamination',difficulty:'medium',explanation:'Decontamination uses physical and chemical means to inactivate bloodborne pathogens on surfaces; cleaning is broader contamination removal and sterilization eliminates all organisms.'},
  {id:'567',question:'Which of the following would be an acceptable method to transport used operating room surgical instrument trays?',options:['Clear plastic bags','Open wire carts','Operating room table','Closed case carts'],correct_answer:3,domain:'Decontamination',difficulty:'medium',explanation:'Closed case carts contain contamination during transport; clear bags and open carts expose personnel to airborne contamination, and OR tables are improper transport surfaces.'},
  {id:'568',question:'Microorganisms found in blood, tissue, and/or body fluids on surgical instruments are referred to as:',options:['An infection','Bioburden','An antagonist','Contaminants'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Bioburden refers to microorganisms on surgical instruments requiring removal; antagonist is not applicable, contaminants is too vague, and infection refers to organisms in body.'},
  {id:'569',question:'According to Dr. John Perkins, surgical instruments should not exceed how many inches in height in the instrument basket for decontamination?',options:['1 inch (2.54 cm)','2 inches (5.08 cm)','3 inches (7.62 cm)','4 inches (10.16 cm)'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Two-inch height limit prevents instrument clustering in baskets, ensuring adequate exposure to decontamination agents and preventing nesting that reduces effectiveness.'},
  {id:'570',question:'Negative pressure refers to:',options:['Recirculated air within the room.','Air exhausted directly to the outside.','Air exchanges of at least four times per hour.','Circulation of air in a confined space.'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Negative pressure means air is exhausted directly outside to prevent contamination spread; recirculated air and confined circulation create positive pressure conditions.'},
  {id:'571',question:'When applying personal protective equipment, which of the following should be donned first?',options:['Gown','Mask','Gloves','Shoe covers'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'The gown must be donned before gloves so the glove cuff can overlap the gown cuff, creating a protective seal that prevents contamination. Mask and shoe covers don\'t require this layering relationship with other PPE.'},
  {id:'572',question:'The MAIN reason why jewelry should not be worn in the decontamination area is because it:',options:['Is expensive and can get damaged.','Can come off and get lost.','Is not easily cleaned.','Can be stolen.'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Jewelry has crevices and grooves that trap microorganisms and organic material that cannot be cleaned to the same standards as bare skin, compromising contamination control. Damage, loss, and theft are not valid infection control reasons.'},
  {id:'573',question:'Before a medical device is cleaned, what information must the technician have before processing it?',options:['Manufacturer\'s instructions for use','Sales representative\'s instructions for operation','Signed purchase order and receiving report','Directions from the department that purchased it'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'Manufacturer\'s IFU contains essential technical specifications for proper cleaning methods, solutions, temperatures, and precautions specific to each device. Sales rep instructions, purchase orders, and department directions lack these critical processing details.'},
  {id:'574',question:'A solution is considered neutral when the pH is:',options:['5','7','11','13'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'pH 7 is the neutral point on the pH scale by definition; values below 7 are acidic and above 7 are alkaline. This is fundamental chemistry applicable to all cleaning solutions.'},
  {id:'575',question:'A cleaning solution having a pH of 9 is said to be:',options:['Acidic','Neutral','Alkaline','Concentrated'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Any pH above 7 is alkaline/basic; pH 9 is well above the neutral point. \'Concentrated\' refers to solution strength, not its acidity or alkalinity.'},
  {id:'576',question:'Enzyme-based detergents contain organic substances that assist in the breakdown of:',options:['Hard water','Disinfectants','Magnesium and copper','Protein soils and blood'],correct_answer:3,domain:'Decontamination',difficulty:'medium',explanation:'Proteolytic enzymes specifically break down protein-based organic material including blood and tissue soils. These enzymes don\'t affect water hardness, disinfectants, or mineral content.'},
  {id:'577',question:'Syringe containers should be changed when they are:',options:['Completely full','2/3rds full','At the fill line','Half full'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Changing at 2/3 full ensures containers don\'t overflow and contaminate the area while maintaining effectiveness. Waiting until completely full risks overflow and contamination hazards.'},
  {id:'578',question:'A proteolytic enzyme breaks down:',options:['Fatty soils','Blood soils','Oily soils','Carbohydrates'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Proteolytic enzymes specifically break down proteins; blood is protein-based soil. Lipid breakdown requires lipolytic enzymes, and carbohydrate breakdown requires different enzyme types.'},
  {id:'579',question:'Which of the following should never be used to remove gross soil on instruments?',options:['Tap water','Chlorine','Moist cloth','Enzymatic foam'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Chlorine corrodes instruments, reduces visibility, and damages metal surfaces when used for gross soil removal. Tap water, enzymatic foam, and moist cloths are appropriate for this initial step.'},
  {id:'580',question:'Before any item with multiple parts is cleaned, it must be:',options:['Processed in an ultrasonic cleaner','Soaked in an enzymatic solution','Sprayed with a lipolytic gel','Disassembled as directed by the manufacturer'],correct_answer:3,domain:'Decontamination',difficulty:'medium',explanation:'Disassembly per manufacturer guidelines ensures all internal and hidden surfaces are properly exposed and cleaned, preventing trapped contamination. Skipping disassembly leaves unreachable surfaces uncleaned.'},
  {id:'581',question:'Generally, metal-bristled brushes can be used to clean:',options:['The cutting edges of scissors','The teeth on vascular forceps','The box locks of hinged instruments','The tungsten carbide jaws of needle holders'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Box locks are sturdy mechanisms that can tolerate metal brushes; cutting edges would be dulled, vascular forceps teeth are too delicate, and carbide surfaces would be damaged. The box lock area is robust enough for this cleaning method.'},
  {id:'582',question:'When manually cleaning surgical instruments, the final rinse in the cleaning process should be performed using:',options:['Critical water','Tap water','Alcohol','Saline'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'Critical (deionized/distilled) water prevents mineral deposits and water spotting that could interfere with subsequent disinfection and sterilization. Tap water leaves minerals; alcohol may leave residue; saline is inappropriate.'},
  {id:'583',question:'Before instruments are processed in an ultrasonic cleaner, the:',options:['Water should be changed','Gross soil should be removed','Temperature of the water should be 75 degrees F','Instruments should be placed in a solid metal basket'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Gross soil must be removed first because it reduces ultrasonic effectiveness, overloads the cleaning solution, and prevents proper cavitation action on instrument surfaces. The other options describe incorrect procedures.'},
  {id:'584',question:'Prior to manual cleaning, a flexible endoscope must be treated with:',options:['Transport in sterile water','Treatment with enzymatic foam','Placement in a humid pack','Covering with a towel moistened with water'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Enzymatic foam is the standard pre-treatment that breaks down organic biofilm and protects delicate endoscope surfaces before mechanical cleaning. Other options don\'t provide the necessary enzymatic breakdown.'},
  {id:'585',question:'If used instruments in a basin are not clearly visible, which of the following should be used to pick them up?',options:['Forceps','Bare hands','Gloved hands','Wire-handled brush'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'Forceps provide safe, controlled handling without direct hand contact, preventing needle stick injuries and contamination. Bare or gloved hands risk injury on sharp instruments; brushes cannot safely grasp items.'},
  {id:'586',question:'Which material can be used as a simple test to check the functioning of the ultrasonic cleaner?',options:['Tyvek','Plastic','Aluminum foil','Polyethylene film'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Aluminum foil cavitation test is the standard method; properly functioning ultrasound creates visible pit marks in the foil. Tyvek, plastic, and polyethylene don\'t show cavitation effects.'},
  {id:'587',question:'Which of the following statements about cleaning is TRUE?',options:['All basic instruments have the same cleaning procedures.','All surgical instruments and devices require ultrasonic cleaning.','The use of additional chemicals, if not in the instructions for use, is not permitted.','The cleaning process can be shortened to meet the needs of the OR.'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Manufacturer IFU must be followed exactly; unapproved chemicals could damage instruments or reduce disinfection efficacy. Different instruments have different procedures, not all need ultrasonic, and shortcuts compromise safety.'},
  {id:'588',question:'Which of the following best describes the process that kills most microorganisms but not necessarily spores?',options:['Antisepsis','Sterilization','Sanitization','Disinfection'],correct_answer:3,domain:'Disinfection',difficulty:'medium',explanation:'Disinfection by definition kills most microorganisms but not spores; sterilization kills spores; antisepsis applies to living tissue; sanitization is lower-level. This is the technical definition of disinfection.'},
  {id:'589',question:'According to Spaulding\'s classification of medical devices, a semicritical item requires which form of disinfection?',options:['Low-level disinfection','High-level disinfection','Sanitization','Sterilization'],correct_answer:1,domain:'Disinfection',difficulty:'medium',explanation:'Spaulding\'s classification requires high-level disinfection for semicritical items that contact non-sterile mucous membranes; critical items require sterilization, noncritical items require low-level. This is the standard classification system.'},
  {id:'590',question:'The Trophon system is mainly used for processing:',options:['Laparoscopic instruments.','TEE probes.','Flexible bronchoscopes.','Rigid cystoscopes.'],correct_answer:1,domain:'Disinfection',difficulty:'medium',explanation:'Trophon is specifically designed for automated high-level disinfection of TEE probes, protecting their sensitive technology. It\'s not suitable for rigid instruments or other endoscope types requiring different processing.'},
  {id:'591',question:'The ability of a disinfectant to perform most efficiently depends on:',options:['How quickly it dries.','A strong concentration.','Mixing it with a detergent.','Whether it remains wet for the stated amount of time.'],correct_answer:3,domain:'Disinfection',difficulty:'medium',explanation:'Disinfectants require adequate contact time (dwell time) while remaining wet to inactivate microorganisms through chemical action. Quick drying (A), concentration alone (B), or mixing with detergent (C) cannot compensate for insufficient wet time.'},
  {id:'592',question:'Which of the following statements is TRUE regarding high-level disinfection?',options:['All disinfectants have the ability to kill the same microorganisms.','Protein soils can affect the disinfection process.','Lumened devices are easy to disinfect because of their air pockets.','All high-level disinfectants have the same exposure time.'],correct_answer:1,domain:'Disinfection',difficulty:'medium',explanation:'Organic soils like proteins shield microorganisms from disinfectant contact, reducing effectiveness. Different disinfectants have different spectrums of activity (negates A), lumens are actually difficult to disinfect (negates C), and exposure times vary by product (negates D).'},
  {id:'593',question:'Alcohol inactivates microorganisms by:',options:['Evaporation','Alkylation','Oxidizing the proteins','Denaturing the proteins'],correct_answer:3,domain:'Disinfection',difficulty:'medium',explanation:'Alcohol disrupts protein structure by unfolding and denaturing them, which kills microorganisms. Evaporation (A) isn\'t the mechanism, alkylation (B) is glutaraldehyde\'s method, and alcohol reduces rather than oxidizes proteins (C).'},
  {id:'594',question:'Which of the following would be obvious on an improperly cleaned instrument that has been disinfected in ortho-phthalaldehyde?',options:['Slimy coating','Yellow stain','Blue stain','Foul odor'],correct_answer:2,domain:'Disinfection',difficulty:'medium',explanation:'Ortho-phthalaldehyde forms a distinctive blue-gray stain when it binds to residual protein on improperly cleaned instruments, serving as a visual indicator of inadequate cleaning.'},
  {id:'595',question:'Osmosis is:',options:['The movement of a solvent through a non-permeable membrane into a solution of higher concentration.','The movement of a solvent through a permeable membrane into a solution of higher concentration.','Not affected by the concentration of the disinfectant.','The factor that causes the passage of the disinfectant into the cell.'],correct_answer:1,domain:'Disinfection',difficulty:'medium',explanation:'Osmosis specifically requires a semipermeable membrane (not non-permeable as in A) that allows solvent but not solute molecules to pass, with movement toward higher solute concentration. This is the textbook definition of osmosis.'},
  {id:'596',question:'Which of the following high-level disinfectants requires activation prior to use?',options:['Ortho-phthalaldehyde','Hydrogen peroxide','Peracetic acid','Glutaraldehyde'],correct_answer:3,domain:'Disinfection',difficulty:'medium',explanation:'Glutaraldehyde requires chemical activation, typically with sodium bicarbonate, before use to become effective. OPA, hydrogen peroxide, and peracetic acid are all ready-to-use disinfectants.'},
  {id:'597',question:'Quaternary ammonium compound disinfectants are:',options:['Used for high-level disinfection.','Relatively non-toxic to humans.','Do not permit the growth of gram-negative bacteria within them.','Are sporicidal.'],correct_answer:1,domain:'Disinfection',difficulty:'medium',explanation:'Quaternary ammonium compounds are relatively safe for human use because of their low toxicity profile. They are low-level disinfectants (not high-level as A suggests), are susceptible to gram-negative contamination (negates C), and lack sporicidal capability (negates D).'},
  {id:'598',question:'Iodine is used primarily to reduce microorganisms on which of the following?',options:['Workstations','Patient care equipment','Skin','Metals and rubber'],correct_answer:2,domain:'Disinfection',difficulty:'medium',explanation:'Iodine is primarily used as an antiseptic for skin preparation and wound treatment. Other disinfectants are used for workstations, equipment, and non-biological surfaces.'},
  {id:'599',question:'To obtain maximum effectiveness, disinfectants must be:',options:['Mixed with a detergent','Used in the proper concentration','Applied two times','Kept at a temperature lower than 40 degrees F'],correct_answer:1,domain:'Disinfection',difficulty:'medium',explanation:'Proper concentration ensures the disinfectant is effective against target microorganisms, which is essential regardless of mixing agents (A), application frequency (C), or temperature storage (D).'},
  {id:'600',question:'Accelerated hydrogen peroxide is:',options:['Used in low-temperature sterilization systems.','An environmental cleaner-disinfectant.','Remains wet more easily for the recommended period of time.','A combination of peroxide and saline.'],correct_answer:1,domain:'Disinfection',difficulty:'medium',explanation:'Accelerated hydrogen peroxide is formulated as an environmental surface cleaner-disinfectant for general use. It differs from liquid hydrogen peroxide used in sterilization (A), and its formulation is distinct from peracetic acid alone (C, D).'},
  {id:'601',question:'When minimum effectiveness testing reveals that the concentration of a high-level disinfectant is below the recommended level, you should:',options:['Add more disinfectant to the basin.','Add water to the solution.','Continue to use the solution.','Discard the solution.'],correct_answer:3,domain:'Disinfection',difficulty:'medium',explanation:'Below-recommended concentration means the disinfectant cannot reliably inactivate microorganisms, so it must be discarded. Adding disinfectant (A) or water (B) creates guesswork about actual concentration, and continuing use (C) is unsafe.'},
  {id:'602',question:'The nursing unit calls for a patient-cooling machine. Which of the following would be sent?',options:['Intravenous pump','Hypo/hyperthermia machine','Sequential compression device','Patient-controlled analgesia pump'],correct_answer:1,domain:'Equipment',difficulty:'medium',explanation:'A hypo/hyperthermia machine actively cools or warms patients for temperature management. IV pumps (A) deliver fluids, sequential compression devices (C) prevent blood clots, and PCA pumps (D) manage pain.'},
  {id:'603',question:'Which of the following pieces of equipment is sometimes used after a total knee replacement to exercise the joint?',options:['Hypo/hyperthermia machine','Sequential compression device','Patient-controlled analgesia pump','Continuous passive motion device'],correct_answer:3,domain:'Equipment',difficulty:'medium',explanation:'Continuous passive motion devices are specifically designed to gently move joints through their range of motion post-operatively to improve healing and function after knee replacement surgery.'},
  {id:'604',question:'Patient care equipment should be reprocessed:',options:['After each use','Once a week','When it is visibly soiled','At least monthly'],correct_answer:0,domain:'Equipment',difficulty:'medium',explanation:'Patient care equipment must be reprocessed after each use to prevent cross-contamination between patients. Weekly (B), visible soiling (C), or monthly schedules (D) do not provide adequate protection.'},
  {id:'605',question:'Generally, prior to disinfection, patient care equipment should be:',options:['Wiped off with water.','Cleaned with a detergent.','Rinsed with an antiseptic.','Cleaned with a chlorine-soaked cloth.'],correct_answer:1,domain:'Equipment',difficulty:'medium',explanation:'Detergent cleaning removes gross soil and organic matter that can interfere with subsequent disinfection. Water alone (A) is insufficient, antiseptic rinse (C) is not preparatory, and pre-treatment with chlorine (D) is not standard protocol.'},
  {id:'606',question:'The process for decontamination of patient care equipment should:',options:['Be approved by the Infection Prevention Committee.','Be standardized so all equipment is decontaminated the same way.','Include treatment with chlorine bleach wipes before cleaning.','Include a high-level disinfection process.'],correct_answer:0,domain:'Equipment',difficulty:'medium',explanation:'The Infection Prevention Committee must approve all equipment reprocessing procedures to ensure they meet infection control standards. While standardization (B) is desirable, approval is the primary requirement; pre-bleach treatment (C) and high-level disinfection (D) are not universal requirements.'},
  {id:'607',question:'Which of the following should be used to disinfect patient care equipment?',options:['An alcohol-based disinfectant','A chlorinated disinfectant wipe','The general-use disinfectant used to clean work surfaces','The disinfectant recommended by the equipment manufacturer'],correct_answer:3,domain:'Equipment',difficulty:'medium',explanation:'The manufacturer\'s recommended disinfectant is validated for that specific equipment\'s materials and components. Generic disinfectants (A, B, C) may damage sensitive equipment surfaces or electronics.'},
  {id:'608',question:'Which of the following is NOT part of the final preparation of patient care equipment for reuse?',options:['Placement of disassembled parts into a plastic bag','Checking of cords and plugs for signs of damage','Checking of the date of the last safety check','Lubrication of movable parts'],correct_answer:0,domain:'Equipment',difficulty:'medium',explanation:'Disassembled parts should NOT be bagged as they need to remain accessible and visible for inspection and use. Checking cords/plugs (B), verifying safety check dates (C), and lubricating parts (D) are all proper final preparation steps.'},
  {id:'609',question:'Which of the following actions should be taken if a small cut or nick is noted in the electrical cord of a piece of patient care equipment?',options:['Place electrical tape over the defect.','Clean and disinfect the equipment and then send it to the biomedical engineering department.','Leave the equipment in service as long as the cut does not reach the wire.','Contact the manufacturer for further instructions.'],correct_answer:1,domain:'Equipment',difficulty:'medium',explanation:'Any cord insulation damage is a safety hazard requiring biomedical engineering evaluation and repair before the equipment returns to service. Taping (A) is not a safe repair, continued use despite damage (C) is unsafe, and manufacturer contact (D) comes after proper decontamination.'},
  {id:'610',question:'Prior to transport to the decontamination area, soiled patient care equipment should be:',options:['Treated with enzyme foam','Placed in clear plastic bags','Placed in biohazard bags','Placed on an open wire cart'],correct_answer:2,domain:'Equipment',difficulty:'medium',explanation:'Soiled patient equipment is considered biohazardous and must be transported in biohazard containment to protect handlers from pathogenic exposure. Clear bags (B) lack proper containment designation, enzyme foam (A) is for cleaning, and open carts (D) expose staff to biohazards.'},
  {id:'611',question:'There is a high patient census, and there are no intravenous pumps available for distribution. Which of the following actions would be most effective?',options:['Wait for the next shift to do rounds.','Call nursing units to let them know.','Check the nursing units more frequently for unused pumps.','Tell the requesting units that there are no pumps in the department.'],correct_answer:2,domain:'Equipment',difficulty:'medium',explanation:'Checking units for unused pumps actively solves the shortage by recovering equipment in-house, whereas waiting (A) does nothing, notification (B) doesn\'t solve the problem, and refusing requests (D) abandons the effort.'},
  {id:'612',question:'Which of the following statements is TRUE? Packaging materials must:',options:['Be impenetrable.','Contain air inside the package.','Resist entry of microorganisms into the package.','Be able to be used in all sterilization methods.'],correct_answer:2,domain:'Packaging',difficulty:'medium',explanation:'Resisting microbial entry is the core function of sterile packaging; impenetrability (A) is unnecessarily strict, air inside (B) inhibits sterilization, and method-specificity (D) means materials are chosen per method, not usable for all.'},
  {id:'613',question:'Muslin wrappers have which thread count per square inch?',options:['100 per inch','120 per inch','140 per inch','160 per inch'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Muslin wrappers are standardized at 120 threads per inch to balance barrier effectiveness with adequate sterilant penetration.'},
  {id:'614',question:'Which of the following statements about reusable wrappers is TRUE?',options:['They do not have to be re-laundered if the package is opened but not used.','Inspection of the wrapper is performed using lighted magnification.','Holes can be repaired by sewing.','The number of reuses should be tracked.'],correct_answer:3,domain:'Packaging',difficulty:'medium',explanation:'Tracking reuse numbers is essential to monitor wrapper degradation and determine replacement timing; opened packages must be reprocessed (A false), holes cannot be safely sewn (C false), and visual inspection is standard (B not the best term).'},
  {id:'615',question:'Dual-ply wrap:',options:['Has the two wrappers bonded together.','Requires that two wrappers be applied sequentially.','Resists tearing and damage.','Can be used to line sterilizer carts.'],correct_answer:0,domain:'Packaging',difficulty:'medium',explanation:'Dual-ply means the two layers are bonded together as one unit for structural integrity; sequential application (B) is separate wrapping, and it resists damage/lining use (C, D) but these don\'t define the term.'},
  {id:'616',question:'If a non-perforated tray is used for the sterilization of instrument sets, it must be:',options:['Wrapped with a towel before instruments are placed in it.','Processed on the top rack of the sterilizer.','Laid flat on the sterilizer rack.','Tilted forward on the sterilizer rack.'],correct_answer:2,domain:'Packaging',difficulty:'medium',explanation:'Flat positioning allows steam to reach under and around the non-perforated tray; tilting (D) blocks steam penetration, top rack (B) limits exposure, and wrapping (A) is unnecessary.'},
  {id:'617',question:'Which of the following statements is TRUE regarding labeling?',options:['Magic markers can be used to label packages.','Ballpoint pens can only be used on the sterilization tape.','Markers used must be non-toxic and approved for the sterilization process.','Writing on the packaging material is permitted.'],correct_answer:2,domain:'Packaging',difficulty:'medium',explanation:'Non-toxic, sterilization-approved markers prevent package contamination and toxic fume release; magic markers (A) and standard pens (B) may contain harmful substances that outgas during sterilization, and writing directly on material (D) degrades packaging integrity.'},
  {id:'618',question:'When assembling a set containing heavy and delicate instruments, where should the heavier instruments be placed in the set?',options:['On top of the delicate instruments','On the bottom of the tray','In the center of the tray','On the right-hand side'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Heavy instruments at the bottom prevent crushing delicate items above them; all other positions risk damaging fragile instruments.'},
  {id:'619',question:'Which of the following statements about missing instruments is TRUE?',options:['Missing instruments are always lost in SPD.','Accurate count sheets contribute to missing instruments.','Adequate inventories of instruments have no effect on missing instruments.','Missing instruments can be caused by inadvertent discarding of instruments during breakdown of sets.'],correct_answer:3,domain:'Packaging',difficulty:'medium',explanation:'Missing instruments can result from multiple causes including accidental discard during set breakdown; the statement acknowledges practical reality rather than absolute loss, poor counts, or inventory effects.'},
  {id:'620',question:'Where should the chemical indicator be placed in a wrapped set of instruments?',options:['The left-hand corner','The center of the set','Two opposite corners','The right-hand side'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'The center of the set is the hardest location for sterilant to penetrate, so the indicator there confirms the most challenging area achieved sterilization; corners and edges reach sterilant sooner.'},
  {id:'621',question:'Which of the following should be placed within each package to provide information on critical sterilization parameters?',options:['Biological indicator','Mechanical monitor','Bowie-Dick test','Type 4 or higher chemical indicator'],correct_answer:3,domain:'Packaging',difficulty:'medium',explanation:'Type 4+ chemical indicators inside packages verify sterilization parameters reached that specific location; biological (A) and mechanical (B) monitors are external/sterilizer-level tests, and Bowie-Dick (C) is a test pack tool, not an in-package indicator.'},
  {id:'622',question:'Basin sets should be prepared for sterilization with:',options:['Basins separated by at least one-half inch.','Basins placed in opposite directions.','An absorbent material between each basin.','A non-absorbent material between each basin.'],correct_answer:2,domain:'Packaging',difficulty:'medium',explanation:'Absorbent material between basins prevents condensation from pooling and interfering with sterilization; spacing (A) alone doesn\'t address moisture, opposing direction (B) isn\'t the key requirement, and non-absorbent (D) traps moisture.'},
  {id:'623',question:'Using excessive amounts of chemical indicator tape to seal a package to be sterilized can:',options:['Interfere with air removal and steam penetration.','Interfere with the stacking of sets on the shelf.','Cause damage to nonwoven wrappers.','Cause difficulty in removing the tape in the operating room.'],correct_answer:0,domain:'Packaging',difficulty:'medium',explanation:'Excessive tape seals the package too tightly, preventing air removal and blocking steam entry during sterilization; shelf stacking (B) and tape removal (D) are minor concerns compared to sterilization failure.'},
  {id:'624',question:'Sterilant penetration can be inhibited by using a wrapper that is:',options:['Too small.','Too large.','An envelope fold on a small set.','A square fold on a large pack.'],correct_answer:0,domain:'Packaging',difficulty:'medium',explanation:'A wrapper that is too small creates tight wrapping that prevents sterilant penetration; oversized (B), envelope folds (C), and square folds (D) are not the primary barrier to penetration—wrapper size is.'},
  {id:'625',question:'When packaging an item in a paper-plastic pouch, approximately how much space should be left between the item and the inside edges of the pouch?',options:['1/4 inch','1/2 inch','3/4 inch','1 inch'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'1/2 inch spacing allows adequate sterilant penetration while keeping the item secure; 1/4 inch (A) restricts penetration, and 3/4–1 inch (C, D) permit excessive item movement during sterilization.'},
  {id:'626',question:'Paper-plastic pouches can be placed:',options:['Inside wrapped sets.','Inside rigid containers.','To package a set of osteotomes.','Only for light-weight items.'],correct_answer:0,domain:'Packaging',difficulty:'medium',explanation:'Paper-plastic pouches can nest inside wrapped sets for added protection; rigid containers (B) have their own sterilization requirements, osteotomes (C) need sturdy containers, and pouches work for various weights (D).'},
  {id:'627',question:'Which of the following packaging materials can be used for low-temperature gas plasma sterilization?',options:['Textile wraps','Tyvek','Woven wrappers','Paper-plastic pouches'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Tyvek is specifically designed for low-temperature gas plasma sterilization; textile wraps (A) and woven wrappers (C) are for steam sterilization, and paper-plastic pouches (D) are for steam and ethylene oxide.'},
  {id:'628',question:'Tamper-evident seals on rigid containers include which of the following?',options:['Lids and gaskets','Lids and latches','Latches and locks','Filters and gaskets'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Lids and latches together serve as tamper-evident seals on rigid containers; gaskets (A) aren\'t tamper-evidence indicators, locks (C) aren\'t standard, and filters (D) are unrelated to evidence of tampering.'},
  {id:'629',question:'Critical parameters for heat sealing paper-plastic pouches include temperature, pressure, and which of the following?',options:['Dwell time','Rotary banding','Impulse banding','Space above the seal'],correct_answer:0,domain:'Packaging',difficulty:'medium',explanation:'Temperature, pressure, and dwell time (duration of heat application) are the three critical heat-sealing parameters; rotary and impulse banding (B, C) refer to machine types, not parameters, and space above the seal (D) isn\'t critical.'},
  {id:'630',question:'Prior to packaging, large instrument sets should be placed:',options:['On a flat metal tray','In a paper-plastic pouch','In a solid metal basket','In a perforated metal mesh basket'],correct_answer:3,domain:'Packaging',difficulty:'medium',explanation:'Perforated metal mesh baskets support instruments while allowing sterilant penetration; flat metal trays (A) don\'t support sets properly, plastic pouches (B) lack support, and solid baskets (C) prevent sterilant access.'},
  {id:'631',question:'Sterile trays that might be subjected to storage challenges should be:',options:['Sterilized in a paper-plastic peel pouch.','Wrapped in double-ply wrap.','Sealed with extra autoclave tape.','Placed in a sterility maintenance cover.'],correct_answer:3,domain:'Packaging',difficulty:'medium',explanation:'Sterility maintenance covers provide protective housing during storage to prevent contamination while maintaining sterile status. Paper-plastic pouches are for initial sterilization, double-ply wrap is basic wrapping, and extra tape doesn\'t address storage challenges.'},
  {id:'632',question:'A titanium instrument can be recognized by which color?',options:['Red','Blue','Green','Purple'],correct_answer:1,domain:'Instrumentation',difficulty:'medium',explanation:'Titanium instruments are color-coded blue for identification. Red, green, and purple are not standard color codes for surgical instruments.'},
  {id:'633',question:'Which of the following would be used to hold back tissue or organs?',options:['Cannulas','Retractors','Tissue forceps','Dressing forceps'],correct_answer:1,domain:'Instrumentation',difficulty:'medium',explanation:'Retractors are specifically designed with blunt ends to hold back tissue and organs without damaging them. Cannulas drain, tissue forceps grasp delicate tissue, and dressing forceps apply dressings.'},
  {id:'634',question:'The weakest part of an instrument is the:',options:['Jaws','Shanks','Ratchet','Box lock'],correct_answer:3,domain:'Instrumentation',difficulty:'medium',explanation:'The box lock is the weakest part because it\'s where two metal pieces meet at an angle, creating a stress concentration point. The jaws, shanks, and ratchet are more structurally solid.'},
  {id:'635',question:'During inspection, debris is most often found in which part of a hemostat?',options:['Jaws','Shanks','Box lock','Ratchet'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'Debris accumulates in the box lock due to the tight crevice where two metal pieces meet and the hinging mechanism. The other areas are more accessible and don\'t trap debris as easily.'},
  {id:'636',question:'Floor-grade instruments:',options:['Are acceptable for use on OR sets.','Last just as long as surgical-grade instruments.','Do not have a protective passivation layer.','Are easier to clean than surgical instruments.'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'Floor-grade instruments lack the protective chromium oxide passivation layer that surgical-grade instruments receive, making them inferior quality. They\'re not acceptable for OR sets, don\'t last as long, and aren\'t easier to clean.'},
  {id:'637',question:'The layer on a surgical instrument that is created by the passivation process is called:',options:['A satin finish','Tungsten carbide','Chromium oxide','An ebonized surface'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'Passivation creates a chromium oxide layer that protects surgical stainless steel from corrosion and staining. Satin finish is a surface appearance, tungsten carbide is a jaw material, and ebonized refers to a handle treatment.'},
  {id:'638',question:'Which of the following would be used to cannulate or drain?',options:['Hemostat','Thumb forceps','Trocar','Tenaculum'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'A trocar is a pointed instrument designed to pierce tissue for cannulation or drainage procedures. Hemostats clamp vessels, thumb forceps grasp tissue, and tenacula hold or retract structures.'},
  {id:'639',question:'Which of the following lubricants is recommended for use on surgical instruments?',options:['Oil-based','Water-based','Silicone-based','Petroleum-based'],correct_answer:1,domain:'Instrumentation',difficulty:'medium',explanation:'Water-based lubricants are recommended because they rinse away completely without leaving residue that could interfere with sterilization or function. Oil-based, silicone-based, and petroleum-based lubricants leave film residues.'},
  {id:'640',question:'Which of the following would NOT be included in the routine inspection of an instrument?',options:['Jaw alignment','Ratchet tension','Box lock stiffness','Vendor identification number'],correct_answer:3,domain:'Instrumentation',difficulty:'medium',explanation:'Vendor identification number is not part of routine functional inspection of instruments. Jaw alignment, ratchet tension, and box lock stiffness are critical checks for proper function.'},
  {id:'641',question:'Which of the following statements about instrument lubricant is TRUE?',options:['Instrument lubrication should be performed in the decontamination area.','The lubricant should be thoroughly rinsed off.','Lubrication of instruments is only needed when the box lock is stiff.','Instrument lubrication can extend the life of an instrument.'],correct_answer:3,domain:'Instrumentation',difficulty:'medium',explanation:'Lubrication can extend instrument life by reducing friction and wear on moving parts, acting as preventive maintenance. It should be done in prep area (not decontamination), shouldn\'t be rinsed off, and should be routine (not just for stiff locks).'},
  {id:'642',question:'When the jaws of a stainless steel (non-tungsten carbide) needle holder become worn, the needle holder must be:',options:['Discarded','Resurfaced','Used only on house trays','Repaired by the vendor'],correct_answer:0,domain:'Instrumentation',difficulty:'medium',explanation:'Non-tungsten carbide needle holder jaws cannot be effectively resurfaced when worn, so the instrument must be discarded. Only tungsten carbide jaws can be resurfaced; stainless steel jaws cannot.'},
  {id:'643',question:'It would be most likely for you to find a crack in which part of a hinged instrument?',options:['Ring handle','Box lock','Ratchet','Shank'],correct_answer:1,domain:'Instrumentation',difficulty:'medium',explanation:'Cracks most commonly occur at the box lock because it\'s the weakest structural point and experiences the greatest stress during use. Ring handles, ratchets, and shanks are more solid.'},
  {id:'644',question:'An insulated instrument that has cracked or nicked insulation can cause:',options:['It to grasp poorly.','Inaccurate cutting.','An electrical shock or burns.','A tear in the surgeon\'s glove.'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'Cracked or nicked insulation on electrosurgical instruments can allow electrical current to contact tissue or personnel, causing electrical shock or burns. Poor grasping, cutting errors, and glove tears are not direct consequences of insulation damage.'},
  {id:'645',question:'Powered equipment should be lubricated:',options:['With a mineral-oil-based lubricant.','With a water-based lubricant.','According to the manufacturer\'s instructions.','In the lubricant cycle of a washer-decontaminator.'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'Different powered equipment has specific lubrication requirements that vary by manufacturer and equipment type, so manufacturer\'s instructions must be followed. Generic recommendations don\'t account for equipment-specific needs.'},
  {id:'646',question:'Which of the following statements is TRUE about the inspection of surgical instruments?',options:['Ratcheted surgical instruments should be inspected in the closed position.','Needle holders should allow the needle to rotate in the jaws while fully clamped.','Cracked box locks will not affect the function of the instrument and can be used.','All hand-held surgical instruments must be checked for cleanliness and proper function.'],correct_answer:3,domain:'Instrumentation',difficulty:'medium',explanation:'All hand-held surgical instruments must be checked for cleanliness and proper function as a fundamental requirement of instrument processing. The other options contain exceptions or false statements (cracked locks can\'t be used, needles shouldn\'t rotate when fully clamped, ratcheted instruments must be inspected open).'},
  {id:'647',question:'Black dots noted in a fiberoptic cable during inspection indicate:',options:['How many times it has been used.','That there is damage to the glass rods.','That the cable is normal and okay to use.','That the wrong light source has been used.'],correct_answer:1,domain:'Instrumentation',difficulty:'medium',explanation:'Black dots in fiberoptic cables indicate damage to the internal glass rods, compromising light transmission. They\'re not usage indicators, not normal condition, and not related to light source issues.'},
  {id:'648',question:'Which of the following statements is TRUE?',options:['The passivation layer of surgical instruments can be destroyed by improper handling.','If blood is left on surgical instruments for more than 60 minutes, the instrument will be stained.','Spots cannot be removed from surgical instruments.','Critical water can cause staining of instruments.'],correct_answer:0,domain:'Instrumentation',difficulty:'medium',explanation:'The passivation layer can be damaged by improper handling (scratching, abrasive materials), which is why careful handling techniques are critical. Blood staining takes longer than 60 minutes to occur, some spots can be removed, and critical water actually protects instruments.'},
  {id:'649',question:'Which of the following is not a component of a rigid endoscope?',options:['Optical element','Elevator mechanism','Objective lens','Light post'],correct_answer:1,domain:'Instrumentation',difficulty:'medium',explanation:'An elevator mechanism is a component of flexible endoscopes, not rigid endoscopes. Optical elements, objective lens, and light post are all standard components of rigid endoscopes.'},
  {id:'650',question:'The fiberoptic cord is attached to which part of a rigid endoscope?',options:['Objective lens','Optical element','Light post','Telescope'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'The fiberoptic cord connects to the light post, which transmits light through the optical system. The objective lens is for viewing, and the optical element and telescope don\'t have separate cord attachment points.'},
  {id:'651',question:'Pitting of surgical instruments is usually caused by:',options:['Enzymatic detergents','Neutral pH detergents','Use of chloride-containing chemicals','Use of hydrogen peroxide solutions'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'Chloride ions breach the protective oxide layer on stainless steel, causing corrosion pitting. Enzymatic detergents, neutral pH, and hydrogen peroxide do not cause this specific damage pattern.'},
  {id:'652',question:'If a surgical instrument is not clean, it should be:',options:['Sent back to the decontamination area.','Cleaned in the handwash sink in the preparation area.','Cleaned at the workstation.','Wiped off with alcohol.'],correct_answer:0,domain:'Instrumentation',difficulty:'medium',explanation:'Unclean instruments require specialized decontamination equipment and procedures; cleaning at the workstation, handwash sink, or with alcohol does not meet safety standards for contaminated instruments.'},
  {id:'653',question:'Which of the following statements is TRUE regarding hemostats?',options:['All hemostats have teeth.','Only the jaws need to be inspected.','The box lock is the strongest part of the instrument.','The jaws have various patterns based on their intended use.'],correct_answer:3,domain:'Instrumentation',difficulty:'medium',explanation:'Hemostat jaws have varied patterns (serrated, smooth, longitudinal) designed for specific tissue types and surgical applications; not all hemostats have teeth, box lock inspection is incomplete, and the box lock is not the strongest part.'},
  {id:'654',question:'A Carmalt clamp would be used in which type of surgery?',options:['Gynecological','Ear, nose, and throat','Intestinal','Neurological'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'Carmalt clamps are designed for vascular and intestinal procedures where they provide secure tissue control without crushing; they are not used in gynecological, ENT, or neurological surgeries.'},
  {id:'655',question:'Which of the following statements about surgical scissors is TRUE?',options:['Gold-handled scissors are known as super sharps.','All surgical scissors are straight.','Dissecting scissors can be used to cut sutures.','Iris scissors have pointed tips.'],correct_answer:3,domain:'Instrumentation',difficulty:'medium',explanation:'Iris scissors are characterized by small size and pointed tips for precise, delicate cutting; gold handles aren\'t called "super sharps," scissors come in curved and straight types, and dissecting scissors aren\'t designed for suture cutting.'},
  {id:'656',question:'The process by which all forms of microbial life, including spores, are destroyed is the definition of:',options:['Sanitization','Disinfection','Decontamination','Sterilization'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'Sterilization destroys all microbial life including spores (SAL 10^-6), while sanitization reduces microbes, disinfection kills vegetative cells but not spores, and decontamination removes contaminants without destroying all microorganisms.'},
  {id:'657',question:'In a non-table-top sterilizer, a gauge on the main steam line tells you the steam pressure:',options:['Inside the jacket','Inside the chamber','As steam is entering the jacket','As steam is exiting the chamber'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'The main steam line gauge measures pressure in the jacket surrounding the chamber, which indicates available steam pressure; other locations would require different gauge placements and wouldn\'t reflect jacket pressure.'},
  {id:'658',question:'Which of the following is the minimum exposure time for wrapped goods in a dynamic-air-removal steam cycle at 275 degrees F and 28 to 30 psi?',options:['3 minutes','4 minutes','10 minutes','15 minutes'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'CRCST protocol specifies 4 minutes minimum for wrapped goods at 275°F/28-30 psi in dynamic-air-removal cycles; 3 minutes is insufficient and 10-15 minutes exceeds required exposure time.'},
  {id:'659',question:'Immediate-use steam sterilization might be indicated when:',options:['A one-of-a-kind instrument is contaminated.','Loaned instruments are received late.','Instrument inventory is low.','The instrument is delicate.'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'IUSS is only justified for emergency situations involving contaminated, irreplaceable instruments; low inventory, late-arriving instruments, and delicate instruments do not meet IUSS criteria.'},
  {id:'660',question:'Which of the following best describes a wet load?',options:['A single package with moisture droplets','Excess moisture collecting in the drain line','Wet sets placed into the sterilizer','Multiple packages in the same load found with excess moisture'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'A wet load describes the condition when multiple packages in a load show excess moisture, compromising sterility across the entire load; moisture in a single package or drain line represents different issues.'},
  {id:'661',question:'Which of the following statements is TRUE regarding sterility assurance?',options:['An item is considered sterile if there is a 1 in 1,000 chance that a microorganism survived the sterilization process.','Removing as many microorganisms as possible from the device increases the probability of microbial kill.','The sterility assurance level for a sterile device is expressed as 10 to the negative 6.','Sterilizers are generally designed to kill 1,000 spores.'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'SAL 10^-6 represents the probability that one organism survives sterilization (one in a million), which is the standard for medical devices; the other options misstate probability, bioburden effects, or sterilizer capabilities.'},
  {id:'662',question:'Which of the following can occur if packages are moist at the end of the steam cycle?',options:['Mold can form on the package.','Microorganisms can wick into the package.','The package can be too hot to handle.','A false reading of external chemical indicators can occur.'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Moisture allows microorganisms to wick into packages through capillary action, bypassing the package barrier; mold is a slower process, heat isn\'t the primary concern, and chemical indicators won\'t show false readings from moisture alone.'},
  {id:'663',question:'In a mixed load of paper-plastic pouches and metal goods, the pouches should be placed:',options:['On the top rack','On the bottom rack','Alternately on each rack','On both racks, with textiles in back and metal items in front'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'Alternating placement ensures even steam distribution to both material types; concentrating either type on one rack prevents adequate steam penetration to all packages.'},
  {id:'664',question:'Stacking of rigid sterilization containers in a steam sterilizer is permitted when:',options:['The manufacturer provides technical data showing that it is acceptable.','It is the last load of the day and the sets will sit overnight.','The top shelf is removed to make more space.','The load will only contain rigid containers.'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Only manufacturer technical data validates stacking since steam penetration varies significantly by container design; end-of-day timing, shelf removal, or load composition alone cannot ensure adequate sterilization.'},
  {id:'665',question:'Which of the following is used to detect air leaks or insufficient air removal?',options:['Bacterial spore strip','Sterilizer indicator tape','Process challenge device','Bowie-Dick test'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'The Bowie-Dick test detects inadequate air removal and steam penetration in dynamic cycles; bacterial spore strips verify lethality, tape shows basic exposure, and PCDs test overall sterilization effectiveness.'},
  {id:'666',question:'One reason for adding chemicals to the boiler feedwater in non-table-top sterilizers is to:',options:['Distill the water.','Prevent condensate.','Provide 100% saturated steam.','Minimize contaminants.'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Chemicals prevent mineral scale and condensate buildup in the steam system, maintaining steam quality; they don\'t distill water, ensure saturation, or serve as the primary contamination removal method.'},
  {id:'667',question:'Which of the following monitoring methods verifies that conditions within the load were adequate to kill bacterial spores?',options:['Chemical','Biological','Mechanical','Administrative'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Biological indicators with bacterial spores directly verify that sterilization conditions were lethal; chemical monitors exposure only, mechanical monitors parameters, and administrative tracks documentation.'},
  {id:'668',question:'What is the correct action to take if an item needs to be corrected or removed from the sterilization load record?',options:['Use a white-out pen.','Rewrite the entire record.','Cross off the item with a black sharpie.','Draw a line through the item and initial it.'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'A line-through with initials creates a clear, auditable record correction that meets legal and compliance standards; white-out, rewriting, or heavy marking obscures the original entry and violates documentation requirements.'},
  {id:'669',question:'The Bowie-Dick test is considered which type of monitoring process?',options:['Administrative','Chemical','Mechanical','Biological'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'The Bowie-Dick test uses chemical indicators to detect air removal and steam penetration; it is not biological (uses no spores), mechanical (monitors no parameters), or administrative (it\'s a physical test).'},
  {id:'670',question:'A Type 5 indicator is called a:',options:['Process indicator','Multi-variable indicator','Integrating indicator','Biological indicator'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'Type 5 integrating indicators respond to multiple sterilization parameters and approximate the microbial killing process; Type 1 is process indicator, Type 6 is biological indicator, and Type 4 is multi-variable indicator.'},
  {id:'671',question:'Type 6 indicators are also called:',options:['Process indicators','Emulating indicators','Integrating indicators','Multi-variable indicators'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Type 6 indicators are called emulating indicators because they emulate/simulate the sterilization of a wrapped load to test the most challenging conditions within a package. This distinguishes them from Type 1 (simple process indicators), Type 4 (parametric indicators), and Type 5 (integrating indicators).'},
  {id:'672',question:'What should be done if the Bowie-Dick test fails the first time?',options:['Run an empty cycle, then repeat the test.','Report to the supervisor for further instructions.','Shut down the sterilizer, then turn it back on.','Increase the sterilization time and repeat the test.'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'An empty cycle must be run first to purge any residual air or condensation from the sterilizer before retesting, ensuring that a failed test reflects an actual problem rather than sterilizer residual conditions. This allows proper validation that the sterilizer is functioning correctly.'},
  {id:'673',question:'Which of the following is the recommended sterilizer setting for the Bowie-Dick test?',options:['3 to 3.5 minutes at 270 degrees F, gravity-displacement','3 to 3.5 minutes at 270 degrees F, dynamic-air-removal','2.5 to 4 minutes at 250 degrees F, gravity-displacement','2.5 to 4 minutes at 250 degrees F, dynamic-air-removal'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'The Bowie-Dick test requires 3-3.5 minutes at 270°F with dynamic-air-removal because this specific setting tests the sterilizer\'s ability to remove air from the test pack, which is the primary challenge in steam sterilization. Other parameters either use incorrect temperatures or gravity-displacement, which doesn\'t adequately test air removal.'},
  {id:'674',question:'Unless otherwise indicated by the biological indicator manufacturer, if a biological test is performed daily, how often is it necessary to incubate a control biological indicator?',options:['With each new case of biological indicators','With each test biological indicator placed in the incubator','Once a day and if a new lot number is used','Once a week unless a new lot number is used'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'A control biological indicator must be incubated once daily and whenever a new lot number is used to verify that each day\'s tests are valid and that new batches of indicators are viable. This ensures consistent quality control of the biological indicators themselves.'},
  {id:'675',question:'All loads containing implantable devices should be monitored with:',options:['A biological indicator','Recorded with the patient\'s name','Recorded with the surgeon\'s name','Monitored with a Type 4 chemical indicator'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'All loads with implantable devices must be monitored with biological indicators because implants have the most serious consequences if sterilization fails, requiring the highest level of validation. Biological indicators provide direct evidence of sterilization efficacy, unlike chemical indicators alone.'},
  {id:'676',question:'For testing of rigid sterilization containers, the biological indicators should be placed:',options:['In two opposite corners of the inner basket and the lid.','As recommended by the manufacturer of the container.','In the center of the inner basket and the center of the lid.','In each corner of the inner basket and under the center of the lid.'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'Biological indicators must be placed in each corner of the inner basket and under the center of the lid because these are the hardest-to-reach areas where steam penetration is most difficult. Testing these challenging spots ensures the entire container is properly sterilized.'},
  {id:'677',question:'Sterile packs are most vulnerable to contamination:',options:['After they have cooled to room temperature.','When the packages are still hot.','When left on the sterilizer rack for long periods.','After the door is cracked at the end of the cycle.'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Hot sterile packs are most vulnerable because cooling packages can draw in contaminated ambient air through micro-gaps as the temperature drops, compromising sterility. This is why packs must be allowed to cool undisturbed in a clean environment.'},
  {id:'678',question:'Items being unloaded from the steam sterilizer cart should be handled with:',options:['Cotton gloves','Rubber gloves','Butyl gloves','Clean hands'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'Butyl gloves must be used because they are impermeable to moisture and steam, protecting hands when handling hot, wet items fresh from the sterilizer. Cotton, rubber, and bare hands do not provide adequate protection from heat and moisture.'},
  {id:'679',question:'A loaned instrument has been contaminated during a procedure and the OR wants to sterilize it in the immediate-use steam sterilizer. Which of the following is the first step to take?',options:['Immediately clean the instrument in an ultrasonic cleaner and send it back to the OR for sterilization.','Consult the manufacturer\'s written instructions for approved cleaning and sterilization methods and parameters.','Ask the sales representative if the instrument is required to be lubricated before sterilization.','Tell the OR to clean the instrument, place it in a covered container, and use the prevacuum cycle.'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'The manufacturer\'s written instructions must be consulted first because they specify the exact cleaning and sterilization parameters required for that specific instrument, ensuring proper decontamination and preventing damage. This is the critical first step before any processing decisions are made.'},
  {id:'680',question:'Which of the following best defines superheating of steam?',options:['Steam heated to greater than 500 degrees F','Heat added to dry steam in the absence of water','Steam contacting cool surfaces, causing condensation','Coagulation of protein during the heating process'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Superheating is heat added to dry steam in the absence of water, which removes the moisture necessary for effective sterilization since moisture is essential for denaturing proteins. Superheated steam is less effective and potentially damaging to items being sterilized.'},
  {id:'681',question:'The best method for loading paper-plastic pouches is to place them:',options:['Paper side up, flat','Clear side up, flat','Between wrapped sets on their side','On their edge in a pouch separator'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'Paper-plastic pouches must be loaded on their edge in a pouch separator to allow steam penetration around all sides of the pouch, ensuring the plastic barrier doesn\'t trap air or moisture. Flat positioning can prevent adequate steam contact and leave pockets of unsterilized areas.'},
  {id:'682',question:'Which of the following organisms is most resistant to the steam sterilization process?',options:['Geobacillus subtilis','Geobacillus stearothermophilus','Bacillus clostridium','Bacillus atrophaens'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Geobacillus stearothermophilus is the most steam-resistant organism because its spores can survive the highest temperatures and pressures, making it the gold standard biological indicator for validating steam sterilization. The other organisms listed are less thermoresistant and less suitable for steam validation.'},
  {id:'683',question:'To prevent scorching of packaging material, how much space should be between the packages and the chamber wall of the sterilizer?',options:['1 inch','2 inches','3 inches','6 inches'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Two inches of space must be maintained between packages and the chamber wall to prevent scorching/charring of packaging materials from direct exposure to the hot metal surfaces. Insufficient spacing allows direct heat transfer that can damage the wrapping.'},
  {id:'684',question:'Which of the following sterilizers requires only a special electrical outlet for installation?',options:['Ethylene oxide gas','Peracetic acid','Steam under pressure','Low-temperature gas plasma'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'Low-temperature gas plasma sterilizers require only an electrical outlet for installation because they do not require water supply (unlike steam) or gas supply and scavenging systems (unlike ethylene oxide). This makes them the simplest sterilizer to install from an infrastructure perspective.'},
  {id:'685',question:'When reviewing a sterilizer printout from a steam sterilization cycle, which parameters need to be verified?',options:['Only the temperature and pressure of the cycle.','Only the pressure and dry time.','The temperature, exposure time, and pressure.','The temperature, exposure time, and dry time.'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'Temperature, exposure time, and pressure must all be verified on the sterilizer printout because these three parameters together define a valid steam sterilization cycle and must meet established standards. Dry time is a post-sterilization condition, not a core cycle parameter.'},
  {id:'686',question:'Which of the following actions should be taken when a positive biological indicator demonstrates a sterilization process failure due to operator error?',options:['Release the load and distribute the contents for use.','Correct the error and reprocess the load.','Retrieve and reprocess all items processed on that day.','Retrieve and reprocess all items processed since the last negative biological test.'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Only the affected load should be corrected and reprocessed when the failure is due to operator error because the sterilizer itself is functioning properly, and other loads processed correctly were not compromised. Retrieving all items from that day would be unnecessary if sterilizer function is verified.'},
  {id:'687',question:'Which of the following statements about lot control is TRUE?',options:['It is needed for productivity monitoring.','The lot control information should include the name of the device being processed.','The lot control label should be applied to the item after it is removed from the steam sterilizer.','An indefinite shelf life statement must be visible for event-related dating.'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Lot control information must include the name of the device being processed so that specific items can be identified and recalled if a sterilization failure is discovered later. This traceability is essential for patient safety.'},
  {id:'688',question:'Process indicators are considered which Type?',options:['1','2','4','5'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Process indicators are Type 1 because they respond to only one sterilization parameter (typically temperature or color change) and provide basic evidence of exposure to the sterilization process. Types 2-6 respond to multiple parameters with increasing sophistication.'},
  {id:'689',question:'The parameters for low-temperature gas plasma sterilization are:',options:['Time, temperature, and humidity.','Time, temperature, and hydrogen peroxide gas plasma.','Steam under pressure, time, and hydrogen peroxide gas plasma.','Temperature, hydrogen peroxide gas plasma, and humidity.'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Low-temperature gas plasma sterilization parameters are time, temperature, and hydrogen peroxide gas plasma concentration because these three factors work together to achieve sterilization at lower temperatures. Steam is not used in gas plasma systems, and humidity is not a control parameter.'},
  {id:'690',question:'Which of the following is compatible with hydrogen peroxide-ozone sterilization?',options:['Woven textiles','Liquids','Stainless steel instruments','Natural rubber and latex'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'Stainless steel instruments are compatible with hydrogen peroxide-ozone sterilization because metals resist the oxidative action of the sterilant, while woven textiles absorb moisture, liquids react chemically with the sterilant, and rubber/latex materials degrade when exposed to these oxidizing agents.'},
  {id:'691',question:'Generally, in a table-top sterilizer, the biological vial is placed:',options:['Unpackaged, on the bottom shelf, in the back of the sterilizer.','Unpackaged, on the bottom shelf, in the front of the sterilizer.','Inside a Tyvek pouch and in the back of the sterilizer.','In the largest pack or pouch on the bottom front of the sterilizer.'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Biological indicators must be unpackaged to allow direct steam contact for effective sterilization validation; placement at the back ensures exposure to saturated steam after air removal, while front placement would be too close to the door where steam hasn\'t fully penetrated.'},
  {id:'692',question:'Biological monitoring of the hydrogen peroxide-ozone sterilization process should be performed:',options:['At least daily.','With each load.','Whenever lumened devices are included in the load.','Whenever rubber or latex is included in the load.'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Hydrogen peroxide-ozone is a low-temperature chemical sterilization process requiring biological monitoring with each load to validate that the sterilant achieved the necessary concentration and contact time; daily monitoring is insufficient for this volatile process.'},
  {id:'693',question:'When loading steam sterilizer carts, space is left between items:',options:['To reduce the risk of burns when unloading the cart.','To allow easier access to the items when unloading the cart.','To permit air removal and steam penetration.','To distribute the weight of items on the cart.'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'Space between items allows gravity-driven air removal and permits saturated steam to circulate and penetrate all surfaces, which is fundamental to steam sterilization efficacy; the other options address convenience rather than the sterilization mechanism.'},
  {id:'694',question:'Which of the following areas is the first to accept responsibility for all supplies in the facility?',options:['Receiving','Requisitioning','Distribution','Storage'],correct_answer:0,domain:'Sterile Storage',difficulty:'medium',explanation:'Receiving is the first department to physically take control of supplies upon arrival and verify quality, quantity, and condition; requisitioning only requests items, and distribution/storage occur after receiving establishes accountability.'},
  {id:'695',question:'Reusable cart covers for surgical case carts should be:',options:['Color-coded for the type of supplies being transported.','Long enough to cover the wheels of the cart.','Cleaned at least monthly.','Cleaned after each use.'],correct_answer:3,domain:'Sterile Storage',difficulty:'medium',explanation:'Cart covers contact potentially contaminated surfaces during transport and must be cleaned after each use to prevent cross-contamination of the supplies they protect; monthly or weekly cleaning is insufficient for this mobile contact surface.'},
  {id:'696',question:'Which of the following is NOT a necessary requirement of a requisition?',options:['It must be legible.','It must have the facility\'s phone number.','It must specify the quantity needed.','It must specify where items are to be delivered.'],correct_answer:1,domain:'Sterile Storage',difficulty:'medium',explanation:'A facility\'s phone number is not a necessary requisition component—legibility, quantity, and delivery location are essential for proper order fulfillment, but contact information does not affect the ability to process the requisition.'},
  {id:'697',question:'Clean supply transportation carts should be cleaned:',options:['After each use','Once a week','At least monthly','At least once a day'],correct_answer:3,domain:'Sterile Storage',difficulty:'medium',explanation:'Clean supply carts are mobile equipment that accumulate dust and environmental contaminants during daily use and must be sanitized at least once daily to maintain the cleanliness of supplies before sterilization; less frequent cleaning would allow contamination buildup.'},
  {id:'698',question:'Which of the following is NOT considered a specialty cart?',options:['Disaster','Exchange','Dialysis','Code'],correct_answer:0,domain:'Sterile Storage',difficulty:'medium',explanation:'Exchange, Dialysis, and Code carts are established specialty carts with defined purposes and supply configurations; disaster carts are emergency supply staging and do not fit the standard specialty cart classifications.'},
  {id:'699',question:'An effective case cart system requires:',options:['Little space.','Infrequent cleaning of carts.','The user to enter a code.','Good communication.'],correct_answer:3,domain:'Sterile Storage',difficulty:'medium',explanation:'Case cart systems depend on accurate pick lists, timely coordination between OR and SPD, and clear delivery schedules, all of which require good communication between departments; the other factors are secondary to effective communication.'},
  {id:'700',question:'Bar-coding of instrument sets is an integral part of:',options:['Case cart systems.','Exchange cart systems.','Tracking systems.','Just-in-time systems.'],correct_answer:2,domain:'Sterile Storage',difficulty:'medium',explanation:'Bar-coding enables real-time tracking of instruments from sterilization through use and return, providing accountability and documentation; case and exchange carts manage sets by rotation rather than tracking, and just-in-time focuses on inventory timing.'},
  {id:'701',question:'Stock should be routinely rotated to reduce:',options:['Storage space.','Outdated supplies.','Inventory.','Workload.'],correct_answer:1,domain:'Sterile Storage',difficulty:'medium',explanation:'FIFO (first-in, first-out) rotation ensures older stock is issued before newer stock, preventing items from reaching expiration dates and reducing waste; it does not reduce physical storage space, total inventory, or workload.'},
  {id:'702',question:'In the receiving area, all sterile products must be kept separate from all of the following EXCEPT:',options:['Food','Waste','Possible contaminants','Clean linen carts'],correct_answer:3,domain:'Sterile Storage',difficulty:'medium',explanation:'Clean linen carts contain non-sterile but non-contaminated items that can share receiving/storage space with sterile products if properly sectioned, whereas food, waste, and possible contaminants must be completely segregated to prevent cross-contamination.'},
  {id:'703',question:'Sterile supplies can be compromised by:',options:['Excessive cold','Stacking rigid containers','Handling packages when the temperature is below 70 degrees F','Being stored on dusty storage shelves'],correct_answer:0,domain:'Sterile Storage',difficulty:'medium',explanation:'Excessive cold causes condensation when packages are moved to warmer areas, introducing moisture that penetrates package barriers and creates a pathway for microbial contamination; the other options do not directly compromise sterility.'},
  {id:'704',question:'The caution triangle with an i symbol means:',options:['Danger, contains contaminated material.','Danger, electrical hazard.','Caution, use PPE when opening.','Caution, see accompanying documents.'],correct_answer:3,domain:'Sterile Storage',difficulty:'medium',explanation:'The \'i\' symbol in a triangle is the standardized ISO caution symbol directing users to refer to accompanying documents for safety information; different symbols are used for contamination hazards, electrical hazards, and PPE requirements.'},
  {id:'705',question:'Which of the following statements is TRUE?',options:['Only facility-sterilized products can be stored in the sterile storage area.','Stored items must be kept 15 inches from a fire sprinkler head.','Clean and sterile items can be stored in the same area as long as they are labeled correctly.','Wire shelving provides the most protection for sterile supplies.'],correct_answer:1,domain:'Sterile Storage',difficulty:'medium',explanation:'The 15-inch minimum clearance from sprinkler heads is a standard requirement to prevent obstruction of spray patterns and ensure adequate fire suppression coverage; the other statements violate separation, mixing, or shelving requirements.'},
  {id:'706',question:'Which of the following factors is a reason for a manufacturer to assign an expiration date to a sterile medical device?',options:['Product labeling','Product degradation','The cost of the product','The type of sterilization method'],correct_answer:1,domain:'Sterile Storage',difficulty:'medium',explanation:'Manufacturers set expiration dates based on stability testing that demonstrates when products begin to lose efficacy, structural integrity, or safety characteristics; labeling, cost, and sterilization method do not determine expiration.'},
  {id:'707',question:'The integrity of a sterile package should be visually inspected:',options:['Once a week','Once a month','When it is issued','Every time it is handled'],correct_answer:3,domain:'Sterile Storage',difficulty:'medium',explanation:'Visual package integrity inspection must occur whenever a package is handled or relocated because damage can occur during any movement, transport, or storage transition; periodic inspections miss damage that occurs between check intervals.'},
  {id:'708',question:'Which of the following statements about sterility maintenance is TRUE?',options:['Physical damage from stacking sets does not occur when rigid containers are placed on top of wrapped sets.','If a package contains water spots, it does not have to be reprocessed.','How a wrapped package is handled has little effect on sterility maintenance.','When items are removed from the sterilizer, they should not be placed on a cool surface.'],correct_answer:3,domain:'Sterile Storage',difficulty:'medium',explanation:'Hot items from the sterilizer placed on cool surfaces create condensation within packages, introducing moisture that can permit bacterial penetration; stacking can damage wrapped sets, water spots indicate compromise, and handling directly affects sterility.'},
  {id:'709',question:'Which of the following steps should be followed if an item wrapped in a sterility maintenance cover is dropped on the floor?',options:['Remove the cover. If the inside package is not damaged, replace the cover.','Inspect for damage to the sterility maintenance cover. If none, wipe with a disinfectant and replace the cover.','Remove the cover and place the item back on the shelf.','Pick it up and place it back on the shelf.'],correct_answer:1,domain:'Sterile Storage',difficulty:'medium',explanation:'The sterility maintenance cover is the protective barrier; if it shows no damage and is disinfected after floor contact, the sealed sterile item inside remains protected, whereas removing the cover or reprocessing is unnecessary if the barrier is intact.'},
  {id:'710',question:'Ideally, the sterile storage area should be located:',options:['Adjacent to the sterilization area.','Adjacent to the distribution area.','Near the main flow of traffic.','In the center of the sterilization area.'],correct_answer:0,domain:'Sterile Storage',difficulty:'medium',explanation:'Proximity to sterilization minimizes handling time and distance between decontamination and storage, reducing exposure to contamination sources; adjacent to distribution or near traffic increases contamination risk, and centering in sterilization area disrupts workflow.'},
  {id:'711',question:'Shipping cartons are NOT acceptable storage containers in the sterile storage area because they:',options:['Are too large.','Can harbor contaminants.','Can tear easily.','Are hard to label.'],correct_answer:1,domain:'Sterile Storage',difficulty:'medium',explanation:'Shipping cartons have corrugated materials and gaps that harbor contaminants like particles and microorganisms, compromising sterile storage. Size, tearing, and labeling are not the primary disqualifying factors.'},
  {id:'712',question:'Which of the following best describes the purpose of evenly distributing large sets of instruments?',options:['The set is difficult to carry if the weight is unevenly distributed.','Extra condensation will make the set more difficult to dry.','It is easier for the end user to sort the instruments.','The overall weight of the set is affected.'],correct_answer:1,domain:'SPD Overview',difficulty:'medium',explanation:'Uneven distribution causes uneven steam penetration, resulting in excessive condensation in heavier areas that delays drying. Carrying difficulty and total weight are not sterilization concerns, and sorting is not the purpose of distribution.'},
  {id:'713',question:'Which of the following best describes the overall role of the sterile processing area? To provide:',options:['Dependable service to enhance patient care.','Sterilization services on a rigid schedule.','Delivery of facility supplies.','Support to the operating room technicians.'],correct_answer:0,domain:'SPD Overview',difficulty:'medium',explanation:'Sterile processing\'s fundamental mission is to support patient care through reliable, dependable sterilization and processing services. Rigid scheduling, supply delivery, and supporting OR staff are secondary functions, not the overall role.'},
  {id:'714',question:'Which of the following government agencies has the responsibility for approving new environmental disinfectants prior to their being sold to healthcare facilities?',options:['Occupational Safety and Health Administration','Food and Drug Administration','Environmental Protection Agency','Centers for Disease Control and Prevention'],correct_answer:2,domain:'SPD Overview',difficulty:'medium',explanation:'EPA has regulatory authority over environmental disinfectants and antimicrobials. OSHA addresses occupational safety, FDA oversees medical devices, and CDC provides guidance but does not approve products.'},
  {id:'715',question:'The function of a ratchet can be checked by:',options:['Closing the ratchet all the way, then tapping the handle on the worktable.','Closing the ratchet on the second click, then tapping the handle on the worktable.','Leaving the ratchet open and moving the jaws of the instrument.','Closing the ratchet on the first click, then tapping the handle on the worktable.'],correct_answer:1,domain:'SPD Overview',difficulty:'medium',explanation:'The second click ensures proper ratchet catch positioning; tapping on the worktable tests for slippage and confirms functionality. Closing fully risks damage, first click is too loose, and leaving open doesn\'t test the catch mechanism.'},
  {id:'716',question:'The science that studies the structure of the body is known as:',options:['Anatomy','Physiology','Body basics','Microbiology'],correct_answer:0,domain:'SPD Overview',difficulty:'medium',explanation:'Anatomy is the discipline studying body structure and organization. Physiology studies function, microbiology studies microorganisms, and "body basics" is not a formal scientific term.'},
  {id:'717',question:'Which of the following transports molecules within the cell?',options:['Cilia','Flagella','Nucleus','Cytoplasm'],correct_answer:0,domain:'SPD Overview',difficulty:'medium',explanation:'Cilia are structures with microtubules that actively transport molecules through the cell. Flagella are for external movement, nucleus is the control center, and cytoplasm is the medium rather than the active transport mechanism.'},
  {id:'718',question:'Which of the following sets would be considered high-risk for special prion processing?',options:['Open heart set','Laparotomy set','Abdominal set','Craniotomy set'],correct_answer:3,domain:'SPD Overview',difficulty:'medium',explanation:'Craniotomy involves brain tissue, which is the primary source of prion contamination in healthcare settings. Abdominal and cardiac sets do not involve neural tissue with significant prion risk.'},
  {id:'719',question:'The metacarpals are located in the:',options:['Spine','Feet','Neck','Hands'],correct_answer:3,domain:'SPD Overview',difficulty:'medium',explanation:'Metacarpals are the five long bones in the palm region of the hand. The spine contains vertebrae, feet contain metatarsals and tarsals, and the neck contains cervical vertebrae.'},
  {id:'720',question:'Microorganisms are measured in:',options:['Inches','Microns','Millimeters','Centimeters'],correct_answer:1,domain:'SPD Overview',difficulty:'medium',explanation:'Microns (micrometers) are the standard unit for measuring microorganisms due to their microscopic size. Inches, millimeters, and centimeters are all too large for typical microbial measurement.'},
  {id:'721',question:'With respect to rigid sterilization container testing, which term defines the sterilizer\'s ability to sterilize under actual use conditions?',options:['Routine biological testing','Small-load testing','Chemical monitoring','Maximum-load testing'],correct_answer:1,domain:'SPD Overview',difficulty:'medium',explanation:'Small-load testing uses realistic instrument loads to verify sterilization efficacy under actual clinical use conditions with rigid containers. Routine testing checks chemical indicators, and maximum-load testing uses worst-case heavy loads rather than typical conditions.'},
  {id:'722',question:'If you have a fever, your temperature would be above:',options:['96.8 degrees F','97.8 degrees F','98.6 degrees F','98.9 degrees F'],correct_answer:2,domain:'SPD Overview',difficulty:'medium',explanation:'Normal body temperature is 98.6°F; any temperature above this indicates fever. The other options are at or below normal temperature range.'},
  {id:'723',question:'Which of the following statements is true of a capsulated bacterium? It is:',options:['Less difficult to kill than vegetative bacteria.','More difficult to kill than a spore.','More resistant to heat and chemicals.','Easily killed by antibiotics.'],correct_answer:2,domain:'SPD Overview',difficulty:'medium',explanation:'Bacterial capsules provide a protective layer that increases resistance to heat and chemical disinfectants. Spores are actually more resistant than capsules, capsules don\'t prevent antibiotic action, and capsules increase rather than decrease resistance.'},
  {id:'724',question:'Pulmonary capillaries are found in which system?',options:['Endocrine','Respiratory','Nervous','Digestive'],correct_answer:1,domain:'SPD Overview',difficulty:'medium',explanation:'Pulmonary capillaries are located in the lungs where gas exchange occurs, which is part of the respiratory system. The other systems are not involved in pulmonary gas exchange.'}
]